UPDATE DTB_UPAY_LIST SET UPAY_STATE='1', UPAY_CODE='1', UPAY_MSG='1', UPAY_TIME=to_char(sysdate,'yyyy-MM-dd HH24:mi:ss') WHERE TRAN_SEQ='1' AND UPAY_STATE='1' ;
UPDATE DTB_UPAY_LIST set UPAY_STATE='1', UPAY_CODE='1', UPAY_MSG='1' WHERE TRAN_SEQ='1' AND UPAY_STATE IN (3,5) ;
UPDATE PER_CUST_ACCOUNT_APPLY SET STAT = '1', TRANS_SEQ = '1' WHERE CTP_ID='1' AND TRAN_SEQ = '1' AND STAT='3' ;
UPDATE PER_CUST_ACCOUNT_APPLY SET STAT = '1', TRANS_SEQ = '1' WHERE CTP_ID='1' AND TRAN_SEQ = '1' AND STAT='1' ;
UPDATE SIGN_PROTOCL_INFO SET PRO_TRAN_MSG = '1', UPD_DATE = to_char(sysdate,'YYYY-MM-DD'), UPD_TIME = to_char(sysdate,'hh24miss'), ACCT_NO='1', PB_PROTOCOL='1' WHERE PRO_ID = '1' ;
SELECT a.ACCT_NO,OPEN_ORG,a.ACCT_NAME,a.BIND_TYPE,a.IS_DK, PRE_NO,ACCT_TP ACCT_TYP, IS_ACTIVE, REG_AMT,IS_RANDOM,a.DK_PRO_ID,b.pb_protocol,DK_PRO_STATE FROM DTB_ACCT a left join SIGN_PROTOCL_INFO b on a.dk_pro_id=b.pro_id WHERE a.EBUSER_NO = '1' AND a.ACCT_NO ='1' ;
SELECT A.BANK_CODE,B.BANK_NAME,length(STRING1),A.CARD_TYPE FROM CARDPARAM_CLS_INFO A LEFT JOIN BANK_COFG_CODE B ON A.BANK_CODE=B.BANK_CODE WHERE STRING1 in ( '1' , '1' , '1' , '1' , '1' , '1' , '1' , '1' , '1' ) AND A.CARD_LEN = '1' ORDER BY length(STRING1) DESC ;
SELECT A.*,B.CTP_NAME,B.OPEN_ORG AS ORG FROM CTP_OPERATOR A LEFT JOIN CTP_INFO B ON A.CTP_ID=B.CTP_ID WHERE (LGN_ID='1' OR OPER_MOBILE='1') AND A.CTP_ID='1' ;
SELECT ACCT_NO FROM DTB_ACCT WHERE EBUSER_NO = '1' AND CTP_ID = '1' AND ACCT_TP = '0' ;
SELECT A.CHAN_TYP,A.TRAN_CODE,A.OPEN_WAY,A.EBUSER_TYP,A.INCORP_NO,A.OPER_TYPE FROM CHAN_INTE_AUTH_CTL A ;
SELECT A.CHAN_TYP,A.TRAN_CODE,A.TRAN_VALUE_NAME,A.FREQ_TYPE,A.PER_TIME,A.PER_COUNT,A.FRE_TIME,A.EXT1,A.EXT2 FROM CHAN_SERVICE_FREQ_CL A ;
SELECT A.CTP_ID, A.ORDER_NO, A.SYNZ_URL, A.OPER_TYPE, D.TRAN_STATE, B.CODE_NAME, A.CTP_SEQ TRANS_SEQ, A.CTP_SEQ, D.HOST_MSG TRAN_STATE_DESC FROM CTP_TRANS_ORDER_INFO A LEFT JOIN PARM_CODE B ON A.STATE = B.CODE_NO AND B.CODE_TYPE = 'CTP_STAT_OUT' LEFT JOIN DTB_ROLL_TR D ON D.CTP_SEQ_NO = A.CTP_SEQ WHERE A.CTP_ID = '1' AND A.ORDER_NO = '1' AND A.SYNZ_URL IS NOT NULL AND D.TRAN_STATE='7' ;
SELECT A.CTP_NAME, A.CTP_LOGO_B, A.CTP_LOGO_S, A.OPEN_ORG ORG_NO, A.OPEN_ORG||'811' TELLER_NO, A.STAT CTP_STAT, A.CIF_NO CTP_CIF_NO, A.ID_TYPE CTP_ID_TYP, A.ID_NO CTP_ID_NO, B.FLAG FROM CTP_INFO A LEFT JOIN CTP_CONFIG_TR B ON A.CTP_ID = B.CTP_ID WHERE A.CTP_ID = '1' ;
SELECT A.LOCAL_LAN,A.EXCEPTION_CODE,A.EXCEPTION_MSG FROM CHAN_EXCEPTION_MSG_PRARM A ;
SELECT A.PROT_TEMP_NAME FROM PROT_TEMP A WHERE PROT_TEMP_ID='1' ;
SELECT BANK_CODE,BANK_NAME FROM BANK_COFG_CODE ORDER BY BANK_CODE ;
SELECT BANK_NO BANK_CODE,BANK_NAME,IS_ACTIVE FROM DTB_ACCT WHERE ACCT_NO = '1' AND CTP_ID = '1' ;
SELECT BANK_NO,IS_ACTIVE FROM DTB_ACCT WHERE ACCT_NO = '1' AND ACCT_TP <> '0' AND CTP_ID = '1' AND EBUSER_NO = '1' ;
SELECT B.CTP_SEQ_NO CTP_SEQ, 'ctpTransOut' TRANS_CODE, B.TRAN_DATE CTP_DATE, B.OPER_TYPE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, B.ACCT_NO ELE_ACCT_NO, B.CARD_NO ACCT_NO, TO_CHAR(B.OPER_AMT) OPER_AMT, TO_CHAR(B.TRAN_FEE) TRAN_FEE FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO WHERE 1=1 AND B.TRAN_STATE = '7' AND B.OPER_TYPE = '1' AND B.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT b.* FROM CTP_USER_MENU a left join ctp_sys_menu b on a.menu_id = b.menu_id WHERE a.CTP_ID='1' and a.OPER_ID='1' ORDER BY a.MENU_ID ;
SELECT BI.BANK_NAME,BI.CERTIFY_PASS_TYPE,BI.IS_CHECK_MOBILE,BI.IS_CHECK_PWD FROM BANK_EXT_INF BI WHERE BANK_CODE='1' AND CTP_ID='1' ;
SELECT CBOI.ORDER_NO, CPCT.CTP_TYP, CPCT.PRO_TYP, CBOI.PRO_ID, CBOI.TRAN_AMT, CBOI.UNIT_MEAT, MICUI.ID_TYP BUYER_ID_TYP, MICUI.ID_NO BUYER_ID_NO, MICUI.CUST_NAME BUYER_CUST_NAME, CUI.ID_TYP, CUI.ID_NO, CUI.CUST_NAME, CBOI.CRE_DATE, CPCT.STAT, CPCT.RCV_ACCT, CPCT.PAY_ACCT from CTP_BT_ORDER_INFO CBOI JOIN CTP_PRO_CONFIRM_TR CPCT ON CBOI.CTP_ID = CPCT.CTP_ID AND CBOI.ORDER_NO = CPCT.ORDER_NO JOIN CTP_USER_INFO CUI ON CBOI.SELLER_NO = CUI.EBUSER_NO AND CBOI.CTP_ID = CUI.CTP_ID JOIN CTP_USER_INFO MICUI ON CBOI.BUYER_NO = MICUI.EBUSER_NO AND CBOI.CTP_ID = MICUI.CTP_ID WHERE CBOI.STAT = '3' AND CBOI.CTP_ID='1' AND CBOI.CRE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT CB.ORI_ORDER_NO, CB.ORDER_NO,CB.OPER_TYPE,CP.CTP_TYP,CP.PRO_TYP, CB.PRO_ID,CB.TRAN_AMT,CB.PRO_FEE, CB.BUYER_NO PAY_NO,CP.PAY_ACCT,CP.PAY_NAME, CB.SELLER_NO,CP.RCV_ACCT,CP.RCV_NAME, CB.TOT_NUM,CB.UNIT_MEAT,CB.BACK_URL, CI.GOODS_NAME,CI.GOODS_DESC,CI.KK_FLAG, REPLACE('2012-12-01','-','')||REPLACE('12:01:02',':','') ORDER_CRE_TIME FROM CTP_BT_ORDER_INFO CB LEFT JOIN CTP_PRO_CONFIRM_TR CP ON CB.ORI_ORDER_NO=CP.ORDER_NO LEFT JOIN CTP_PRO_INFO CI ON CI.PRO_ID=CB.PRO_ID WHERE CB.CTP_ID = '1' AND CB.ORDER_NO = '1' AND CB.OPER_TYPE = '1' AND CB.STAT = '1' ;
SELECT CC.BUY_EBUSER, CC.SELL_EBUSER, CB.TRAN_AMT,CB.PRO_FEE FEE_AMT, CB.TOT_NUM,CB.UNIT_MEAT FROM CTP_PRO_CONFIRM_TR CC LEFT JOIN CTP_BT_ORDER_INFO CB ON CB.ORI_ORDER_NO = CC.ORDER_NO AND CB.OPER_TYPE='P' WHERE CC.ORDER_NO = '1' AND CC.CTP_TYP = '1' AND CC.PRO_TYP = '1' AND CC.PRO_ID = '1' AND CC.CTP_ID = '1' ;
SELECT C.CONF_TYPE,C.TRANS_CODE,C.TRANS_CONF FROM CHAN_TRANS_PUB_CONF C ;
SELECT CHAN_TYP,EBUSER_NO CUST_NO FROM USER_LOG_CONF ;
SELECT CHAN_TYP,TRANS_CODE,TRANS_TYPE,TRAN_WAY FROM E_LMT_PARM_CT ;
SELECT CHARGE_TYPE,FEE_VALUE FROM PASS_FEE_CONF WHERE PASS_TYPE='1' AND OPER_TYPE = '1' AND '1'<=UPPER_LIMIT AND '1'>LOWER_LIMIT ;
SELECT CI.EBUSER_TYP ,DA.ACCT_NO ELE_ACCT_NO,DA.IS_ACTIVE,DA.IS_SIGN_MOBILE,CI.MOBILE FROM CTP_USER_INFO CI LEFT JOIN DTB_ACCT DA ON DA.ACCT_TP='0' AND DA.EBUSER_NO=CI.EBUSER_NO AND DA.CTP_ID=CI.CTP_ID WHERE CI.EBUSER_NO='1' AND CI.CTP_ID='1' ;
SELECT CIF_NO,CUST_NAME,USER_STAT,EBUSER_TYP,MOBILE FROM CTP_USER_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' ;
SELECT CLEAR_TYP FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT CODE_TYPE TYPE, CODE_NO CODE, CODE_NAME LABEL FROM PARM_CODE T ORDER BY CODE_SORT ;
SELECT COUNT(1) FROM CTP_DYNAMIC_CODE WHERE CHAN_TYP = '1' AND EBUSER_NO = '1' ;
SELECT COUNT(1) FROM( SELECT A.*, ROW_NUMBER() OVER(ORDER BY CTP_ACCT) AS RN FROM CTP_ACCT A WHERE CTP_ID = '1' AND ACCT_STATE='N' ) ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP = '0' WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND CUST_NAME LIKE '%'||'1'||'%' AND ID_NO LIKE '%'||'1'||'%' AND EBUSER_TYP = '1' ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND CUST_NAME LIKE '%'||'1'||'%' AND ID_NO LIKE '%'||'1'||'%' AND EBUSER_TYP = '1' ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND EBUSER_TYP = '1' ;
SELECT COUNT(*) FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' ;
SELECT COUNT(*) FROM DTB_ACCT WHERE EBUSER_NO='1' AND ACCT_TP!='0' ;
SELECT CPCT.TRAN_AMT-CPCT.TRAN_FEE TRAN_AMT,CPCT.TRAN_FEE, CPCT.TRAN_AMT AMT_BIG,CPCT.TRAN_FEE FEE_BIG,CPCT.STAT, DA.ACCT_NO RCV_ACCT,DA.ACCT_NAME RCV_NAME, CASE WHEN CBTC.ZJH_FLAG='Y' THEN CBTC.JG_ACCT ELSE CPI.ACCT_MIDDLE END AS PAY_ACCT, CI.CTP_NAME PAY_NAME,CBTC.FEE_ACCT,CPCT.FEE_ACCT FEE_ACCT_SECOND,CPCT.FEE_NAME FROM CTP_PRO_CONFIRM_TR CPCT LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CPCT.SELL_EBUSER AND DA.ACCT_TP='0' LEFT JOIN CTP_BT_TYP_CONF CBTC ON CBTC.CTP_ID=CPCT.CTP_ID AND CBTC.PRO_TYP=CPCT.PRO_TYP LEFT JOIN CTP_PRO_INFO CPI ON CPI.PRO_ID=CPCT.PRO_ID AND CPI.PRO_TYP=CPCT.PRO_TYP AND CPI.CTP_TYP=CPCT.CTP_TYP LEFT JOIN CTP_INFO CI ON CPCT.CTP_ID= CI.CTP_ID WHERE ORDER_NO= '1' AND CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' AND CPCT.STAT IN ('10','22','32') AND CPCT.BUY_EBUSER = '1' ;
SELECT CPCT.TRAN_AMT,DA.ACCT_NO PAY_ACCT,DA.ACCT_NAME PAY_NAME, CPCT.TRAN_AMT AMT_BIG,CPCT.TRAN_FEE FEE_BIG,CPCT.STAT, CASE WHEN CBTC.ZJH_FLAG='Y' THEN CBTC.JG_ACCT ELSE CPI.ACCT_MIDDLE END AS RCV_ACCT, CI.CTP_NAME RCV_NAME,CPI.KK_FLAG, CASE WHEN CUI.EBUSER_TYP='P' THEN '' ELSE '1' END AS DRACT_TYPE,CPCT.FEE_ACCT,CPCT.FEE_NAME FROM CTP_PRO_CONFIRM_TR CPCT LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CPCT.BUY_EBUSER AND DA.ACCT_TP='0' LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO=CPCT.BUY_EBUSER LEFT JOIN CTP_BT_TYP_CONF CBTC ON CBTC.CTP_ID=CPCT.CTP_ID AND CBTC.PRO_TYP=CPCT.PRO_TYP LEFT JOIN CTP_PRO_INFO CPI ON CPI.PRO_ID=CPCT.PRO_ID AND CPI.PRO_TYP=CPCT.PRO_TYP AND CPI.CTP_TYP=CPCT.CTP_TYP LEFT JOIN CTP_INFO CI ON CI.CTP_ID=CPCT.CTP_ID WHERE ORDER_NO= '1' AND CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' AND CPCT.STAT IN ('00','12','42') AND CPCT.BUY_EBUSER = '1' ;
SELECT CTO.EBUSER_NO, CTO.OPER_TYPE, CTO.ORDER_NO, CTO.ACCT_NO, CTO.TRAN_AMT, CTO.CUST_FEE, DA.ACCT_NO ELE_ACCT_NO, DA.ACCT_TP, DA2.BANK_NO RCV_BANK_CODE, BCC.BANK_NAME RCV_BANK_NAME, DA2.BRANCH_NO RCV_BRANCH_CODE, PBC.LNAME RCV_BRANCH_NAME, PBC.NODE_CODE PROV_CODE, PBC.CITY_CODE, CTO.BACK_URL,CTO.CTP_SEQ, PBC.CLS_CODE, CUI.MOBILE MOBILE_NO,FEE_LIST,CUI.EBUSER_TYP, REPLACE(CRE_DATE,'-','')||REPLACE(CRE_TIME,':','') ORDER_CRE_TIME FROM CTP_TRANS_ORDER_INFO CTO LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CTO.EBUSER_NO AND DA.ACCT_TP='0' AND DA.CTP_ID = CTO.CTP_ID LEFT JOIN DTB_ACCT DA2 ON DA2.ACCT_NO=CTO.ACCT_NO AND DA2.CTP_ID = CTO.CTP_ID LEFT JOIN BANK_COFG_CODE BCC ON DA2.BANK_NO=BCC.BANK_CODE AND DA2.ACCT_NO=CTO.ACCT_NO LEFT JOIN PT_BANK_CODE PBC ON DA2.BRANCH_NO=PBC.BANK_CODE AND DA2.ACCT_NO=CTO.ACCT_NO AND PBC.MSG_TYPE IN('CNAPS','CNAPS1') LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO=CTO.EBUSER_NO WHERE CTO.CTP_ID = '1' AND CTO.ORDER_NO = '1' AND STATE = '1' ;
SELECT CTP_ACCT FROM CTP_ACCT WHERE CTP_ID='1' AND CTP_ACCT='1' ;
SELECT CTP_ID,CTP_TRAN_SEQ,UNI_STAT FROM CTP_COMP_QUAIL_INFO WHERE UNI_NO='1' ;
SELECT CTP_ID FROM CTP_PRO_TYP_CONF WHERE CTP_ID = '1' AND CTP_TYP = '1' AND PRO_TYP = '1' ;
SELECT CTP_NAME,ID_TYPE,ID_NO FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT CTP_NAME,OPEN_ORG,STAT FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT CTP_PRO_SEQ.NEXTVAL FROM DUAL ;
SELECT CU.EBUSER_NO,CU.USER_STAT ,DA.IS_ACTIVE, DA.ACCT_NO EACCT_NO,DA.IS_SIGN_MOBILE, DA1.BANK_NO BANK_CODE,DA1.BANK_NAME,DA1.REG_AMT FROM CTP_USER_INFO cu LEFT JOIN DTB_ACCT DA ON CU.EBUSER_NO=DA.EBUSER_NO AND DA.ACCT_TP='0' LEFT JOIN DTB_ACCT DA1 ON CU.EBUSER_NO=DA1.EBUSER_NO AND DA1.ACCT_TP<>'0' WHERE CU.ID_TYP = '1' AND CU.ID_NO = '1' AND CU.CUST_NAME = '1' AND CU.CTP_ID = '1' ;
SELECT CUI.MOBILE MOBILE_NO, CUI.CIF_NO CUST_NO, DA.ACCT_NO ELE_ACCT_NO, CI.CTP_NAME FROM CTP_USER_INFO CUI LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO = CUI.EBUSER_NO AND DA.ACCT_TP = '0' LEFT JOIN CTP_INFO CI ON CI.CTP_ID=CUI.CTP_ID WHERE CUI.EBUSER_NO = '1' ;
SELECT CUST_LOGIN_ID_SEQ.NEXTVAL FROM DUAL ;
SELECT CUST_NAME,ID_TYP,ID_NO FROM CTP_USER_INFO WHERE EBUSER_NO = '1' ;
SELECT CUST_ROLE,ID_NAME,ID_NO,MOBILE,CTP_LOGIN_NAME,CTP_NICK_NAME,ACCT_NO,CCY_TYPE,ACC_ALIAS,CUST_ENAME,ID_TYP, EBUSER_TYP,OPEN_TELLER,SERIAL_NO,CHK_CODE,SYNZ_URL,CTP_ID,BACK_URL,STAT,TRANS_SEQ, CASE WHEN ID_TYP='01' THEN '身份证' WHEN ID_TYP='02' THEN '户口本' WHEN ID_TYP='03' THEN '军官证' WHEN ID_TYP='05' THEN '护照' WHEN ID_TYP='20' THEN '港澳居民来往内地通行证' WHEN ID_TYP='21' THEN '台湾居民来往大陆通行证' WHEN ID_TYP='22' THEN '临时身份证' WHEN ID_TYP='23' THEN '武警证' WHEN ID_TYP='24' THEN '外国人永久居留证' WHEN ID_TYP='25' THEN '边民出入通行证' WHEN ID_TYP='26' THEN '外国护照' END AS ID_TYP_CNY, CASE WHEN STAT IN ('0','2') THEN '0' ELSE STAT END AS ORDER_STAT FROM PER_CUST_ACCOUNT_APPLY WHERE TRAN_SEQ = '1' AND CTP_ID = '1' ;
SELECT DA.ACCT_NO,DA.ACCT_NAME FROM DTB_ACCT DA WHERE DA.EBUSER_NO = '1' AND DA.ACCT_TP = '0' ;
SELECT DA.ACCT_NO,DA.BANK_NO,DA.REG_AMT*100 REG_AMT,DA.IS_ACTIVE,(SELECT LNAME FROM PT_BANK_CODE WHERE BANK_CODE=DA.BANK_NO AND MSG_TYPE IN ('CNAPS', 'CNAPS1')) BANK_NAME, DA.BRANCH_NO BRC_NO,(SELECT LNAME FROM PT_BANK_CODE WHERE BANK_CODE=DA.BRANCH_NO AND MSG_TYPE IN ('CNAPS', 'CNAPS1')) BRC_NAME FROM DTB_ACCT DA WHERE EBUSER_NO='1' AND CTP_ID='1' AND ACCT_TP !='0' ;
SELECT DA.ACCT_NO, DA.OPEN_ORG, DA.ACCT_NAME, DA.ACCT_TP ACCT_TYP, DA.IS_ACTIVE, CUI.EBUSER_TYP, DA.CUST_ROLE FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = DA.EBUSER_NO WHERE DA.EBUSER_NO = '1' AND DA.ACCT_TP = '1' ;
SELECT DISTINCT DREC_CODE FROM PT_BANK_CODE WHERE BANK_CODE = '1' AND MSG_TYPE IN('CNAPS','CNAPS1') ;
SELECT DISTINCT PBC.BANK_CODE, PBC.LNAME BANK_NAME, PBC.CITY_CODE, PBC.DREC_CODE FROM PT_BANK_CODE PBC WHERE PBC.DREC_CODE IN (SELECT A.BANK_CODE FROM PT_BANK_CODE A WHERE A.BANK_CODE IN (SELECT DISTINCT B.DREC_CODE FROM PT_BANK_CODE B) AND A.MSG_TYPE IN('CNAPS','CNAPS1') AND A.DREC_CODE = '1') AND PBC.CITY_CODE = '1' AND PBC.MSG_TYPE IN('CNAPS','CNAPS1') ;
SELECT DRT.CTP_SEQ_NO ORDER_NO,DRT.OPER_TYPE,TRAN_STATE, CASE WHEN DRT.OPER_TYPE='0' THEN PC1.CODE_NAME WHEN DRT.OPER_TYPE = '1'THEN PC2.CODE_NAME END AS TRAN_STATE_DESC FROM DTB_ROLL_TR DRT LEFT JOIN PARM_CODE PC1 ON PC1.CODE_TYPE='CTP_STAT_IN' AND PC1.CODE_NO=DRT.TRAN_STATE LEFT JOIN PARM_CODE PC2 ON PC2.CODE_TYPE='CTP_STAT_OUT'AND PC2.CODE_NO=DRT.TRAN_STATE WHERE 1=1 AND DRT.CTP_SEQ_NO = (SELECT CTP_SEQ FROM CTP_TRANS_ORDER_INFO WHERE ORDER_NO='1') AND CTP_ID = '1' ORDER BY REPLACE(DRT.TRAN_DATE,'-','')||REPLACE(DRT.TRAN_TIME,':','') DESC ;
SELECT EBUSER_NO FROM CTP_USER_INFO WHERE ID_TYP = '1' AND ID_NO = '1' AND CUST_NAME = '1' AND CTP_ID = '1' ;
SELECT FEE_TYPE, FEE_AMT, FEE_BOTTOM, FEE_TOP, CUST_FEE_TOP, CUST_FEE_BOTTOM FROM CTP_SER_FEE_CONF WHERE CTP_ID = '1' AND TRAN_TYPE = '1' AND STAR_AMT < '1' AND END_AMT >= '1' ;
SELECT FEE_TYPE,FEE_AMT, FEE_BOTTOM,FEE_TOP FROM CTP_PRO_FEE_CONF WHERE CTP_ID = '1' AND PRO_TYP = '1' AND '1'>= STAR_AMT AND '1' < END_AMT ;
SELECT FLAG FROM CTP_CONFIG_TR WHERE CTP_ID = '1' ;
SELECT UNI_NO,COMP_NAME,ID_TYP,ID_NO,COMP_PHONE,INDU_CATE,REG_AMT,COMP_PROP,LEGAL_NAME,LEGAL_ID_TYP,LEGAL_ID_NO,LEGAL_PHONE,LEGAL_PATH,COMP_ORG,COMP_ORG_PATH,COMP_LICEN,COMP_LICEN_PATH,IRS_REGIST,IRS_ID_NO,IRS_PATH,LAND_TAX_REGIST,LAND_TAX_ID_NO,LAND_TAX_PATH,APP_NO,APP_PATH,INST_CREDIT,INST_CREDIT_PATH,IS_EACCT_SIGN,SYNZ_URL,IS_SYNZ,SYNZ_RATE,CTP_TRAN_SEQ,SUBMIT_TELLER,UPD_TELLER,ORG_NO,CTP_ID,UNI_STAT,IS_EACCT_CERTIFY,EACCT_NO,EACCT_TYPE,CUSTOMERID,BACK_URL,IS_ACTIVE_SYNC,SYNZ_ACTIVE_RATE,IS_OPEN_SYNC,SYNZ_OPEN_RATE,AUDIT_OPINION,THREE_IN_ONE,TRANS_URL,IS_INNER_CUST,TRAN_SEQ,IS_PAR_COMP,PAR_COMP_NAME,PAR_ID_TYP,PAR_ID_NO,PAR_COMP_PHONE,PAR_INDU_CATE,PAR_REG_AMT,PAR_LEGAL_NAME,PAR_LEGAL_ID_TYP,PAR_LEGAL_ID_NO,PAR_LEGAL_PHONE,PAR_LEGAL_PATH,PAR_COMP_ORG,PAR_COMP_ORG_PATH,PAR_COMP_LICEN,PAR_COMP_LICEN_PATH,PAR_IRS_REGIST,PAR_IRS_PATH,PAR_LAND_TAX_REGIST,PAR_LAND_TAX_PATH,PAR_APP_NO,PAR_APP_PATH,PAR_INST_CREDIT,PAR_INST_CREDIT_PATH,PAR_THREE_IN_ONE,PAR_INST_CREDIT_DATE,PAR_INST_CREDIT_END_DATE,ACCT_NO,PASS_ID,ORI_TRANS_SEQ,IS_UPDATE,IS_CONFIRM_SYNC,SYNC_CONFIRM_RATE,USER_ID,SL_OPEN_SYNC,SL_OPEN_DATE,CUST_ROLE,CTP_DATE,IS_CANCEL,DO_FLAG,MOBILE FROM CTP_COMP_QUAIL_INFO WHERE CTP_ID='1' AND UNI_NO='1' ;
SELECT UNI_NO,COMP_NAME,ID_TYP,ID_NO,COMP_PHONE,INDU_CATE,REG_AMT,COMP_PROP,LEGAL_NAME,LEGAL_ID_TYP,LEGAL_ID_NO,LEGAL_PHONE,LEGAL_PATH,COMP_ORG,COMP_ORG_PATH,COMP_LICEN,COMP_LICEN_PATH,IRS_REGIST,IRS_ID_NO,IRS_PATH,LAND_TAX_REGIST,LAND_TAX_ID_NO,LAND_TAX_PATH,APP_NO,APP_PATH,INST_CREDIT,INST_CREDIT_PATH,IS_EACCT_SIGN,SYNZ_URL,IS_SYNZ,SYNZ_RATE,CTP_TRAN_SEQ,SUBMIT_TELLER,UPD_TELLER,ORG_NO,CTP_ID,UNI_STAT,IS_EACCT_CERTIFY,EACCT_NO,EACCT_TYPE,CUSTOMERID,BACK_URL,IS_ACTIVE_SYNC,SYNZ_ACTIVE_RATE,IS_OPEN_SYNC,SYNZ_OPEN_RATE,AUDIT_OPINION,THREE_IN_ONE,TRANS_URL,IS_INNER_CUST,TRAN_SEQ,IS_PAR_COMP,PAR_COMP_NAME,PAR_ID_TYP,PAR_ID_NO,PAR_COMP_PHONE,PAR_INDU_CATE,PAR_REG_AMT,PAR_LEGAL_NAME,PAR_LEGAL_ID_TYP,PAR_LEGAL_ID_NO,PAR_LEGAL_PHONE,PAR_LEGAL_PATH,PAR_COMP_ORG,PAR_COMP_ORG_PATH,PAR_COMP_LICEN,PAR_COMP_LICEN_PATH,PAR_IRS_REGIST,PAR_IRS_PATH,PAR_LAND_TAX_REGIST,PAR_LAND_TAX_PATH,PAR_APP_NO,PAR_APP_PATH,PAR_INST_CREDIT,PAR_INST_CREDIT_PATH,PAR_THREE_IN_ONE,ACCT_NO,PASS_ID,ORI_TRANS_SEQ,IS_CONFIRM_SYNC,SYNC_CONFIRM_RATE,USER_ID,SL_OPEN_SYNC,CUST_ROLE,IS_CANCEL,DO_FLAG,MOBILE FROM CTP_COMP_QUAIL_INFO WHERE CTP_TRAN_SEQ='1' ;
SELECT * FROM CTP_COMP_QUAIL_INFO WHERE UNI_NO='1' AND UNI_STAT='0' ;
SELECT * FROM CTP_INFO CI LEFT JOIN CTP_OPERATOR CO ON CI.CTP_ID = CO.CTP_ID WHERE CI.CTP_ID = '1' AND CO.OPER_ID = '1' ;
SELECT * FROM ctp_info WHERE CTP_ID='1' ;
SELECT * FROM CTP_OPERATOR WHERE CTP_ID = '1' and (lgn_id='1' or oper_mobile='1') ;
SELECT * FROM CTP_OPERATOR WHERE CTP_ID='1' AND OPER_ID='1' ;
SELECT * FROM CTP_OPERATOR WHERE CTP_ID = '1' AND OPER_ID='1' ;
SELECT PRO_ID,PRO_NAME,CTP_TYP,PRO_TYP,GOODS_ID,GOODS_NAME,GOODS_DESC,CHANNEL_ID,EBUSER_NO,STAT,ACCT_MIDDLE,KK_FLAG,CTP_ID FROM CTP_PRO_INFO WHERE PRO_ID='1' AND CTP_TYP='1' AND PRO_TYP='1' ;
SELECT * FROM CTP_SYS_MENU WHERE MENU_ID in (SELECT MENU_ID  from CTP_USER_ROLE_SYSMENU where ROLE_ID='1') ORDER BY MENU_ID,MENU_SORT ;
SELECT * FROM CTP_TRANS_CODE_QX ;
SELECT * FROM CTP_TRANS_ORDER_INFO WHERE CTP_ID = '1' AND ORDER_NO = '1' ;
SELECT * FROM ctp_user_menu WHERE CTP_ID = '1' AND OPER_ID = '1' ;
SELECT * FROM DTB_ACCT WHERE EBUSER_NO='1' AND ACCT_TP ='0' AND CTP_ID='1' ;
SELECT EBUSER_NO,ACCT_INDEX,ACCT_NO,ACCT_NAME,ACC_ALIAS,CCY_TYPE,ACCT_TP,HANG_ORG,HANG_TELER,HANG_CHAN,BANK_NO,BANK_NAME,IS_ACTIVE,IS_SIGN_MOBILE,PRE_NO,TRANIN_AMT,OPEN_ORG,ACC_TYPE,BIND_TYPE,CTP_ID,BRANCH_NO,CHANNEL_ID,REG_AMT,IS_RANDOM,DK_PRO_ID,DK_PRO_STATE,IS_DK,IS_DATA_TRANS,CUST_ROLE,ACCT_NO_ENCRYPT,IS_CANCEL,CANCEL_COUNT FROM DTB_ACCT WHERE EBUSER_NO='1' AND ACCT_TP !='0' AND CTP_ID='1' AND ACCT_NO = '1' ;
SELECT TRAN_SEQ,EBUSER_NO,ACCT_NO,TRANS_CHAN_TYPE,BATCH_NO,OPER_TYPE,OPER_AMT,CARD_NO,CARD_NAME,BANK_NO,BANK_NAME,TRAN_STATE,HOST_AMT,HOST_BALANCE,HOST_RESULT,HOST_CODE,HOST_MSG,HOST_QUERY_SEQ,REMARK,RECHARGE_SEQ,CANCEL_SEQ,FRONT_SEQ,NEED_CHECK,CHECK_WAY,CHECK_TELLER,CHECK_RESULT,IS_BATCH,CHAN_TYP,GG_BRANCH_NO,GG_TELLER_NO,TERMINALID,SYSID,CTP_ID,TZ_SEQ,CZ_SEQ,TRAN_FEE,CUST_FEE,ZJ_FEE,CTP_SEQ_NO,HY_FLAG,CLEAR_FLAG,PRO_TYP,CA_CHECK_FLAG,CF_CHECK_FLAG,TRAN_CHECK_FLAG,CANCEL_CHECK,BUC_CHECK_FLAG,ACCT_TP,ORI_CTP_SEQ FROM DTB_ROLL_TR WHERE TRAN_SEQ = '1' ;
SELECT TRAN_SEQ,EBUSER_NO,CARD_NO,CARD_NAME,OPER_AMT,OPER_TYPE,BANK_NAME,BANK_NO,UPAY_RESULT,UPAY_STATE,UPAY_ORDER_NO,UPAY_CODE,UPAY_MSG,UPAY_QUERY_SEQ,REMARK,CHECK_AMT,CHECK_RESULT,PASS_TYPE,ACC_TYPE,VALIDITY,CVN2,BRANCH_BANK,PROVICE,CITY,CERT_TYPE,CERT_NO,PROT_NO,MOBILE_NO,EMAIL,IS_BATCH,IS_TODAY_CHECK,CHAN_TYP,CTP_ID,CTP_USER_ID,TRAN_AMT,TRAN_FEE,FLAG,END_FLAG,SYS_TRACE_AUDIT_NUM FROM DTB_UPAY_LIST WHERE TRAN_SEQ='1' ;
SELECT * FROM MENU_TRANS_CODE_RELATION WHERE TRANS_CODE LIKE '%'||'1'||'%' ;
SELECT * FROM (SELECT CRR.CHAN_TYPE,CRR.RES_TYPE,PN.ID,PN.CATG_CODE,PN.TITLE,PN.CONTENT PNCONTENT,PN.USE_TIME STARDATE,PN.EXPIRE_TIME ENDDATE, CASE WHEN TO_DATE(PN.USE_TIME,'YYYY-MM-DD')<=SYSDATE AND TO_DATE(PN.EXPIRE_TIME,'YYYY-MM-DD')+1>=SYSDATE THEN '1' ELSE '0' END IS_USERFUL FROM PUB_NOTICE PN LEFT JOIN CHAN_RESOURCE_REL CRR ON PN.ID = CRR.ID AND CRR.RES_TYPE='C' WHERE CRR.CHAN_TYPE ='1' ) US WHERE US.IS_USERFUL='1' ORDER BY US.STARDATE DESC ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, ROW_NUMBER() OVER(ORDER BY OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP = '0' WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND A.CUST_NAME LIKE '%'||'1'||'%' AND A.EBUSER_TYP = '1' AND A.ID_NO LIKE '%'||'1'||'%' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, ROW_NUMBER() OVER(ORDER BY OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND A.CUST_NAME LIKE '%'||'1'||'%' AND A.EBUSER_TYP = '1' AND A.ID_NO LIKE '%'||'1'||'%' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, ROW_NUMBER() OVER(ORDER BY OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND A.EBUSER_TYP = '1' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.PRO_ID, A.PRO_NAME, A.PRO_TYP, A.PRO_AMT, A.RISK_LEV, A.PRO_DESC, CASE A.STAT WHEN '1' THEN '添加待确认' WHEN '2' THEN '已拒绝' WHEN '3' THEN '投标中' WHEN '4' THEN '已满标' WHEN '5' THEN '定标已受理' WHEN '6' THEN '已定标' WHEN '7' THEN '流标已受理' WHEN '8' THEN '已流标' WHEN '9' THEN '还款中' WHEN '10' THEN '兑付中' WHEN '11' THEN '已兑付' WHEN '31' THEN '待上架' WHEN '52' THEN '定标成功,打款失败' END STAT, A.CRE_DATE, A.CRE_TIME, A.STAR_BUY_TIME, A.END_BUY_TIME, A.STAR_DATE, A.END_DATE, A.PRO_TERM, A.EXPINC_RATE, A.MJ_NAME, A.MJ_ID_TYP, A.MJ_ID_NO, CASE A.HK_FLAG WHEN '0' THEN '止付' WHEN '1' THEN '直接划款' END HK_FLAG, CASE A.ZR_FLAG WHEN '0' THEN '否' WHEN '1' THEN '是' END ZR_FLAG, CASE A.DC_FLAG WHEN '0' THEN '否' WHEN '1' THEN '是' END DC_FLAG, CASE A.IS_DC_FLAG WHEN '0' THEN '未代偿' WHEN '1' THEN '已代偿' END IS_DC_FLAG, A.DC_AMT, A.DF_DATE, A.DF_TIME, A.BUY_ACCT, A.BUY_NAME, A.DF_ACCT, A.DF_NAME, A.FX_PER_TOP, A.TOT_FX_AMT, A.FEE_PER_TOP, A.AGREE_NO, CASE A.DB_FLAG WHEN '0' THEN '满标可定' WHEN '1' THEN '非满标可定' ELSE '未知' END DB_FLAG, A.LEFT_AMT, A.TOT_NUM, A.CONF_SEQ, CASE A.CONF_STAT WHEN '1' THEN '定标成功' WHEN '2' THEN '定标失败' WHEN '3' THEN '流标成功' WHEN '4' THEN '流标失败' END CONF_STAT, A.DF_SEQ, CASE A.DF_STAT WHEN '1' THEN '还款成功' WHEN '2' THEN '还款失败' WHEN '3' THEN '兑付成功' WHEN '4' THEN '兑付失败' END DF_STAT, A.FEE_ACCT1, A.FEE_NAME1, A.FEE_AMT1, A.FEE_ACCT2, A.FEE_NAME2, A.FEE_AMT2, A.FEE_ACCT3, A.FEE_NAME3, A.FEE_AMT3, A.ZR_FEE_ACCT, A.HK_AMT, A.PRO_MIN_AMT, A.DB_AMT, A.CTP_S_TIME, A.CTP_F_TIME, A.CTP_REPAY_TIME, A.CTP_CASH_TIME, A.IS_DATA_TRANS, A.ERR_MSG, CASE A.IS_AUTO_BID WHEN '0' THEN '否' WHEN '1' THEN '是' END IS_AUTO_BID, A.TOT_FEE, A.AUTO_REPAY_COUNT, A.AUTO_REPAY_QUOTA, A.AUTO_REPAY_END_DATE, A.HK_CORPUS, A.HK_ACCRUAL, ROW_NUMBER() OVER(ORDER BY CRE_DATE DESC,CRE_TIME DESC) AS RN FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' ORDER BY A.PRO_ID ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.*, ROW_NUMBER() OVER(ORDER BY CTP_ACCT) AS RN FROM CTP_ACCT A WHERE CTP_ID = '1' AND ACCT_STATE='N' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT IS_MOBILE,MOBILE FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT LGN_ID_TYP OPER_ID_TYP, LGN_ID_NO OPER_ID_NO, OPER_NAME, OPER_STAT, OPER_MOBILE, LAST_LGN_TIME FROM CTP_OPERATOR WHERE CTP_ID = '1' AND OPER_ID = '1' ;
SELECT MA.* FROM MARKET_ACTIVITY MA LEFT JOIN CHAN_RESOURCE_REL CRR ON MA.ACTIVITY_ID = CRR.ID WHERE CRR.CHAN_TYPE ='1' AND MA.STATE ='0' AND TO_DATE(MA.BEGIN_TIME,'YYYY-MM-DD')<=SYSDATE AND TO_DATE(MA.END_TIME,'YYYY-MM-DD')+1>=SYSDATE AND CRR.RES_TYPE='1' ORDER BY MA.ORDER_INDEX ASC ;
SELECT ORDER_NO FROM CTP_BT_ORDER_INFO WHERE CTP_ID = '1' AND ORDER_NO = '1' ;
SELECT ORDER_NO FROM CTP_PRO_CONFIRM_TR WHERE CTP_ID = '1' AND ORDER_NO = '1' ;
SELECT ORDER_NO FROM CTP_PRO_CONFIRM_TR WHERE CTP_ID = '1' AND ORDER_NO = '1' AND STAT IN ('10','22','32') ;
SELECT ORDER_NO FROM CTP_TRANS_ORDER_INFO WHERE CTP_ID = '1' AND ORDER_NO = '1' ;
SELECT ORG_NO FROM CTP_COMP_QUAIL_INFO WHERE UNI_NO='1' AND CTP_ID='1' ;
SELECT PARAM_TYPE,PARAM_VALUE FROM SYS_FILTER_PARAM ORDER BY SORT ;
SELECT PASS_URL,CHECK_TYPE, FEE_OUT_AMT FEE_COST FROM PASS_INF WHERE PASS_TYPE='1' ;
SELECT PAY_TYPE,ACCOUNT_NO FROM CTP_TRANS_CONF WHERE TRANS_CODE = '1' AND FEE_TYPE = '1' AND CTP_ID = '1' ;
SELECT PC.CITY CITY_CODE, PC.CITY_DESC CITY_NAME FROM PT_CITY PC WHERE CITY_NODE = '1' AND MSG_TYPE = 'CNAPS' ORDER BY PC.CITY ;
SELECT PCT.INTE_SEQ, PCT.ACCT_NO, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, TO_NUMBER(PCT.TRANS_AMT) TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME FROM PAYMENT_CHECK_TR PCT, DTB_ACCT DA WHERE DA.ACCT_NO = PCT.RCV_ACCT AND DA.ACCT_TP = '0' AND PCT.SUM_INFO!='0005' AND DA.CTP_ID='1' AND PCT.TRANS_DATE=REPLACE('1','-','') UNION ALL SELECT PCT.INTE_SEQ, PCT.ACCT_NO, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, TO_NUMBER(PCT.TRANS_AMT) TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME FROM PAYMENT_CHECK_TR PCT,CTP_ACCT CA WHERE CA.CTP_ACCT = PCT.RCV_ACCT AND CA.ACCT_STATE='N' AND PCT.SUM_INFO!='0005' AND CA.CTP_ID='1' AND PCT.TRANS_DATE=REPLACE('1','-','') ;
SELECT PMT.PROMPT_TYPE, PMT.PROMPT_TRANS_CODE, PMT.PROMPT_HOST_TRANS_CODE, PMT.PROMPT_MSG_CODE, PMT.PROMPT_PREVIOUS_MSG_VALUE, PMT.PROMPT_MSG_VALUE FROM PROMPT_MSG_TRANSLATE PMT ;
SELECT PP.PROVINCE_CODE PROV_CODE, PP.PROVINCE_NAME PROV_NAME FROM PT_PROVINCE PP ORDER BY PP.PROVINCE_CODE ;
SELECT SMS_TEMP_CONT FROM SMS_TEMP WHERE SMS_TEMP_ID='1' ;
SELECT SUM(BID_AMT)*100 FROM ( SELECT BID_AMT FROM CTP_PP_CONFIRM_TR WHERE CTP_ID = '1' AND BIDER_NO = '1' AND BID_STAT IN ('0','5','8','10') UNION ALL SELECT PRO_AMT FROM CTP_PP_INFO WHERE CTP_ID = '1' AND MJ_NO = '1' AND STAT IN ('3','4','5','6','7','9','10','31') ) ;
SELECT SUM(TRAN_AMT)*100 FROM CTP_PRO_CONFIRM_TR WHERE 1=1 AND (SELL_EBUSER='1' AND STAT IN('00','11','21','31','41')) OR (BUY_EBUSER='1' AND STAT IN('00','11','21','31','41')) AND CTP_ID='1' ;
SELECT T.PASS_TYPE,S.IS_BATCH,T.PASS_LEVEL,S.SUPPORT_DAY,S.DAY_AMT,TOTAL_ERR_NUM,S.MONTH_AMT FROM PASS_CTP_CONFIG T INNER JOIN PASS_DETAIL_CONF S ON T.PASS_TYPE=S.PASS_TYPE AND T.EBUSER_TYP=S.EBUSER_TYP WHERE T.BUSI_TYPE='1' AND T.CTP_ID='1' AND T.EBUSER_TYP = '1' AND S.BANK_CODE='1' AND S.BUSI_TYPE='1' AND to_char(sysdate,'HH24mi')>S.BEGIN_TIME AND to_char(sysdate,'HH24mi')<S.END_TIME AND '1'>=S.START_AMT AND '1'<=S.END_AMT ORDER BY T.PASS_LEVEL ;
SELECT TRAN_SEQ,CONF_SEQ,RETU_SEQ,CANC_SEQ,STAT FROM CTP_PRO_CONFIRM_TR WHERE CTP_ID = '1' AND CTP_TYP = '1' AND PRO_TYP = '1' AND ORDER_NO = '1' AND PRO_ID = '1' ;
SELECT TRANS_URL, URL_PARM FROM CTP_TRANS_URL_CONF WHERE TRAN_TYPE = '1' ;
SELECT T.TRANS_CODE, T.CHECK_TYPE, T.CHECK_CHAN, T.CHECK_COLUMN, T.IS_NULL_FLAG FROM CHAN_TRANS_AUTH_CHECK_CONF T WHERE T.CONF_STATUS = '0' ;
SELECT UNI_NO FROM CTP_COMP_QUAIL_INFO WHERE APP_NO ='1' AND (UNI_STAT IN('1','0') OR UNI_STAT='4' AND EACCT_NO IS NOT NULL) AND CTP_ID='1' ;
SELECT UNI_NO FROM CTP_COMP_QUAIL_INFO WHERE COMP_LICEN='1' AND (UNI_STAT IN('1','0') OR UNI_STAT='4' AND EACCT_NO IS NOT NULL) AND CTP_ID='1' ;
SELECT UNI_NO FROM CTP_COMP_QUAIL_INFO WHERE INST_CREDIT ='1' AND (UNI_STAT IN('1','0') OR UNI_STAT='4' AND EACCT_NO IS NOT NULL) AND CTP_ID='1' ;
SELECT UNI_NO,UNI_STAT,AUDIT_OPINION,IS_EACCT_SIGN,EACCT_NO,COMP_NAME,ID_TYP,ID_NO,THREE_IN_ONE,COMP_PHONE,INDU_CATE,REG_AMT, LEGAL_NAME,LEGAL_ID_TYP,LEGAL_ID_NO,LEGAL_PHONE,COMP_LICEN,IRS_REGIST,LAND_TAX_REGIST,APP_NO,COMP_ORG, CASE WHEN LEGAL_PATH is null THEN 'N' ELSE 'Y' END LEGAL_ID_NO_PIC, CASE WHEN COMP_LICEN_PATH is null THEN 'N' ELSE 'Y' END COMP_LICEN_PIC, CASE WHEN IRS_PATH is null THEN 'N' ELSE 'Y' END IRS_REGIST_PIC, CASE WHEN LAND_TAX_PATH is null THEN 'N' ELSE 'Y' END LAND_TAX_REGIST_PIC, CASE WHEN APP_PATH is null THEN 'N' ELSE 'Y' END APP_NO_PIC, CASE WHEN INST_CREDIT_PATH is null THEN 'N' ELSE 'Y' END INST_CREDIT_PIC, INST_CREDIT,TRANS_URL,IS_PAR_COMP,PAR_THREE_IN_ONE,PAR_COMP_ORG FROM CTP_COMP_QUAIL_INFO WHERE CTP_TRAN_SEQ='1' ;
SELECT UNIQUE(CTP_TYP) FROM CTP_PRO_TYP_CONF WHERE CTP_ID='1' ;
SELECT XABANK_PAY_ACCT,XABANK_REC_ACCT, XABANK_FEE_REC, DF_SETM_PAY_ACCT,DF_SETM_REC_ACCT, TRANS_CHAN_TYPE, XABANK_FEE_PAY, XABANK_PAY_NAME, XABANK_REC_NAME FROM XABANK_INNER_ACCT WHERE TRANS_CHAN_TYPE = '1' ;
SELECT ZJH_FLAG,JG_ACCT,KK_FLAG FROM CTP_BT_TYP_CONF WHERE CTP_ID='1' AND PRO_TYP='1' ;
SELECT A.*,B.OPEN_ORG FROM CTP_DF_TYP_CONF A LEFT JOIN CTP_INFO B ON A.CTP_ID = B.CTP_ID WHERE A.STAT ='0' ;
SELECT A.CTP_ID,A.PRO_ID, A.PRO_TYP,A.SYNZ_URL, B.ID_TYP,B.ID_NO, B.CUST_NAME ID_NAME,B.CUST_ROLE,A.OPER_TYPE,A.TRAN_STAT, A.CTP_SEQ TRANS_SEQ FROM CTP_PP_AUTO_COMPENT_TR A LEFT jOIN CTP_USER_INFO B ON A.EBUSER_NO = B.EBUSER_NO WHERE A.TRAN_STAT = '0' AND A.SYNZ_RATE <3 AND A.IS_SYNZ = 'N' AND A.SYNZ_URL IS NOT NULL ;
SELECT A.CTP_SEQ, A.PRO_ID, A.BID_SEQ_NO, C.CUST_NAME, A.BUY_ACCT BIDER_ACCT, A.BID_AMT, A.BUY_AMT TRAN_AMT, CASE WHEN A.TRAN_TYP = '0' THEN '手动投标' WHEN A.TRAN_TYP = '1' THEN '单笔自动投标' END AS BID_TYP, B.ACTIVE_ACCT1, B.ACTIVE_NAME1, B.ACTIVE_AMT1, B.ACTIVE_ACCT2, B.ACTIVE_NAME2, B.ACTIVE_AMT2, B.ACTIVE_ACCT3, B.ACTIVE_NAME3, B.ACTIVE_AMT3, TO_CHAR(TO_DATE(A.SUBMIT_TIME, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD') CRE_DATE, TO_CHAR(TO_DATE(A.SUBMIT_TIME, 'YYYY-MM-DD HH24:MI:SS'), 'HH24:MI:SS') CRE_TIME, TO_CHAR(TO_DATE(A.COMP_TIME, 'YYYY-MM-DD HH24:MI:SS'), 'YYYY-MM-DD') BID_DATE, TO_CHAR(TO_DATE(A.COMP_TIME, 'YYYY-MM-DD HH24:MI:SS'), 'HH24:MI:SS') BID_TIME FROM CTP_PP_BID_TR A LEFT JOIN CTP_PP_ORDER_TR B ON A.CTP_SEQ = B.CTP_SEQ AND A.CTP_ID = B.CTP_ID AND A.PRO_ID = B.PRO_ID AND A.BID_SEQ_NO = B.BID_SEQ_NO LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO = A.BUY_NO WHERE A.CTP_ID='1' AND A.STAT='0' AND SUBSTR(COMP_TIME,0,10)='1' UNION ALL SELECT CTP_SEQ,PRO_ID, BID_SEQ BID_SEQ_NO, ID_NAME CUST_NAME, PAY_ACCT BIDER_ACCT, TRAN_AMT BID_AMT, TRAN_AMT, '批量自动投标' BID_TYP, ACTIVE_ACCT1, '' ACTIVE_NAME1, ACTIVE_AMT1, ACTIVE_ACCT2, '' ACTIVE_NAME2, ACTIVE_AMT2, ACTIVE_ACCT3, '' ACTIVE_NAME3, ACTIVE_AMT3, TRAN_DATE CRE_DATE, TRAN_TIME CRE_TIME, COMPLE_DATE BID_DATE, COMPLE_TIME BID_TIME FROM CTP_BATCH_AUTOBID_TR WHERE STAT = '0' AND CTP_ID = '1' AND TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT A.CTP_SEQ, A.PRO_ID, C.PRO_NAME, A.ORI_BID_SEQ_NO, A.ZR_NAME, A.ZR_ID_TYP, A.ZR_ID_NO, A.BID_AMT, A.TRAN_AMT, A.BID_SEQ_NO, A.BUY_NAME, A.BUY_ID_TYP, A.BUY_ID_NO, A.ACTIVE_ACCT1, A.ACTIVE_NAME1, A.ACTIVE_AMT1, A.ACTIVE_ACCT2, A.ACTIVE_NAME2, A.ACTIVE_AMT2, A.FEE_ACCT1, A.FEE_NAME1, A.FEE_AMT1, A.FEE_ACCT2, A.FEE_NAME2, A.FEE_AMT2, A.FEE_ACCT3, A.FEE_NAME3, A.FEE_AMT3, CASE WHEN A.ZR_TYP='0'THEN '部分转让' WHEN A.ZR_TYP='1' THEN '全部转让' END AS ZR_TYP, CASE WHEN B.BID_TYP='1' THEN '转让' WHEN B.BID_TYP = '4' THEN '自动投债权' END AS BID_TYP, A.ZR_DATE, A.ZR_TIME FROM CTP_PP_ZR_ORDER_TR A LEFT JOIN CTP_PP_CONFIRM_TR B ON A.CTP_ID=B.CTP_ID AND A.PRO_ID=B.PRO_ID AND A.BID_SEQ_NO = B.BID_SEQ_NO LEFT JOIN CTP_PP_INFO C ON A.CTP_ID=C.CTP_ID AND A.PRO_ID=C.PRO_ID WHERE A.STAT='4' AND B.BID_TYP IN('1','4') AND A.CTP_ID='1' AND A.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') order by a.pro_id ;
SELECT A.CTP_SEQ, A.PRO_ID, PPINFO.PRO_NAME, A.TRAN_AMT, A.HOST_SN, A.RCV_ACCT, A.RCV_NAME, A.PAY_ACCT, A.PAY_NAME, A.RESC_RACT_NO FROM CTP_TRAN_INFO A LEFT JOIN CTP_PP_INFO PPINFO ON A.PRO_ID = PPINFO.PRO_ID WHERE A.CTP_ID = '1' AND A.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ORDER BY A.TRAN_DATE,A.TRAN_TIME,A.PRO_ID DESC ;
SELECT A.CTP_SEQ, B.ID_TYP, B.ID_NO, B.CUST_NAME, A.PAY_ACCT, B.MOBILE, A.RCV_ACCT, A.RCV_NAME, A.PRO_ID, A.TRAN_AMT, A.STAT, C.TRAN_DATE, C.TRAN_TIME, C.UPD_DATE, C.UPD_TIME FROM CTP_PP_REPAY_TR A LEFT JOIN CTP_USER_INFO B ON A.CTP_ID = B.CTP_ID AND A.PAY_NO = B.EBUSER_NO LEFT JOIN CTP_TRANS_TR C ON A.TRAN_SEQ = C.TRAN_SEQ AND C.CTP_ID=A.CTP_ID WHERE A.STAT='0' AND A.CTP_ID='1' AND C.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT A.ID_TYP, A.ID_NO, A.CUST_NAME ID_NAME, C.CTP_ID, C.TRAN_SEQ, C.CTP_SEQ TRANS_SEQ, C.SYNZ_URL, C.CUST_ROLE FROM CTP_URL_TR C LEFT JOIN CTP_USER_INFO A ON A.EBUSER_NO = C.EBUSER_NO WHERE C.IS_CANCEL = '1' AND C.IS_SYNZ = 'N' AND C.SYNZ_URL IS NOT NULL AND C.SYNZ_RATE < 3 ;
SELECT A.SYNZ_URL, A.CTP_ID, A.CTP_SEQ TRANS_SEQ, A.TRANS_SEQ TRAN_SEQ, A.ID_TYP, A.ID_NO, A.ID_NAME COMP_NAME, A.MOBILE_NO MOBILE, A.ELE_ACCT_NO, C.ACCT_NO, C.IS_ACTIVE, TO_CHAR(C.REG_AMT *100) REG_AMT, CUI.CUST_ROLE, C.BANK_NAME BIND_BANK_NAME, C.BANK_NO BIND_BANK_NO, B.IS_SIGN_MOBILE, B.BANK_NAME, B.BANK_NO FROM CTP_BATCH_ACTIVE_TR A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO = B.EBUSER_NO AND A.ELE_ACCT_NO = B.ACCT_NO LEFT JOIN DTB_ACCT C ON A.EBUSER_NO=C.EBUSER_NO AND C.ACCT_TP<>'0' LEFT JOIN CTP_USER_INFO CUI ON A.EBUSER_NO = CUI.EBUSER_NO AND A.CTP_ID = CUI.CTP_ID WHERE A.SYNZ_URL IS NOT NULL AND A.SYNZ_ACTIVE_RATE < 3 AND A.IS_ACTIVE_SYNZ = 'N' AND C.ACCT_NO IS NOT NULL AND A.IS_ACTIVE_STAT = 'Y' AND A.EBUSER_TYP = 'E' ;
SELECT BUSI_TYP,SERVICE_TYPE,FILE_FLAG,CFSQ_FLAG FROM CTP_SERVICE_TYPE_CONF WHERE TRAN_TYP = '1' AND UPD_DATE = TO_CHAR(SYSDATE,'yyyy-MM-dd') ;
SELECT CBAT.CTP_SEQ TRANS_SEQ, CBAT.CTP_ID, CBAT.SYNZ_URL, CBAT.ID_NAME AS CUST_NAME, CBAT.ID_TYP, CBAT.ID_NO, CBAT.MOBILE_NO AS MOBILE, DA.ACCT_NO AS ELE_ACCT_NO, DA1.ACCT_NO, DA1.IS_ACTIVE, DA1.REG_AMT, DA1.CUST_ROLE, DA.IS_SIGN_MOBILE, DA.BANK_NO, DA.BANK_NAME, DA1.BANK_NO AS BIND_BANK_NO, DA1.BANK_NAME AS BIND_BANK_NAME, CASE WHEN (SELECT COUNT(*) FROM CTP_FINAN_PLAN_INFO CFPI WHERE CFPI.EBUSER_NO = DA.EBUSER_NO AND CFPI.STAT = '0') > 0 THEN '0' ELSE '1' END AS FIN_SIGN_STAT FROM CTP_FIN_BATCH_ACTIVE_TR CBAT LEFT JOIN DTB_ACCT DA ON CBAT.EBUSER_NO = DA.EBUSER_NO AND DA.ACCT_TP = '0' LEFT JOIN DTB_ACCT DA1 ON CBAT.EBUSER_NO = DA1.EBUSER_NO AND DA1.ACCT_TP != '0' WHERE CBAT.IS_ACTIVE_STAT = 'Y' AND CBAT.SYNZ_ACTIVE_RATE < 3 AND CBAT.IS_ACTIVE_SYNZ = 'N' AND CBAT.SYNZ_URL IS NOT NULL ;
SELECT CBHT.SEQ_NO, CBHT.CTP_SEQ, CBHT.PRO_ID, PPINFO.PRO_NAME, CPCT.BID_SEQ_NO BID_SEQ, CUI.ID_TYP, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CASE CBHT.JD_FLAG WHEN '3' THEN'借' WHEN '4' THEN '贷' END JD_FLAG, CBHT.TRAN_AMT, CASE CBHT.STAT WHEN '0' THEN'成功' WHEN '1' THEN '已受理' WHEN '2' THEN '失败' WHEN '4' THEN '部分成功' END STAT, CBHT.HOST_MSG, CBHT.TRAN_DATE, CBHT.TRAN_TIME, CBHT.COMPLE_DATE, CBHT.COMPLE_TIME FROM CTP_BATCH_HOST_TR CBHT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBHT.DETAIL_SEQ = CPCT.CONF_SEQ AND CPCT.BID_STAT NOT IN ('6') AND CPCT.CONF_STAT IN ('10','14') LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO LEFT JOIN CTP_PP_INFO PPINFO ON CBHT.PRO_ID = PPINFO.PRO_ID WHERE CBHT.CTP_ID = '1' AND CBHT.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND CBHT.TRAN_TYPE IN('2','3') ORDER BY CBHT.TRAN_DATE,CBHT.TRAN_TIME,CBHT.PRO_ID DESC ;
SELECT CBRT.CTP_SEQ, CBRT.SEQ_NO, CBRT.ID_TYP, CBRT.ID_NO, CBRT.ID_NAME, CBRT.ACCT_NO, CBT.ACCT_NAME, CBT.ACCT_NO CTP_ACCT, CBRT.TRAN_AMT, CBRT.STAT, CBRT.TRAN_DATE, CBRT.TRAN_TIME, CBRT.COMPLE_DATE, CBRT.COMPLE_TIME FROM CTP_BATCH_REBATE_TR CBRT LEFT JOIN CTP_BATCH_TR CBT ON CBT.CTP_SEQ = CBRT.CTP_SEQ AND CBT.TRAN_TYPE = '6' WHERE CBRT.STAT = '0' AND CBRT.CTP_ID = '1' AND CBRT.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ORDER BY CBRT.TRAN_DATE DESC,CBRT.TRAN_TIME DESC ;
SELECT C.CTP_SEQ, C.PRO_ID, C.PRO_NAME, C.SEQ_NO, C.ACCT_NO, C.ACCT_NAME, C.TRAN_AMT, C.REAL_AMT, C.STAT, C.HOST_MSG, C.TRAN_DATE, C.TRAN_TIME, C.COMPLE_DATE, C.COMPLE_TIME FROM CTP_BATCH_REPAY_TR C WHERE C.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND C.CTP_ID = '1' AND C.STAT = '0' AND C.FEE_FLAG = '2' ORDER BY C.PRO_ID, C.SEQ_NO, C.TRAN_DATE, C.TRAN_TIME ;
SELECT C.CTP_SEQ, C.PRO_ID, C.PRO_NAME, C.SEQ_NO, C.ACCT_NO, C.ACCT_NAME, C.TRAN_AMT, C.REAL_AMT, C.STAT, C.HOST_MSG, C.TRAN_DATE, C.TRAN_TIME, C.COMPLE_DATE, C.COMPLE_TIME FROM CTP_BATCH_REPAY_TR C WHERE C.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND C.CTP_ID = '1' AND C.STAT = '0' AND C.FEE_FLAG = '3' ORDER BY C.PRO_ID,C.SEQ_NO,C.TRAN_DATE,C.TRAN_TIME ;
SELECT C.CTP_SEQ, C.PRO_ID, C.PRO_NAME, C.SEQ_NO, C.BACK_FLAG, C.ACCT_NO, C.ACCT_NAME, C.TRAN_AMT, C.REAL_AMT, C.STAT, C.HOST_MSG, C.TRAN_DATE, C.TRAN_TIME, C.COMPLE_DATE, C.COMPLE_TIME, C.FIRST_FLAG, C.DIFF_AMT FROM CTP_BATCH_REPAY_TR C WHERE C.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND C.CTP_ID = '1' AND C.STAT = '0' AND C.FEE_FLAG = '0' ORDER BY C.PRO_ID, C.SEQ_NO, C.TRAN_DATE, C.TRAN_TIME ;
SELECT C.CTP_SEQ, C.PRO_ID, C.PRO_NAME, C.SEQ_NO, C.BACK_FLAG, C.ACCT_NO, C.ACCT_NAME, D.TRAN_AMT, C.REAL_AMT, C.STAT, C.HOST_MSG, C.TRAN_DATE, C.TRAN_TIME, C.COMPLE_DATE, C.COMPLE_TIME, C.DIFF_AMT FROM CTP_BATCH_REPAY_TR C LEFT JOIN CTP_BATCH_TR D ON D.CTP_ID=C.CTP_ID AND D.CTP_SEQ=C.CTP_SEQ WHERE C.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND C.CTP_ID = '1' AND C.STAT = '0' AND C.FEE_FLAG = '1' ORDER BY C.PRO_ID, C.SEQ_NO, C.TRAN_DATE, C.TRAN_TIME ;
SELECT COUNT(1) ACCOUNT_NUMBER FROM CTP_USER_INFO WHERE 1=1 AND CTP_ID = '1' AND OPEN_DATE like '1' ;
SELECT COUNT(1) DK_NUMBER,SUM(OPER_AMT) DK_AMT FROM DTB_UPAY_LIST WHERE OPER_TYPE='0' AND UPAY_STATE='6' AND CTP_ID = '1' AND SUBSTR(SUBMIT_TIME,0,10) like '1' ;
SELECT COUNT(1) FROM CTP_BATCH_AUTOBID_TR A LEFT JOIN CTP_USER_INFO B ON A.BID_NO = B.EBUSER_NO WHERE A.CTP_ID = '1' AND A.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND A.STAT = '0' ;
SELECT COUNT(1) FROM CTP_BATCH_AUTOCREDIT_TR WHERE STAT = '0' AND CTP_ID = '1' AND TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_BATCH_CANCEL_TR A LEFT JOIN CTP_USER_INFO CUI ON A.EBUSER_NO = CUI.EBUSER_NO WHERE A.STAT = '0' AND A.CTP_ID = '1' AND A.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_BATCH_HOST_TR CBHT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBHT.DETAIL_SEQ = CPCT.CONF_SEQ LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO WHERE CBHT.STAT = '0' AND CBHT.CTP_ID = '1' AND CBHT.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_BATCH_REBATE_TR A LEFT JOIN CTP_USER_INFO B ON A.EBUSER_NO = B.EBUSER_NO WHERE A.STAT = '0' AND A.CTP_ID = '1' AND A.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_BATCH_REPAY_TR CBRT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBRT.DETAIL_SEQ = CPCT.DF_SEQ LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO WHERE CBRT.STAT = '0' AND CBRT.CTP_ID = '1' AND CBRT.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_CHECK_FILE_TR WHERE UPDATE_TIME=TO_CHAR(SYSDATE,'yyyy-MM-dd') AND IS_CENTER = '1' AND TRAN_TYP = '1' ;
SELECT COUNT(1) FROM CTP_COMMON_TR A JOIN CTP_USER_INFO B ON A.EBUSER_NO = B.EBUSER_NO WHERE A.CTP_ID = '1' AND A.STAT = '0' AND A.TRANS_CODE = 'ctpP2pProjectAutoCreditTransf' AND A.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_FINAN_PLAN_TR D LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO = D.EBUSER_NO WHERE D.CTP_ID = '1' AND D.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND D.STAT = '0' ;
SELECT COUNT(1) FROM CTP_JF_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO WHERE B.STAT = '2' AND NVL(B.CTP_DATE,B.CRE_DATE) <= '1' AND B.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT count(1) FROM CTP_PP_ADD_TR B WHERE B.STAT = '5' AND B.CTP_DATE <= '1' AND CONF_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_PP_AUTO_BID_TR B JOIN CTP_USER_INFO C ON C.EBUSER_NO=B.EBUSER_NO WHERE B.STAT = '0' AND B.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_PP_BID_TR A LEFT JOIN CTP_USER_INFO b ON A.BUY_NO = b.EBUSER_NO WHERE NVL(A.CTP_DATE,SUBSTR(SUBMIT_TIME,0,10)) <= '1' AND SUBSTR(A.COMP_TIME,0,10) = '1' AND A.CTP_ID = '1' AND A.STAT='0' AND A.BID_SEQ_NO IS NOT NULL ;
SELECT COUNT(1) FROM CTP_PP_REPAY_TR A LEFT JOIN CTP_USER_INFO B ON B.ebuser_no=A.RCV_NO LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO=A.PAY_NO WHERE A.STAT = '0' AND NVL(A.CTP_DATE,A.TRAN_DATE) <= '1' AND A.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND C.CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_PP_ZR_ORDER_TR B LEFT JOIN CTP_PP_CONFIRM_TR C ON B.CTP_ID=C.CTP_ID AND B.PRO_ID = C.PRO_ID AND B.BID_SEQ_NO = C.BID_SEQ_NO WHERE NVL(B.CTP_DATE,to_char(to_date(B.ZR_DATE,'yyyy-mm-dd'),'yyyy-mm-dd')) <= '1' AND B.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.STAT = '4' AND C.BID_TYP='1' AND C.CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_PP_ZR_ORDER_TR B WHERE B.CTP_DATE <= '1' AND B.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.STAT = '4' AND B.BID_TYP='4' AND B.CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_SERVICE_TYPE_CONF WHERE TRAN_TYP='1' AND UPD_DATE = TO_CHAR(SYSDATE,'YYYY-MM-DD') ;
SELECT COUNT(1) FROM CTP_SUB_TRANSFER_TR D JOIN CTP_USER_INFO C ON D.EBUSER_NO=C.EBUSER_NO AND D.CTP_ID = C.CTP_ID WHERE D.TRAN_STAT = '0' AND D.TRAN_FLAG='0' AND D.CTP_DATE <= '1' AND D.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND D.CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_TRANS_TR WHERE TRAN_DATE=TO_CHAR((SELECT SYSDATE-INTERVAL '1' DAY FROM DUAL),'yyyy-MM-dd') AND CTP_ID='78000010' AND TRANS_CODE IN ('ctpTransIn','ctpTransOut') ;
SELECT COUNT(1) FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO LEFT JOIN CTP_TRANS_ORDER_INFO CTOI ON B.CTP_ID = CTOI.CTP_ID AND B.CTP_SEQ_NO = CTOI.CTP_SEQ WHERE B.TRAN_STATE = '6' AND B.OPER_TYPE = '0' AND CTOI.CTP_DATE <= '1' AND CTOI.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT COUNT(1) FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO LEFT JOIN CTP_TRANS_ORDER_INFO CTOI ON B.CTP_ID = CTOI.CTP_ID AND B.CTP_SEQ_NO = CTOI.CTP_SEQ WHERE B.TRAN_STATE = '7' AND B.OPER_TYPE = '1' AND CTOI.CTP_DATE <= '1' AND CTOI.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT COUNT(1) FROM (SELECT PCT.INTE_SEQ, PCT.ACCT_NO, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, TO_NUMBER(PCT.TRANS_AMT) TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME, ROW_NUMBER() OVER(ORDER BY PCT.INTE_SEQ DESC) AS RN FROM PAYMENT_CHECK_TR PCT, DTB_ACCT DA WHERE DA.ACCT_NO = PCT.RCV_ACCT AND DA.ACCT_TP = '0' AND PCT.SUM_INFO!='0005' AND DA.CTP_ID='1' AND PCT.TRANS_DATE=REPLACE('1','-','') UNION ALL SELECT PCT.INTE_SEQ, PCT.ACCT_NO, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, TO_NUMBER(PCT.TRANS_AMT) TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME, ROW_NUMBER() OVER(ORDER BY PCT.INTE_SEQ DESC) AS RN FROM PAYMENT_CHECK_TR PCT,CTP_ACCT CA WHERE CA.CTP_ACCT = PCT.RCV_ACCT AND CA.ACCT_STATE='N' AND PCT.SUM_INFO!='0005' AND CA.CTP_ID='1' AND PCT.TRANS_DATE=REPLACE('1','-','')) ;
SELECT COUNT(1) FROM TPP_BATCH_TR TBT LEFT JOIN TPP_BATCH_WITHHOLD_TR TBWT ON TBT.BATCH_NO = TBWT.BATCH_NO LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO=TBWT.EBUSER_NO WHERE TBWT.OPER_TYPE = '0' AND TBWT.STAT = '3' AND TBWT.CTP_ID ='1' AND TBWT.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT count(*) FROM CTP_CHECK_FILE_TR WHERE UPDATE_TIME = TO_CHAR(SYSDATE,'yyyy-MM-dd') AND NVL(IS_CHECK,'0') = '0' AND TRAN_TYP = '1' ;
SELECT count(*) FROM CTP_CHECK_FILE_TR WHERE UPDATE_TIME = TO_CHAR(SYSDATE,'yyyy-MM-dd') AND TRAN_TYP = '1' ;
SELECT CTP_ID,CTP_NAME,ACCOUNT FROM CTP_INFO ;
SELECT CTP_ID,CTP_SEQ,CTP_SEQ TRANS_SEQ,ID_TYP,ID_NO,ID_NAME,SYNZ_URL,TRAN_STAT FROM CTP_COMPENT_TR WHERE TRAN_STAT = '0' AND SYNZ_RATE <3 AND IS_SYNZ = 'N' AND SYNZ_URL IS NOT NULL ;
SELECT CTP_ID FROM CTP_INFO ;
SELECT CTP_ID,MID_FEE_TYPE,CTP_SEQ,ORIGINAL_ACCT,ORIGINAL_ACCT_NAME,PAY_ACCT,PAY_NAME,TRAN_AMT,TRAN_DATE,TRAN_TIME FROM CTP_TRANS_TR WHERE CTP_ID = '1' AND TRAN_STAT = '2' AND MID_FEE_TYPE = '1' AND FEE_TYPE = '1' AND TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND HOST_CHECK = '1' ;
SELECT CTP_ID,MID_FEE_TYPE,CTP_SEQ,PRO_ID,ORIGINAL_ACCT,ORIGINAL_ACCT_NAME,TRAN_AMT,COMPLE_DATE,COMPLE_TIME FROM CTP_BATCH_HOST_TR WHERE CTP_ID = '1' AND MID_FEE_TYPE = '1' AND COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND STAT = '0' ;
SELECT CTP_ID,PRO_ID,BUY_NO,BUY_AMT TRAN_AMT,STAT,CTP_SEQ FROM CTP_PP_BID_TR WHERE TRANS_SEQ = '1' ;
SELECT CTP_ONLINE_DATE,CONTRACT_BEGIN_DATE,CONTRACT_END_DATE,COMP_FULL_NAME FROM CTP_ONLINE_INFO WHERE 1=1 AND CTP_ID = '1' ;
SELECT CTP_TASK_SEQ_NO.NEXTVAL FROM DUAL ;
SELECT CTT.TRAN_SEQ, CTT.PAY_ACCT, CTT.PAY_NAME, CUI.ID_NO, CUI.ID_TYP, CTT.RCV_ACCT, CTT.RCV_NAME, CTT.TRAN_AMT, CTT.TRAN_STAT,CTT.UPD_DATE,CTT.UPD_TIME FROM CTP_TRANS_TR CTT LEFT JOIN DTB_ACCT DA ON CTT.PAY_ACCT = DA.ACCT_NO LEFT JOIN CTP_USER_INFO CUI ON DA.EBUSER_NO = CUI.EBUSER_NO WHERE TRANS_CODE = 'ctpPayMentTran' AND TRAN_STAT = '2' AND CTT.CTP_ID='1' AND CTT.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ORDER BY UPD_DATE DESC, UPD_TIME DESC ;
SELECT DISTINCT * FROM ( SELECT A.TRAN_SEQ, A.CTP_ID, A.RCV_ACCT, A.RCV_NAME, NVL(A.ORIGINAL_ACCT, A.RCV_ACCT) ORIGINAL_ACCT, NVL(A.ORIGINAL_ACCT_NAME, A.RCV_NAME) ORIGINAL_ACCT_NAME, A.TRAN_STAT,A.SEQ,A.TRAN_AMT, A.FEE_TYPE,A.PAY_ACCT, A.PAY_NAME,A.PAY_TYPE, A.TRAN_DATE, A.TRAN_TIME, A.CTP_TYP, A.TRAN_HOST_NO, B.BUSI_TYP, B.SERVICE_TYPE, A.UPD_DATE,A.UPD_TIME, A.QZ_SEQ,A.QZ_DATE, A.HOST_DATE,A.TRANS_CODE, A.MID_FEE_TYPE FROM CTP_TRANS_TR A LEFT JOIN CTP_CHECK_FILE_TR B ON A.TRAN_SEQ = B.TRANS_SEQ WHERE NVL(A.HOST_CHECK, '0') != '0' AND A.TRAN_SEQ = B.TRANS_SEQ AND NVL(A.ROLL_CHECK, '0') = '0' AND B.TRAN_TYP = '1' ) ;
SELECT DRT.CTP_SEQ_NO CTP_SEQ, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CUI.ID_TYP, CUI.MOBILE, DRT.OPER_AMT, DRT.ACCT_NO ELE_ACCT_NO, DRT.CARD_NO ACCT_NO, DRT.BANK_NAME, DRT.TRAN_STATE, DRT.TRAN_FEE FEE_AMT, DRT.TRAN_FEE-DRT.CUST_FEE ACTIVITY_FEE, DRT.TRAN_DATE, DRT.TRAN_TIME, TO_CHAR(TO_DATE(DRT.HOST_TIME,'YYYY-MM-DD HH24:MI:SS'),'YYYY-MM-DD') WC_DATE, TO_CHAR(TO_DATE(DRT.HOST_TIME,'YYYY-MM-DD HH24:MI:SS'),'HH24:MI:SS') WC_TIME FROM DTB_ROLL_TR DRT LEFT JOIN CTP_USER_INFO CUI ON DRT.EBUSER_NO = CUI.EBUSER_NO WHERE DRT.TRAN_STATE='7' AND DRT.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND DRT.CTP_ID='1' AND DRT.OPER_TYPE='1' ;
SELECT F.CTP_SEQ, U.ID_TYP, U.ID_NO, U.CUST_NAME, U.MOBILE, S.ACCT_NO, C.PACKAGE_ID, C.PACKAGE_NAME, C.FEE_TOP, C.SUB_ACCT_NO, C.AMT, F.ACTIVE_ACCT1, F.ACTIVE_NAME1, F.ACTIVE_AMT1, F.ACTIVE_ACCT2, F.ACTIVE_NAME2, F.ACTIVE_AMT2, F.ACTIVE_ACCT3, F.ACTIVE_NAME3, F.ACTIVE_AMT3, F.STAT, F.TRAN_DATE, F.TRAN_TIME, C.SIGN_DATE, C.SIGN_TIME FROM CTP_FINAN_PLAN_INFO C LEFT JOIN CTP_FINAN_PLAN_TR F ON F.SUB_ACCT_NO = C.SUB_ACCT_NO AND F.EBUSER_NO = C.EBUSER_NO AND F.PACKAGE_ID = C.Package_Id LEFT JOIN CTP_USER_INFO U ON C.EBUSER_NO = U.EBUSER_NO LEFT JOIN CTP_SUB_ACCT S ON C.SUB_ACCT_NO = S.SUB_ACCT_NO WHERE F.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND F.STAT = '0' AND F.CTP_ID = '1' ;
SELECT FLAG FROM CTP_CONFIG_TR WHERE CTP_ID = '1' ;
SELECT * FROM ACP_BATCH_TR where TRAN_STAT='1' AND ROWNUM <=10 ;
SELECT * FROM CTP_CHECK_KEY_SQL_INFO WHERE OPEN_TYPE = '1' ;
SELECT * FROM CTP_CHECK_ZIP_INFO WHERE STAT = '0' ;
SELECT * FROM CTP_CHECK_ZIP_INFO WHERE STAT = '0' AND CTP_ID = '1' ;
SELECT * FROM CTP_MIDDLE_TRANSFER_TR WHERE TRAN_STATE = '4' AND ROWNUM <= 100 ;
SELECT * FROM CTP_PP_BID_TR WHERE STAT='1' AND TO_DATE(SUBMIT_TIME,'YYYY-MM-DD HH24:MI:SS')<SYSDATE-15/(24*60) AND QUERY_RATE<3 AND ROWNUM<1001 ;
SELECT * FROM CTP_PP_REPAY_TR WHERE STAT='1' AND TO_DATE(TRAN_DATE||TRAN_TIME,'YYYY-MM-DD HH24:MI:SS')<SYSDATE-15/(24*60) AND QUERY_RATE<3 AND ROWNUM<1001 ;
SELECT TRANS_SEQ,CTP_ID,CTP_SEQ,PRO_ID,ORI_BID_SEQ_NO,BID_SEQ_NO,ZR_EBUSER_NO,ZR_ACCT,ZR_NAME,ZR_ID_TYP,ZR_ID_NO,BID_AMT,TRAN_AMT,TOT_AMT,ZR_TYP,STAT,BUY_EBUSER_NO,BUY_ACCT,BUY_NAME,BUY_ID_TYP,BUY_ID_NO,RET_CODE,RET_MSG,HOST_SEQ,HOST_SEQ1,HOST_SEQ2,ACTIVE_ACCT1,ACTIVE_NAME1,ACTIVE_AMT1,ACTIVE_ACCT2,ACTIVE_NAME2,ACTIVE_AMT2,IS_SYNZ,SYNZ_URL,BACK_URL,SYNZ_RATE,FEE_ACCT1,FEE_NAME1,FEE_AMT1,FEE_ACCT2,FEE_NAME2,FEE_AMT2,FEE_ACCT3,FEE_NAME3,FEE_AMT3,IS_CHECK,FEE_STAT1,FEE_STAT2,FEE_STAT3,ZR_PERC,AC_STAT1,AC_STAT2,PRO_TYP,BID_TYP FROM CTP_PP_ZR_ORDER_TR WHERE CTP_SEQ='1' AND CTP_ID = '1' AND PRO_ID = '1' ;
SELECT * FROM CTP_PP_ZR_TR WHERE STAT='1' AND TO_DATE(ZR_DATE||ZR_TIME,'YYYY-MM-DD HH24:MI:SS')<SYSDATE-15/(24*60) AND QUERY_RATE<3 AND ROWNUM<1001 ;
SELECT * FROM CTP_PP_ZR_TR WHERE TRANS_SEQ='1' ;
SELECT * FROM CTP_SUB_TRANSFER_TR WHERE TRAN_STAT='1' AND TO_DATE(TRAN_DATE||TRAN_TIME,'YYYY-MM-DD HH24:MI:SS')<SYSDATE-15/(24*60) AND QUERY_RATE<3 AND ROWNUM<1001 ;
SELECT * FROM CTP_TASK_THREAD_INFO T LEFT JOIN CTP_TASK_JOB_INFO S ON T.JOB_NAME=S.JOB_NAME WHERE S.IP_POOR_FLAG='1' ;
SELECT * FROM CTP_TRANS_TR WHERE NVL(HOST_CHECK,'0') = '0' AND TRAN_SEQ = '1' ;
SELECT * FROM CTP_TRANS_UN_TR WHERE QUE_NUM < 3 AND TRAN_STAT = '4' AND (to_date(TRAN_DATE||' '||TRAN_TIME,'YYYY-MM-DD HH24:MI:SS')+TO_NUMBER(900)/24/60/60<SYSDATE) ;
SELECT TRAN_SEQ,EBUSER_NO,ACCT_NO,TRANS_CHAN_TYPE,BATCH_NO,OPER_TYPE,OPER_AMT,CARD_NO,CARD_NAME,BANK_NO,BANK_NAME,TRAN_STATE,HOST_AMT,HOST_BALANCE,HOST_RESULT,HOST_CODE,HOST_MSG,HOST_QUERY_SEQ,REMARK,RECHARGE_SEQ,CANCEL_SEQ,FRONT_SEQ,NEED_CHECK,CHECK_WAY,CHECK_TELLER,CHECK_RESULT,IS_BATCH,CHAN_TYP,GG_BRANCH_NO,GG_TELLER_NO,TERMINALID,SYSID,CTP_ID,TZ_SEQ,CZ_SEQ,TRAN_FEE,CUST_FEE,ZJ_FEE,CTP_SEQ_NO,HY_FLAG,CLEAR_FLAG,PRO_TYP,CA_CHECK_FLAG,CF_CHECK_FLAG,TRAN_CHECK_FLAG,CANCEL_CHECK,BUC_CHECK_FLAG,ACCT_TP,ORI_CTP_SEQ FROM DTB_ROLL_TR WHERE TRAN_SEQ='1' ;
SELECT * FROM RUN_TASK_CONTROL WHERE CHAN_TYP='1' ;
SELECT * FROM ( SELECT * FROM DTB_UPAY_LIST WHERE UPAY_STATE IN (3,5) AND PASS_TYPE ='1' AND (IS_BATCH IS NULL OR IS_BATCH='N') ORDER BY TO_DATE(SUBMIT_TIME,'YYYY-MM-DD HH24:MI:SS') ASC ) WHERE END_FLAG='Y' and SUBSTR(SUBMIT_TIME,0,10)=TO_CHAR(SYSDATE,'yyyy-MM-dd') OR (FLAG='0' AND UPAY_STATE IN (3,5)) ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT A.CTP_SEQ, A.SEQ_NO, A.CTP_ID, A.STAT, A.ID_TYP, A.ID_NO, A.ID_NAME, A.ACCT_NO, A.REAL_AMT, A.TRAN_DATE, A.TRAN_TIME, A.COMPLE_DATE, A.COMPLE_TIME, A.HOST_CODE, A.HOST_MSG, B.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY A.SEQ_NO,A.CTP_SEQ DESC) AS RN FROM CTP_BATCH_REBATE_TR A LEFT JOIN CTP_USER_INFO B ON A.EBUSER_NO = B.EBUSER_NO WHERE A.STAT = '0' AND A.CTP_ID = '1' AND A.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT A.CTP_SEQ, A.TRANS_CODE, A.CTP_DATE, b.ID_TYP, b.ID_NO, b.CUST_NAME ID_NAME, A.STAT OPER_TYPE, B.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY A.CTP_SEQ DESC) AS RN FROM CTP_COMMON_TR A JOIN CTP_USER_INFO B ON A.EBUSER_NO = B.EBUSER_NO WHERE A.CTP_ID = '1' AND A.STAT = '0' AND A.TRANS_CODE = 'ctpP2pProjectAutoCreditTransf' AND A.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT A.CTP_SEQ, CASE TRAN_TYP when '1' then 'ctpP2pProjectAutoBid' WHEN '0' THEN 'ctpP2pProjectBidReq' END AS TRANS_CODE, NVL(A.CTP_DATE,SUBSTR(submit_time,0,10)) CTP_DATE, A.PRO_ID, B.ID_TYP, B.ID_NO, B.CUST_NAME ID_NAME, TO_CHAR(A.BID_AMT*100) BID_AMT, CASE TRAN_TYP WHEN '1' THEN '3' ELSE TRAN_TYP END AS BID_TYP, B.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY A.CTP_SEQ DESC) AS RN FROM CTP_PP_BID_TR A LEFT JOIN CTP_USER_INFO b ON A.BUY_NO = b.EBUSER_NO WHERE NVL(A.CTP_DATE,SUBSTR(SUBMIT_TIME,0,10)) <= '1' AND SUBSTR(A.COMP_TIME,0,10) = '1' AND A.CTP_ID = '1' AND A.STAT='0' AND A.BID_SEQ_NO IS NOT NULL ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT A.CTP_SEQ, 'ctpP2pProjectPayBack' TRANS_CODE, NVL(A.CTP_DATE,A.TRAN_DATE) CTP_DATE, A.PRO_ID, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, C.CUST_ROLE, A.PAY_ACCT ELE_ACCT_NO, B.CUST_NAME COMPEN_NAME, B.ID_TYP COMPEN_ID_TYP, B.ID_NO COMPEN_ID_NO, B.CUST_ROLE COMPEN_CUST_ROLE, TO_CHAR(A.TRAN_AMT*100) TRAN_AMT, ROW_NUMBER() OVER(ORDER BY A.CTP_SEQ DESC) AS RN FROM CTP_PP_REPAY_TR A LEFT JOIN CTP_USER_INFO B ON B.ebuser_no=A.RCV_NO LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO=A.PAY_NO WHERE A.STAT = '0' AND NVL(A.CTP_DATE,A.TRAN_DATE) <= '1' AND A.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND C.CTP_ID = '1' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT B.CTP_SEQ, 'ctpP2pProjectAddSubmit' TRANS_CODE, B.CRE_DATE CTP_DATE, B.PRO_ID, B.MJ_ID_TYP ID_TYP, B.MJ_ID_NO ID_NO, B.MJ_NAME ID_NAME, TO_CHAR(B.PRO_AMT*100) PRO_AMT, '1' CUST_ROLE, ROW_NUMBER() OVER(ORDER BY B.CTP_SEQ DESC) AS RN FROM CTP_PP_ADD_TR B WHERE B.STAT = '5' AND B.CTP_DATE <= '1' AND CONF_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT B.CTP_SEQ, 'ctpP2pProjectAutoBuyCredit' TRANS_CODE, B.CTP_DATE, B.PRO_ID, B.PRO_TYP, B.ORI_BID_SEQ_NO, B.ZR_ID_TYP, B.ZR_ID_NO, B.ZR_NAME ZR_ID_NAME, B.ZR_ACCT ZR_SUB_ACCT, B.BID_SEQ_NO, B.BUY_ID_TYP, B.BUY_ID_NO, B.BUY_NAME BUY_ID_NAME, B.BUY_ACCT BUY_SUB_ACCT, TO_CHAR(B.BID_AMT*100) BID_AMT, TO_CHAR(B.TRAN_AMT*100) TRAN_AMT, '0' ZR_CUST_ROLE, '0' BUY_CUST_ROLE, ROW_NUMBER() OVER(ORDER BY B.CTP_SEQ DESC) AS RN FROM CTP_PP_ZR_ORDER_TR B WHERE B.CTP_DATE <= '1' AND B.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.STAT = '4' AND B.BID_TYP='4' AND B.CTP_ID = '1' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT B.CTP_SEQ_NO CTP_SEQ, 'ctpTransOut' TRANS_CODE, NVL(CTOI.CTP_DATE,CTOI.CRE_DATE) CTP_DATE, B.OPER_TYPE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, B.ACCT_NO ELE_ACCT_NO, B.CARD_NO ACCT_NO, TO_NUMBER(B.OPER_AMT) OPER_AMT, TO_NUMBER(B.TRAN_FEE) TRAN_FEE, C.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY B.CTP_SEQ_NO DESC) AS RN FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO LEFT JOIN CTP_TRANS_ORDER_INFO CTOI ON B.CTP_ID = CTOI.CTP_ID AND B.CTP_SEQ_NO = CTOI.CTP_SEQ WHERE B.TRAN_STATE = '7' AND B.OPER_TYPE = '1' AND CTOI.CTP_DATE <= '1' AND CTOI.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT CBHT.CTP_SEQ, CBHT.SEQ_NO, CPCT.BID_SEQ_NO BID_SEQ, CUI.ID_TYP, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CBHT.JD_FLAG, CBHT.TRAN_AMT, CBHT.STAT, CBHT.HOST_MSG, CUI.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY CPCT.TRANS_SEQ DESC) AS RN FROM CTP_BATCH_HOST_TR CBHT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBHT.DETAIL_SEQ = CPCT.CONF_SEQ LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO WHERE CBHT.STAT = '0' AND CBHT.CTP_ID = '1' AND CBHT.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT CBRT.CTP_SEQ, CBRT.SEQ_NO, CPCT.BID_SEQ_NO BID_SEQ, CUI.ID_TYP, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CBRT.JD_FLAG, CBRT.DC_FLAG, CBRT.BACK_FLAG, CBRT.TRAN_AMT, CBRT.REAL_AMT, CBRT.STAT, CBRT.HOST_MSG, CUI.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY CPCT.TRANS_SEQ DESC) AS RN FROM CTP_BATCH_REPAY_TR CBRT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBRT.DETAIL_SEQ = CPCT.DF_SEQ LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO WHERE CBRT.STAT = '0' AND CBRT.CTP_ID = '1' AND CBRT.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT D.CTP_SEQ, 'ctpP2pFinancialPlanSignReq' TRANS_CODE, D.TRAN_DATE CTP_DATE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, D.PACKAGE_ID, D.PACKAGE_NAME, D.AMT, D.TRAN_AMT, D.SIGN_TYPE OPER_TYPE, C.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY D.TRANS_SEQ DESC) AS RN FROM CTP_FINAN_PLAN_TR D LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO = D.EBUSER_NO WHERE D.CTP_ID = '1' AND D.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND D.STAT = '0' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT D.CTP_TRANS_SEQ CTP_SEQ, 'ctpUserAccountTransfer' TRANS_CODE, D.TRAN_DATE CTP_DATE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, D.TRAN_AMT, D.CUST_FEE, D.SUB_ACCOUNT, C.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY D.CTP_TRANS_SEQ DESC) AS RN FROM CTP_SUB_TRANSFER_TR D JOIN CTP_USER_INFO C ON D.EBUSER_NO=C.EBUSER_NO AND D.CTP_ID = C.CTP_ID WHERE D.TRAN_STAT = '0' AND D.TRAN_FLAG='0' AND D.CTP_DATE <= '1' AND D.COMP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND D.CTP_ID = '1' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT NVL(B.ORI_CTP_SEQ,B.CTP_SEQ_NO) CTP_SEQ, 'ctpTransIn' TRANS_CODE, NVL(CTOI.CTP_DATE,CTOI.CRE_DATE) CTP_DATE, B.OPER_TYPE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, B.ACCT_NO ELE_ACCT_NO, B.CARD_NO ACCT_NO, TO_CHAR(B.OPER_AMT*100) OPER_AMT, TO_CHAR(B.TRAN_FEE*100) TRAN_FEE, C.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY B.CTP_SEQ_NO DESC) AS RN FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO LEFT JOIN CTP_TRANS_ORDER_INFO CTOI ON B.CTP_ID = CTOI.CTP_ID AND B.CTP_SEQ_NO = CTOI.CTP_SEQ WHERE B.TRAN_STATE = '6' AND B.OPER_TYPE = '0' AND CTOI.CTP_DATE <= '1' AND CTOI.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT * FROM (SELECT ROW_.* FROM ( SELECT TBWT.CTP_SEQ, TBWT.PASS_TYPE, TBT.TPP_SEQ, TBWT.SEQ_NO, TBWT.PRO_ID, TBWT.ID_TYP, TBWT.ID_NO, TBWT.ID_NAME, TBWT.JD_FLAG, TBWT.TRAN_AMT*100 TRAN_AMT, TBWT.FEE*100 FEE, CASE WHEN TBWT.STAT = '2' THEN '3' WHEN TBWT.STAT IN ('0','1','5') THEN '1' WHEN TBWT.STAT = '4' THEN '4' WHEN TBWT.STAT = '3' THEN '0' ELSE '' END STAT, TBWT.HOST_MSG, TBWT.TRAN_DATE, TBWT.TRAN_TIME, TBWT.COMPLE_DATE, TBWT.COMPLE_TIME, C.CUST_ROLE, ROW_NUMBER() OVER(ORDER BY TBWT.TRAN_SEQ DESC) AS RN FROM TPP_BATCH_TR TBT LEFT JOIN TPP_BATCH_WITHHOLD_TR TBWT ON TBT.BATCH_NO = TBWT.BATCH_NO LEFT JOIN CTP_USER_INFO C ON C.EBUSER_NO=TBWT.EBUSER_NO WHERE TBWT.OPER_TYPE = '0' AND TBWT.STAT = '3' AND TBWT.CTP_ID ='1' AND TBWT.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1') WHERE RN > '1' ;
SELECT HOST_BATCH_NO AS BATCH_NO FROM CTP_BATCH_TR WHERE STAT = '1' AND ((SYSDATE-TO_DATE((CONCAT(TRAN_DATE,TRAN_TIME)),'yyyy-mm-dd hh24:mi:ss'))*24*60)>5 AND BATCH_QUERY_RATE<3 AND ROWNUM <= 20 AND HOST_BATCH_NO IS NOT NULL AND TRAN_FLAG = '0' ;
SELECT HOST_DATE FROM CTP_SYSTEM_CONTROL;
SELECT INTE_SEQ,TRANS_AMT FROM PAYMENT_CHECK_TR WHERE RCV_ACCT = '1' AND NVL(DF_IS_SYNZ,'0') = '0' ;
SELECT IS_CHECK FROM CTP_PASS_TYPE_TR WHERE PASS_TYPE='innerTrans' AND UPDATE_DATE=TO_CHAR(SYSDATE,'yyyy-MM-dd') AND TRAN_TYP = '1' ;
SELECT NVL(DRT.ORI_CTP_SEQ,DRT.CTP_SEQ_NO) CTP_SEQ, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CUI.ID_TYP, CUI.MOBILE, DRT.OPER_AMT, DRT.ACCT_NO ELE_ACCT_NO, DRT.CARD_NO ACCT_NO, DRT.BANK_NAME, DRT.TRAN_STATE, DRT.TRAN_FEE FEE_AMT, DRT.TRAN_FEE-DRT.CUST_FEE ACTIVITY_FEE, DRT.TRAN_DATE, DRT.TRAN_TIME, TO_CHAR(TO_DATE(DRT.HOST_TIME,'YYYY-MM-DD HH24:MI:SS'),'YYYY-MM-DD') WC_DATE, TO_CHAR(TO_DATE(DRT.HOST_TIME,'YYYY-MM-DD HH24:MI:SS'),'HH24:MI:SS') WC_TIME FROM DTB_ROLL_TR DRT LEFT JOIN CTP_USER_INFO CUI ON DRT.EBUSER_NO = CUI.EBUSER_NO WHERE DRT.TRAN_STATE='6' AND DRT.CTP_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND DRT.CTP_ID='1' AND DRT.OPER_TYPE='0' ;
SELECT NVL(SUM(TRAN_AMT * 100),0) TOT_AMT FROM ACP_TRANS_TR WHERE CTP_ID = '1' AND TRAN_STAT = '0' AND TRANS_FLAG ='0' AND TRAN_DATE < TO_CHAR(SYSDATE,'yyyy-MM-dd') ;
SELECT PCT.INTE_SEQ, PCT.TRANS_SEQ, PCT.TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME, PCT.ACCT_NO, CA.CTP_ID, PCT.PS, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, CASE WHEN PCT.OPER_FLAG='2' THEN 'C1' ELSE 'A1' END LIST_KIND, PCT.LZ_CTP_SEQ LIST_ID, CI.SYNZ_URL FROM PAYMENT_CHECK_TR PCT, CTP_ACCT CA, CTP_INFO CI WHERE CA.CTP_ACCT = PCT.RCV_ACCT AND NVL(PCT.IS_DZ_SYNZ,'N') = 'N' AND NVL(PCT.DZ_SYNZ_RATE,0) < 3 AND CA.CTP_ID = CI.CTP_ID AND CI.IS_PS_NOTICE = 'Y' AND PCT.SUM_INFO!='0005' AND CI.CTP_ID!='80010008' AND ROWNUM <= 10 ;
SELECT PCT.INTE_SEQ, PCT.TRANS_SEQ, PCT.TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME, PCT.ACCT_NO, DA.CTP_ID, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, CASE WHEN PCT.OPER_FLAG='2' THEN 'C1' ELSE 'A1' END LIST_KIND, PCT.LZ_CTP_SEQ LIST_ID, CI.SYNZ_URL FROM PAYMENT_CHECK_TR PCT, DTB_ACCT DA, CTP_INFO CI WHERE DA.ACCT_NO = PCT.RCV_ACCT AND DA.ACCT_TP = '0' AND NVL(PCT.IS_DZ_SYNZ,'N') = 'N' AND NVL(PCT.DZ_SYNZ_RATE,0) < 3 AND DA.CTP_ID = CI.CTP_ID AND CI.IS_ACCT_NOTICE = 'Y' AND PCT.SUM_INFO!='0005' AND CI.CTP_ID = '1' AND ROWNUM <= 10 ;
SELECT PCT.INTE_SEQ, PCT.TRANS_SEQ, PCT.TRANS_AMT, PCT.RCV_ACCT, PCT.RCV_NAME, PCT.ACCT_NO, DA.CTP_ID, PCT.PS, CASE WHEN PCT.CHAN_TYPE='3' THEN '1' WHEN PCT.CHAN_TYPE='4' THEN '0' ELSE '2' END TRAN_TYPE, CASE WHEN PCT.OPER_FLAG='2' THEN 'C1' ELSE 'A1' END LIST_KIND, PCT.LZ_CTP_SEQ LIST_ID, CI.SYNZ_URL FROM PAYMENT_CHECK_TR PCT, DTB_ACCT DA, CTP_INFO CI WHERE DA.ACCT_NO = PCT.RCV_ACCT AND DA.ACCT_TP = '0' AND NVL(PCT.IS_DZ_SYNZ,'N') = 'N' AND NVL(PCT.DZ_SYNZ_RATE,0) < 3 AND DA.CTP_ID = CI.CTP_ID AND CI.IS_PS_NOTICE = 'Y' AND PCT.SUM_INFO!='0005' AND ROWNUM <= 10 ;
SELECT P.TRANS_SEQ , P.RCV_ACCT, P.ACCT_NO, TRIM(TO_CHAR(TO_NUMBER(P.TRANS_AMT) / 100, '99999999999990.00')) TRAN_AMT, TO_CHAR(TO_DATE(P.TRANS_DATE,'YYYY-MM-DD'),'YYYY-MM-DD') LOAD_DATE, P.LOAD_TIME FROM PAYMENT_CHECK_TR P LEFT JOIN DTB_ACCT C ON P.RCV_ACCT = C.ACCT_NO AND C.ACCT_TP='0' WHERE TO_CHAR(TO_DATE(P.TRANS_DATE,'YYYY-MM-DD'),'YYYY-MM-DD') = '1' AND C.CTP_ID = '1' and p.sum_info!='0005' ;
SELECT ROW_.RN,ROW_.TRANS_SEQ,ROW_.BUSI_TYP,ROW_.SERVICE_TYPE,ROW_.HOST_SEQ,ROW_.TRAN_AMT,ROW_.TRAN_STAT,ROW_.SEQ_NO,ROW_.JF_ACCT_NO,ROW_.DF_ACCT_NO FROM( SELECT ROW_NUMBER() OVER(ORDER BY UPDATE_TIME DESC) AS RN , A.TRANS_SEQ, A.BUSI_TYP, A.SERVICE_TYPE, A.HOST_SEQ, A.HOST_DATE, A.TRAN_AMT, A.TRAN_STAT, A.UPDATE_TIME, A.SEQ_NO, A.JF_ACCT_NO, A.DF_ACCT_NO FROM CTP_CHECK_FILE_TR A WHERE A.IS_CENTER = '1' AND NVL(A.IS_CHECK,'0') = '0' AND A.UPDATE_TIME = TO_CHAR(SYSDATE,'yyyy-MM-dd') AND A.TRAN_TYP = '1' ) ROW_ WHERE ROW_.RN<=500 ;
SELECT SUM(NVL(DB_AMT,PRO_AMT)) DB_AMT,COUNT(1) JK_NUMBER,COUNT(TOT_NUM) CJ_NUMBER FROM CTP_PP_INFO WHERE STAT IN ('6','9','10','11') AND CTP_ID = '1' AND SUBSTR(CTP_S_TIME,0,10) like '1' ;
SELECT SUM(REAL_AMT) REPAY_AMT FROM CTP_BATCH_REPAY_TR WHERE FEE_FLAG !='3' AND STAT='0' AND JD_FLAG='4' AND CTP_ID = '1' AND COMPLE_DATE like '1' ;
SELECT TRAN_SEQ FROM DTB_RECHARGE_TR WHERE RECHARGE_SEQ='1' ;
UPDATE CTP_PP_BID_TR SET STAT='2' WHERE TRANS_SEQ IN ( SELECT TRAN_SEQ FROM CTP_TRANS_TR WHERE NVL(HOST_CHECK,'0')='0' AND TRANS_CODE IN ('ctpP2pProjectBidSubmit','ctpP2pProjectAutoBid') AND TRAN_DATE != TO_CHAR(SYSDATE,'yyyy-MM-dd')) AND STAT ='1' ;
UPDATE CTP_PP_ORDER_TR SET STAT='5' WHERE TRAN_SEQ IN ( SELECT A.TRAN_SEQ FROM CTP_PP_ORDER_TR A LEFT JOIN CTP_PP_BID_TR B ON A.CTP_SEQ = B.CTP_SEQ AND A.CTP_ID=B.CTP_ID WHERE B.TRANS_SEQ IN ( SELECT TRAN_SEQ FROM CTP_TRANS_TR WHERE TRANS_CODE ='ctpP2pProjectBidSubmit' AND TRAN_STAT='3' ) AND NVL(B.CTP_SEQ,'0')<> '0' ) AND STAT!='5' ;
SELECT a.ACCT_NO,OPEN_ORG,a.ACCT_NAME,a.BIND_TYPE,a.IS_DK, PRE_NO,ACCT_TP ACCT_TYP, IS_ACTIVE, REG_AMT,IS_RANDOM,a.DK_PRO_ID,b.pb_protocol,DK_PRO_STATE FROM DTB_ACCT a left join SIGN_PROTOCL_INFO b on a.dk_pro_id=b.pro_id WHERE a.EBUSER_NO = '1' AND a.ACCT_NO ='1' ;
SELECT A.*,B.ACCT_NO FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP= '0' WHERE A.CTP_ID='1' AND A.ID_TYP='1' AND A.ID_NO='1' AND A.CUST_NAME='1' AND A.CUST_ROLE='1' AND A.IS_CANCEL='0' ;
SELECT A.BANK_CODE,B.BANK_NAME,length(STRING1),A.CARD_TYPE FROM CARDPARAM_CLS_INFO A LEFT JOIN BANK_COFG_CODE B ON A.BANK_CODE=B.BANK_CODE WHERE STRING1 in ( '1' , '1' , '1' , '1' , '1' , '1' , '1' , '1' , '1' ) AND A.CARD_LEN = '1' ORDER BY length(STRING1) DESC ;
SELECT A.*,B.CTP_NAME,B.OPEN_ORG AS ORG FROM CTP_OPERATOR A LEFT JOIN CTP_INFO B ON A.CTP_ID=B.CTP_ID WHERE (LGN_ID='1' OR OPER_MOBILE='1') AND A.CTP_ID='1' ;
SELECT A.*,B.CTP_NAME,C.PASS_NAME,ROWNUM AS RN FROM PASS_CTP_CONFIG A LEFT JOIN CTP_INFO B ON A.CTP_ID=B.CTP_ID LEFT JOIN PASS_INF C ON A.PASS_TYPE=C.PASS_TYPE WHERE A.CTP_ID IS NOT NULL AND A.CTP_ID = '1' AND A.EBUSER_TYP = '1' ;
SELECT A.*,B.* FROM CTP_PP_CONFIRM_TR A LEFT JOIN CTP_PP_ZR_ORDER_TR B ON A.BID_SEQ_NO=B.ORI_BID_SEQ_NO AND A.PRO_ID = B.PRO_ID WHERE A.CTP_ID = '1' AND A.BID_SEQ_NO = '1' AND A.PRO_ID = '1' AND A.BID_STAT='1' AND A.LOCK_FLAG='1' AND B.BID_AMT<=A.BID_AMT AND B.TRANS_SEQ='1' ;
SELECT A.BID_SEQ_NO, B.ID_TYP, B.ID_NO, B.CUST_NAME,B.CUST_ROLE, A.BIDER_ACCT, A.PRO_ID, A.BID_AMT, A.BID_TYP, A.BID_STAT from CTP_PP_CONFIRM_TR A,CTP_USER_INFO B where A.BIDER_NO = B.EBUSER_NO AND PRO_ID = '1' AND A.CTP_ID = '1' AND A.BID_STAT in (0,1,2,3,4,5) ORDER BY BID_DATE ,BID_TIME ;
SELECT A.*,B.LNAME AS BANK_NAME,C.PASS_NAME,ROWNUM AS RN FROM PASS_DETAIL_CONF A LEFT JOIN PT_BANK_CODE B ON A.BANK_CODE=B.BANK_CODE LEFT JOIN PASS_INF C ON A.PASS_TYPE=C.PASS_TYPE WHERE A.BANK_CODE IS NOT NULL AND B.MSG_TYPE='CNAPS' AND B.LNAME LIKE '%'||'1'||'%' ;
SELECT A.*,B.LNAME AS BANK_NAME,C.PASS_NAME,ROWNUM AS RN FROM PASS_DETAIL_CONF A LEFT JOIN PT_BANK_CODE B ON A.BANK_CODE=B.BANK_CODE LEFT JOIN PASS_INF C ON A.PASS_TYPE=C.PASS_TYPE WHERE A.BANK_CODE IS NOT NULL AND B.MSG_TYPE='CNAPS' AND B.LNAME LIKE '%'||'1'||'%' AND BUSI_TYPE = '1' ;
SELECT A.*,B.LNAME AS BANK_NAME,C.PASS_NAME,ROWNUM AS RN FROM PASS_DETAIL_CONF A LEFT JOIN PT_BANK_CODE B ON A.BANK_CODE=B.BANK_CODE LEFT JOIN PASS_INF C ON A.PASS_TYPE=C.PASS_TYPE WHERE A.BANK_CODE IS NOT NULL AND B.MSG_TYPE='CNAPS' AND B.LNAME LIKE '%'||'1'||'%' AND EBUSER_TYP = '1' ;
SELECT A.*,B.LNAME AS BANK_NAME,C.PASS_NAME,ROWNUM AS RN FROM PASS_DETAIL_CONF A LEFT JOIN PT_BANK_CODE B ON A.BANK_CODE=B.BANK_CODE LEFT JOIN PASS_INF C ON A.PASS_TYPE=C.PASS_TYPE WHERE A.BANK_CODE IS NOT NULL AND B.MSG_TYPE='CNAPS' AND BUSI_TYPE = '1' ;
SELECT A.*,B.LNAME AS BANK_NAME,C.PASS_NAME,ROWNUM AS RN FROM PASS_DETAIL_CONF A LEFT JOIN PT_BANK_CODE B ON A.BANK_CODE=B.BANK_CODE LEFT JOIN PASS_INF C ON A.PASS_TYPE=C.PASS_TYPE WHERE A.BANK_CODE IS NOT NULL AND B.MSG_TYPE='CNAPS' AND EBUSER_TYP = '1' ;
SELECT ACCT_NO, EBUSER_NO,ACCT_NAME FROM CTP_SUB_ACCT WHERE SUB_ACCT_NO ='1' AND CTP_ID='1' ;
SELECT ACCT_NO, EBUSER_NO,ACCT_NAME FROM DTB_ACCT_EXTEND WHERE CTP_ID='1' AND (SUB_ACCT_NO ='1' OR SUB_ACCT_NO_SECOND ='1') ;
SELECT ACCT_NO, EBUSER_NO,ACCT_NAME FROM DTB_ACCT WHERE ACCT_NO ='1' AND CTP_ID='1' ;
SELECT ACCT_NO ELE_ACCT_NO, ACCT_NAME ELE_ACCT_NAME FROM DTB_ACCT WHERE ACCT_TP = '0' AND EBUSER_NO = ( SELECT EBUSER_NO FROM CTP_USER_INFO WHERE ID_NO = '1' AND ID_TYP = '1' AND CUST_NAME = '1' AND CTP_ID = '1' AND CUST_ROLE = '1' AND IS_CANCEL = '0' ) ;
SELECT ACCT_NO FROM DTB_ACCT WHERE ACCT_NO = '1' AND ACCT_TP IN ('1','2') AND CTP_ID = '1' AND CUST_ROLE = '1' AND IS_CANCEL = '0' ;
SELECT A.CHAN_TYP,A.TRAN_CODE,A.OPEN_WAY,A.EBUSER_TYP,A.INCORP_NO,A.OPER_TYPE FROM CHAN_INTE_AUTH_CTL A ;
SELECT A.CHAN_TYP,A.TRAN_CODE,A.TRAN_VALUE_NAME,A.FREQ_TYPE,A.PER_TIME,A.PER_COUNT,A.FRE_TIME,A.EXT1,A.EXT2 FROM CHAN_SERVICE_FREQ_CL A ;
SELECT A.CTP_ACCT,A.CTP_ACCT_NAME, B.REBATE_ACCT_NO,B.REBATE_ACCT_NAME,B.REBATE_TYPE, CASE WHEN B.REBATE_TYPE = '0' THEN '批量转账' WHEN B.REBATE_TYPE = '1' THEN '批量奖励' ELSE '' END AS REBATE_TYPE_NAME FROM CTP_ACCT A LEFT JOIN CTP_REBATE_SIGN_INFO B ON A.CTP_ID = B.CTP_ID AND A.CTP_ACCT = B.CTP_ACCT WHERE A.CTP_ID = '1' AND A.ACCT_STATE = 'N' AND A.ACCT_RIGHT = 'Z' AND B.STAT='2' ;
SELECT A.CTP_ID, A.ORDER_NO, A.SYNZ_URL, A.OPER_TYPE, D.TRAN_STATE, B.CODE_NAME, A.CTP_SEQ TRANS_SEQ, A.CTP_SEQ, D.HOST_MSG TRAN_STATE_DESC FROM CTP_TRANS_ORDER_INFO A LEFT JOIN PARM_CODE B ON A.STATE = B.CODE_NO AND B.CODE_TYPE = 'CTP_STAT_OUT' LEFT JOIN DTB_ROLL_TR D ON D.CTP_SEQ_NO = A.CTP_SEQ WHERE A.CTP_ID = '1' AND A.ORDER_NO = '1' AND A.SYNZ_URL IS NOT NULL AND D.TRAN_STATE='7' ;
SELECT A.CTP_NAME, A.CTP_LOGO_B, A.CTP_LOGO_S, A.OPEN_ORG ORG_NO, A.OPEN_ORG||'811' TELLER_NO, A.STAT CTP_STAT, A.CIF_NO CTP_CIF_NO, A.ID_TYPE CTP_ID_TYP, A.ID_NO CTP_ID_NO, B.FLAG FROM CTP_INFO A LEFT JOIN CTP_CONFIG_TR B ON A.CTP_ID = B.CTP_ID WHERE A.CTP_ID = '1' ;
SELECT A.CTP_SEQ, CASE TRAN_TYP when '1' then 'ctpP2pProjectAutoBid' WHEN '0' THEN 'ctpP2pProjectBidReq' END AS TRANS_CODE, NVL(A.CTP_DATE,SUBSTR(submit_time,0,10)) CTP_DATE, A.PRO_ID, B.ID_TYP, B.ID_NO, B.CUST_NAME ID_NAME, TO_CHAR(A.BID_AMT*100) BID_AMT, CASE TRAN_TYP WHEN '1' THEN '3' ELSE TRAN_TYP END AS BID_TYP, B.CUST_ROLE FROM CTP_PP_BID_TR A LEFT JOIN CTP_USER_INFO b ON A.BUY_NO = b.EBUSER_NO WHERE A.CTP_DATE <= '1' AND SUBSTR(A.COMP_TIME,0,10) = '1' AND A.CTP_ID = '1' AND A.STAT='0' AND A.BID_SEQ_NO IS NOT NULL ;
SELECT A.EACCT_NO ELE_ACCT_NO, B.IS_ACTIVE, A.SYNZ_URL, A.CTP_ID, A.UNI_NO, A.UNI_STAT, A.COMP_NAME ID_NAME, A.ID_TYP, A.ID_NO, A.CUST_ROLE, B.BANK_NO, B.BANK_NAME, B.IS_SIGN_MOBILE, C.ACCT_NO_ENCRYPT ACCT_NO, A.CTP_TRAN_SEQ TRANS_SEQ, B.EBUSER_NO, A.MOBILE MOBILE_NO, TO_CHAR(C.REG_AMT * 100) REG_AMT FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN DTB_ACCT C ON B.EBUSER_NO = C.EBUSER_NO AND C.ACCT_TP <> '0' WHERE A.CTP_ID= '1' AND A.UNI_NO= '1' ;
SELECT A.CTP_ID, A.EBUSER_NO FROM CTP_PP_AUTO_BID_INFO A LEFT JOIN CTP_BATCH_AUTOBID_TR B ON A.EBUSER_NO = B.BID_NO WHERE B.CTP_ID = '1' AND B.SEQ_NO = '1' AND B.CTP_SEQ = '1' ORDER BY SIGN_DATE DESC ;
SELECT A.IS_ACTIVE FROM DTB_ACCT A LEFT JOIN CTP_USER_INFO B ON A.EBUSER_NO=B.EBUSER_NO WHERE A.ACCT_TP<>0 AND B.ID_NO='1' AND B.ID_TYP='1' AND B.CUST_NAME='1' AND B.CUST_ROLE='1' AND A.IS_CANCEL='0' AND B.CTP_ID='1' ;
SELECT A.LOCAL_LAN,A.EXCEPTION_CODE,A.EXCEPTION_MSG FROM CHAN_EXCEPTION_MSG_PRARM A ;
SELECT A.PROT_TEMP_NAME FROM PROT_TEMP A WHERE PROT_TEMP_ID='1' ;
SELECT A.SEQ_NO, A.BID_SEQ, A.ID_TYP, A.ID_NO, A.ID_NAME, A.TRAN_AMT*100 BID_AMT, A.TRAN_AMT*100 TRAN_AMT, A.STAT, A.HOST_MSG, B.CUST_ROLE FROM CTP_BATCH_AUTOBID_TR A LEFT JOIN CTP_USER_INFO B ON A.BID_NO = B.EBUSER_NO WHERE A.CTP_ID = '1' AND A.CTP_SEQ = '1' ;
SELECT A.SEQ_NO, A.CTP_ID, A.CTP_SEQ, A.STAT, A.ID_TYP, A.ID_NO, A.ID_NAME, A.ACCT_NO, A.REAL_AMT, A.HOST_CODE, A.HOST_MSG, B.CUST_ROLE FROM CTP_BATCH_REBATE_TR A LEFT JOIN CTP_USER_INFO B ON A.EBUSER_NO = B.EBUSER_NO WHERE A.CTP_ID = '1' AND A.CTP_SEQ = '1' ;
SELECT A.STAT TRAN_STAT FROM PER_CUST_ACCOUNT_APPLY A WHERE A.CTP_ID='1' AND A.TRAN_SEQ = '1' ;
SELECT A.SYNZ_URL, A.CTP_ID, A.CTP_SEQ TRANS_SEQ, A.TRANS_SEQ TRAN_SEQ, A.ID_TYP, A.ID_NO, A.ID_NAME, CUI.MOBILE, A.ELE_ACCT_NO, C.ACCT_NO, C.IS_ACTIVE, TO_CHAR(C.REG_AMT *100) REG_AMT, A.CUST_ROLE, C.BANK_NAME BIND_BANK_NAME, C.BANK_NO BIND_BANK_NO, C.IS_SIGN_MOBILE, B.BANK_NAME, B.BANK_NO FROM CTP_BATCH_ACTIVE_TR A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO =B.EBUSER_NO AND A.ELE_ACCT_NO = B.ACCT_NO LEFT JOIN DTB_ACCT C ON A.EBUSER_NO = C.EBUSER_NO AND C.ACCT_TP <>'0' LEFT JOIN CTP_USER_INFO CUI ON A.EBUSER_NO = CUI.EBUSER_NO WHERE A.TRANS_SEQ='1' AND A.CTP_ID='1' ;
SELECT A.SYNZ_URL, A.ID_TYP, A.ID_NO, D.ACCT_NO_ENCRYPT ACCT_NO, D.CUST_ROLE, A.CUST_NAME ID_NAME, A.EACCT_NO ELE_ACCT_NO, B.BANK_NO, B.BANK_NAME, B.IS_SIGN_MOBILE, D.REG_AMT*100 REG_AMT, B.IS_ACTIVE, B.IS_SIGN_MOBILE, A.TRAN_SEQ, A.CTP_ID, A.CTP_SEQ_NO TRANS_SEQ, D.IS_ACTIVE ACCT_ACTIVE, A.MOBILE MOBILE_NO FROM CTP_REGISTER_TR A LEFT JOIN DTB_ACCT D ON A.EBUSER_NO = D.EBUSER_NO AND D.ACCT_TP <> '0', DTB_ACCT B, CTP_USER_INFO C WHERE A.EACCT_NO = B.ACCT_NO AND A.EBUSER_NO = C.EBUSER_NO AND A.CTP_ID='1' AND A.CTP_SEQ_NO='1' ;
SELECT A.USER_STAT,A.EBUSER_NO,A.EBUSER_TYP,A.MOBILE, A.CIF_NO,A.IS_DATA_TRANS, B.ACCT_NO,B.ACCT_NAME,B.BANK_NO,B.DK_PRO_ID, B.ACCT_TP, B.BANK_NAME, B.PRE_NO, A.CTP_ID, C.ACCT_NO ELE_ACCT_NO,C.IS_SIGN_MOBILE,C.IS_ACTIVE FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP <> '0' LEFT JOIN DTB_ACCT C ON A.EBUSER_NO=C.EBUSER_NO AND C.ACCT_TP = '0' WHERE A.ID_TYP = '1' AND A.ID_NO = '1' AND A.CUST_NAME = '1' AND A.CTP_ID = '1' AND A.CUST_ROLE = '1' AND A.IS_CANCEL ='0' ;
SELECT BANK_CODE,BANK_NAME FROM BANK_COFG_CODE ORDER BY BANK_CODE ;
SELECT BANK_CODE,BANK_NAME FROM BANK_EXT_INF WHERE CTP_ID = '1' ;
SELECT BANK_NO BANK_CODE,BANK_NAME,IS_ACTIVE FROM DTB_ACCT WHERE ACCT_NO = '1' AND CTP_ID = '1' AND EBUSER_NO = '1' ;
SELECT BANK_NO FROM CTP_ACCT WHERE CTP_ID='1' AND CTP_ACCT='1' ;
SELECT BANK_NO,IS_ACTIVE FROM DTB_ACCT WHERE ACCT_NO = '1' AND ACCT_TP <> '0' AND CTP_ID = '1' AND EBUSER_NO = '1' ;
SELECT BARGAIN_TOP,BARGAIN_BOTTOM,ZR_VALID FROM CTP_P2P_TYP_CONF WHERE CTP_ID = '1' AND PRO_TYP = '1' ;
SELECT B.CTP_SEQ, 'ctpP2pProjectAddSubmit' TRANS_CODE, B.CRE_DATE CTP_DATE, B.PRO_ID, B.MJ_ID_TYP ID_TYP, B.MJ_ID_NO ID_NO, B.MJ_NAME ID_NAME, TO_CHAR(B.PRO_AMT*100) PRO_AMT, '1' CUST_ROLE FROM CTP_PP_ADD_TR B WHERE B.STAT = '5' AND B.CTP_DATE <= '1' AND CONF_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT B.CTP_SEQ_NO CTP_SEQ, 'ctpTransOut' TRANS_CODE, NVL(CTOI.CTP_DATE,CTOI.CRE_DATE) CTP_DATE, B.OPER_TYPE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, B.ACCT_NO ELE_ACCT_NO, B.CARD_NO ACCT_NO, TO_NUMBER(B.OPER_AMT) OPER_AMT, TO_NUMBER(B.TRAN_FEE) TRAN_FEE, C.CUST_ROLE FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO LEFT JOIN CTP_TRANS_ORDER_INFO CTOI ON B.CTP_ID = CTOI.CTP_ID AND B.CTP_SEQ_NO = CTOI.CTP_SEQ WHERE B.TRAN_STATE = '7' AND B.OPER_TYPE = '1' AND CTOI.CTP_DATE <= '1' AND CTOI.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT b.* FROM CTP_USER_MENU a left join ctp_sys_menu b on a.menu_id = b.menu_id WHERE a.CTP_ID='1' and a.OPER_ID='1' ORDER BY a.MENU_ID ;
SELECT BI.BANK_NAME,BI.CERTIFY_PASS_TYPE,BI.IS_CHECK_MOBILE,BI.IS_CHECK_PWD FROM BANK_EXT_INF BI WHERE BANK_CODE='1' AND CTP_ID='1' ;
SELECT BID_AMT,BIDER_NO,IS_ZR_STAT FROM CTP_PP_CONFIRM_TR WHERE CTP_ID = '1' AND BID_SEQ_NO = '1' AND PRO_ID = '1' AND BID_STAT='1' AND LOCK_FLAG='1' ;
SELECT BID_SEQ FROM CTP_BATCH_AUTOBID_TR WHERE CTP_ID = '1' AND PRO_ID = '1' AND CTP_SEQ = '1' AND SEQ_NO = '1' ;
SELECT CBHT.SEQ_NO, CPCT.BID_SEQ_NO BID_SEQ, CUI.ID_TYP, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CBHT.JD_FLAG, CBHT.TRAN_AMT, CBHT.STAT, CBHT.HOST_MSG, CUI.CUST_ROLE FROM CTP_BATCH_HOST_TR CBHT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBHT.DETAIL_SEQ = CPCT.CONF_SEQ LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO WHERE CBHT.CTP_ID = '1' AND CBHT.CTP_SEQ = '1' AND CBHT.TRAN_TYPE = '1' ;
SELECT CBRT.SEQ_NO, CPCT.BID_SEQ_NO BID_SEQ, CUI.ID_TYP, CUI.ID_NO, CUI.CUST_NAME ID_NAME, CBRT.JD_FLAG, CBRT.DC_FLAG, CBRT.BACK_FLAG, CBRT.TRAN_AMT, CBRT.REAL_AMT, CBRT.STAT, CBRT.HOST_MSG, CUI.CUST_ROLE FROM CTP_BATCH_REPAY_TR CBRT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CBRT.DETAIL_SEQ = CPCT.DF_SEQ LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPCT.BIDER_NO WHERE CBRT.CTP_ID = '1' AND CBRT.CTP_SEQ = '1' ;
SELECT CBT.PRO_ID,CBT.CTP_ID, CBT.TRAN_TYPE, CBT.CTP_SEQ,CBT.TRAN_SEQ,CBT.FIRST_FLAG FROM CTP_BATCH_TR CBT WHERE HOST_BATCH_NO = '1' AND STAT= '1' ;
SELECT C.CONF_TYPE,C.TRANS_CODE,C.TRANS_CONF FROM CHAN_TRANS_PUB_CONF C ;
SELECT CFPT.SYNZ_URL, CFPT.TRANS_SEQ TRAN_SEQ, CFPT.CTP_SEQ TRANS_SEQ, CSA.CTP_id, CSA.ACCT_NAME, CSA.ACCT_NO, CFPT.SUB_ACCT_NO,CFPT.SIGN_TYPE,CFPT.STAT,CFPT.PACKAGE_ID,CFPT.PACKAGE_NAME,CFPI.AMT FROM CTP_FINAN_PLAN_TR CFPT LEFT JOIN CTP_SUB_ACCT CSA ON CFPT.EBUSER_NO = CSA.EBUSER_NO AND CFPT.CTP_ID = CSA.CTP_ID AND CFPT.SUB_ACCT_NO = CSA.SUB_ACCT_NO LEFT JOIN CTP_FINAN_PLAN_INFO CFPI ON CFPT.CTP_ID = CFPI.CTP_ID AND CFPT.EBUSER_NO = CFPI.EBUSER_NO AND CFPT.PACKAGE_ID =CFPI.PACKAGE_ID WHERE CFPT.TRANS_SEQ='1' AND CFPT.CTP_ID='1' AND CFPT.STAT='0' ;
SELECT CHAN_TYP,EBUSER_NO CUST_NO FROM USER_LOG_CONF ;
SELECT CHAN_TYP,TRANS_CODE,TRANS_TYPE,TRAN_WAY FROM E_LMT_PARM_CT ;
SELECT CHARGE_TYPE,FEE_VALUE FROM PASS_FEE_CONF WHERE PASS_TYPE='1' AND OPER_TYPE = '1' AND '1'<=UPPER_LIMIT AND '1'>LOWER_LIMIT ;
SELECT CI.EBUSER_TYP ,DA.ACCT_NO ELE_ACCT_NO,DA.IS_ACTIVE,DA.IS_SIGN_MOBILE,CI.ID_NO,CI.CUST_NAME,CI.CUST_ROLE FROM CTP_USER_INFO CI LEFT JOIN DTB_ACCT DA ON DA.ACCT_TP='0' AND DA.EBUSER_NO=CI.EBUSER_NO AND DA.CTP_ID=CI.CTP_ID WHERE CI.EBUSER_NO='1' AND CI.CTP_ID='1' ;
SELECT CI.EBUSER_TYP ,DA.ACCT_NO ELE_ACCT_NO,DA.IS_ACTIVE,DA.IS_SIGN_MOBILE,CI.ID_NO,CI.CUST_NAME,DA.CUST_ROLE FROM CTP_USER_INFO CI LEFT JOIN DTB_ACCT DA ON DA.ACCT_TP='0' AND DA.EBUSER_NO=CI.EBUSER_NO AND DA.CTP_ID=CI.CTP_ID WHERE CI.EBUSER_NO='1' AND CI.CTP_ID='1' ;
SELECT CI.EBUSER_TYP ,DA.ACCT_NO ELE_ACCT_NO,DA.IS_ACTIVE,DA.IS_SIGN_MOBILE,CI.ID_NO,CI.CUST_NAME FROM CTP_USER_INFO CI LEFT JOIN DTB_ACCT DA ON DA.ACCT_TP='0' AND DA.EBUSER_NO=CI.EBUSER_NO AND DA.CTP_ID=CI.CTP_ID WHERE CI.EBUSER_NO='1' AND CI.CTP_ID='1' ;
SELECT CI.EBUSER_TYP ,DA.ACCT_NO ELE_ACCT_NO,DA.IS_ACTIVE,DA.IS_SIGN_MOBILE,CI.MOBILE,CI.IS_CANCEL FROM CTP_USER_INFO CI LEFT JOIN DTB_ACCT DA ON DA.ACCT_TP='0' AND DA.EBUSER_NO=CI.EBUSER_NO AND DA.CTP_ID=CI.CTP_ID WHERE CI.EBUSER_NO='1' AND CI.CTP_ID='1' AND CI.IS_CANCEL='0' ;
SELECT CIF_NO,CUST_NAME,USER_STAT,EBUSER_TYP,MOBILE FROM CTP_USER_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' ;
SELECT C.IS_ACTIVE_STAT TRAN_STATE,C.ACCT_NO,C.MOBILE_NO NEW_MOBILE, C.EBUSER_TYP FROM CTP_BATCH_ACTIVE_TR C WHERE CTP_SEQ = '1' AND CTP_ID = '1' ;
SELECT CLEAR_TYP FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT CODE_TYPE TYPE, CODE_NO CODE, CODE_NAME LABEL FROM PARM_CODE T ORDER BY CODE_SORT ;
SELECT COUNT(1) ACCOUNT_NUMBER FROM CTP_USER_INFO WHERE 1=1 AND CTP_ID = '1' ;
SELECT COUNT(1) CUST_NUMBER FROM CTP_USER_INFO WHERE 1=1 AND CTP_ID = '1' ;
SELECT COUNT(1) DK_NUMBER,SUM(OPER_AMT) DK_AMT FROM DTB_UPAY_LIST WHERE OPER_TYPE='0' AND UPAY_STATE='6' AND CTP_ID = '1' ;
SELECT COUNT(1) FROM CTP_ACCT WHERE CTP_ID='1' AND CTP_ACCT = '1' AND CTP_ACCT_NAME = '1' ;
SELECT count(1) FROM CTP_BATCH_ACTIVE_TR WHERE CTP_ID='1' AND ID_NAME='1' AND ID_TYP='1' AND ID_NO = '1' AND CUST_ROLE = '1' AND IS_ACTIVE_STAT='Y' ;
SELECT COUNT(1) FROM CTP_FINAN_PLAN_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' AND PACKAGE_ID = '1' ;
SELECT COUNT(1) FROM CTP_PP_AUTO_BID_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' AND STAT = '0' ;
SELECT COUNT(1) FROM CTP_PP_BID_TR A WHERE A.CTP_ID = '1' AND A.PRO_ID = '1' AND A.BID_SEQ_NO = '1' ;
SELECT COUNT(1) FROM( SELECT A.*, ROW_NUMBER() OVER(ORDER BY CTP_ACCT) AS RN FROM CTP_ACCT A WHERE CTP_ID = '1' AND ACCT_STATE='N' ) ;
SELECT COUNT(1) FROM ( SELECT BID_SEQ_NO FROM CTP_PP_CONFIRM_TR A WHERE A.CTP_ID = '1' AND A.PRO_ID = '1' AND A.BID_SEQ_NO = '1' UNION ALL SELECT BID_SEQ FROM CTP_BATCH_AUTOBID_TR B WHERE B.CTP_ID = '1' AND B.PRO_ID = '1' AND B.BID_SEQ = '1' ) ;
SELECT COUNT(1) FROM( SELECT CPCT.BID_SEQ_NO, CPCT.PRO_ID, CUI.CUST_NAME, CUI.ID_NO, CUI.ID_TYP, CASE WHEN CPCT.BID_STAT = '0' THEN '正常' WHEN CPCT.BID_STAT = '1' THEN '已转让' WHEN CPCT.BID_STAT = '2' THEN '已兑付' WHEN CPCT.BID_STAT = '4' THEN '部分转让' WHEN CPCT.BID_STAT = '5' THEN '已定标' WHEN CPCT.BID_STAT = '6' THEN '作废' WHEN CPCT.BID_STAT = '7' THEN '已流标' WHEN CPCT.BID_STAT = '8' THEN '撤销已受理' WHEN CPCT.BID_STAT = '9' THEN '撤消成功' WHEN CPCT.BID_STAT = '10' THEN '撤销失败' ELSE CPCT.BID_STAT END AS BID_STAT_NAME, CASE WHEN CPCT.DF_STAT = '12' THEN '还款失败' WHEN CPCT.DF_STAT = '22' THEN '兑付失败' ELSE CPCT.DF_STAT END AS DF_STAT_NAME, NVL(CPCT.HK_AMT ,0) HK_AMT, ROW_NUMBER() OVER(ORDER BY CPCT.TRANS_SEQ DESC) AS RN FROM CTP_PP_CONFIRM_TR CPCT JOIN CTP_USER_INFO CUI ON CPCT.BIDER_NO = CUI.EBUSER_NO WHERE CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' AND (CPCT.DF_STAT = '12' OR CPCT.DF_STAT = '22') ) ;
SELECT COUNT(1) FROM( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_DATE DESC, TRAN_TIME DESC) AS RN, SEQ_NO, STAT, ID_TYP, ID_NO, ID_NAME, ACCT_NO, ACCT_NAME, REAL_AMT, TRAN_DATE, TRAN_TIME, COMPLE_DATE, COMPLE_TIME, HOST_CODE, HOST_MSG FROM CTP_BATCH_REBATE_TR WHERE 1=1 AND CTP_ID = '1' AND CTP_SEQ = '1' ) ;
SELECT COUNT(1) FROM( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_DATE DESC, TRAN_TIME DESC) AS RN, TRAN_SEQ, CTP_SEQ, STAT, ACCT_NO, ACCT_NAME, TRAN_AMT, TOT_NUM, SUCC_NUM, SUCC_AMT, FAIL_NUM, FAIL_AMT, TRAN_DATE, TRAN_TIME, COMPLE_DATE, COMPLE_TIME, HOST_CODE, HOST_MSG FROM CTP_BATCH_TR WHERE 1=1 AND CTP_ID = '1' AND ACCT_NO='1' AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')>=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')<=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TRAN_TYPE = '6' ) ;
SELECT COUNT(1) FROM( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_DATE DESC, TRAN_TIME DESC) AS RN, TRAN_SEQ, CTP_SEQ, STAT, ACCT_NO, ACCT_NAME, TRAN_AMT, TOT_NUM, SUCC_NUM, SUCC_AMT, FAIL_NUM, FAIL_AMT, TRAN_DATE, TRAN_TIME, COMPLE_DATE, COMPLE_TIME, HOST_CODE, HOST_MSG FROM CTP_BATCH_TR WHERE 1=1 AND CTP_ID = '1' AND CTP_SEQ='1' AND TRAN_TYPE = '6' ) ;
SELECT COUNT(1) FROM( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_SEQ DESC) AS RN, TRAN_SEQ, CTP_SEQ, TRAN_STAT STAT, PAY_ACCT ACCT_NO, PAY_NAME ACCT_NAME, TRAN_AMT, TRAN_DATE, TRAN_TIME FROM CTP_TRANS_UN_TR WHERE 1=1 AND CTP_ID = '1' AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')>=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')<=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') ) ;
SELECT COUNT(1) TOT_NUM,SUM(TRAN_AMT_FEN) TOT_AMT FROM ( SELECT ROW_NUMBER() OVER(ORDER BY A.HOST_SEQ) AS SEQ_NO, A.* FROM( SELECT CTT.PAY_ACCT,CTT.PAY_NAME, CTT.RCV_ACCT,CTT.RCV_NAME, TO_CHAR(CTT.TRAN_AMT*100) TRAN_AMT_FEN, CTT.TRAN_AMT, CTT.TRAN_HOST_NO HOST_SEQ,CTT.HOST_DATE, CTT.PAY_ACCT ACCT_NO,CTT.PAY_NAME ACCT_NAME, CPCT.CONF_SEQ CTP_DETAIL_SEQ,'3' JD_FLAG FROM CTP_TRANS_TR CTT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CTT.TRAN_SEQ=CPCT.PAY_SEQ WHERE CPCT.BID_STAT='0' AND CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' UNION ALL SELECT CBHT2.ACCT_NO,CBHT2.ACCT_NAME, CBT2.ACCT_NO RCV_ACCT,CBT2.ACCT_NAME RCV_NAME, TO_CHAR(CBHT2.TRAN_AMT*100) TRAN_AMT_FEN,CBHT2.TRAN_AMT, CBHT2.HOST_SEQ,CBHT2.HOST_DATE, CBHT2.ACCT_NO,CBHT2.ACCT_NAME, CPCT2.CONF_SEQ CTP_DETAIL_SEQ,'3' FROM CTP_BATCH_HOST_TR CBHT2 LEFT JOIN CTP_BATCH_TR CBT2 ON CBT2.TRAN_SEQ=CBHT2.TRAN_SEQ LEFT JOIN CTP_PP_CONFIRM_TR CPCT2 ON CPCT2.PAY_SEQ=CBHT2.TRAN_SEQ AND CPCT2.AUTO_SEQ = CBHT2.DETAIL_SEQ AND CPCT2.PRO_ID=CBHT2.PRO_ID AND CBT2.TRAN_TYPE='1' WHERE CPCT2.BID_STAT='0' AND CPCT2.CTP_ID = '1' AND CPCT2.PRO_ID = '1' ) A ) ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP = '0' WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND CUST_NAME LIKE '%'||'1'||'%' AND B.CUST_ROLE = '1' AND ID_NO LIKE '%'||'1'||'%' AND EBUSER_TYP = '1' ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND CUST_NAME LIKE '%'||'1'||'%' AND EBUSER_TYP = '1' ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND EBUSER_TYP = '1' ;
SELECT COUNT(A.OPEN_DATE) FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND ID_NO LIKE '%'||'1'||'%' AND EBUSER_TYP = '1' ;
select count(case when R.oper_type='0' and R.tran_state='6' then 1 when R.oper_type='1' and R.tran_state='7' then 1 end) from ( SELECT ROW_NUMBER() OVER(ORDER BY DB.TRAN_DATE DESC,DB.TRAN_TIME DESC) AS RN, DB.*,DUL.UPAY_MSG,PI.PASS_NAME AS CODE_NAME FROM DTB_ROLL_TR DB LEFT JOIN PASS_INF PI ON PI.PASS_TYPE = DB.TRANS_CHAN_TYPE LEFT JOIN DTB_UPAY_LIST DUL ON DB.TRAN_SEQ=DUL.TRAN_SEQ WHERE 1=1 AND TO_DATE(DB.TRAN_DATE, 'YYYY-MM-DD')=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND DB.CTP_ID = '1' ) R ;
SELECT COUNT(*) FROM CTP_ACCT WHERE CTP_ID='1' AND ACCT_STATE='N' ;
SELECT COUNT(*) FROM CTP_COMP_QUAIL_INFO A LEFT JOIN CTP_INFO B ON A.CTP_ID=B.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' AND A.SUBMIT_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT COUNT(*) FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN CTP_INFO C ON A.CTP_ID=C.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' ;
SELECT COUNT(*) FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN CTP_INFO C ON A.CTP_ID=C.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' AND A.COMP_NAME LIKE '%'||'1'||'%' ;
SELECT COUNT(*) FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN CTP_INFO C ON A.CTP_ID=C.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' AND A.CTP_TRAN_SEQ LIKE '%'||'1'||'%' ;
SELECT COUNT(*) FROM CTP_FINAN_PLAN_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' AND STAT = '0' ;
SELECT COUNT(*) FROM CTP_MER_AUTH_DATA WHERE REV_RESULT = '2' AND CTP_ID='1' AND SUM_MER_ID!='1' ;
SELECT COUNT(*) FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' ;
SELECT COUNT(*) FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' AND TO_DATE(A.CRE_DATE,'YYYY-MM-DD')>=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TO_DATE(A.CRE_DATE,'YYYY-MM-DD')<=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD')+1 ;
SELECT COUNT(*) FROM CTP_PP_ZR_ORDER_TR WHERE CTP_SEQ='1' AND CTP_ID='1' ;
SELECT COUNT(*) FROM CTP_REBATE_SIGN_INFO WHERE CTP_ID='1' ;
SELECT COUNT(*) FROM CTP_SUB_ACCT WHERE EBUSER_NO = '1' AND SUB_ACCT_NO = '1' ;
SELECT COUNT(*) FROM DTB_ACCT WHERE EBUSER_NO='1' AND ACCT_TP!='0' ;
SELECT COUNT(*) FROM DTB_UPAY_ACCT_CHECK WHERE ORDER_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND IS_CHECK='0' AND PASS_TYPE='1' ;
SELECT COUNT(*) FROM DTB_UPAY_ACCT_CHECK WHERE ORDER_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND PASS_TYPE='1' ;
SELECT COUNT(*) FROM PROT_TEMP WHERE PROT_TEMP_ID='1' ;
SELECT COUNT(*) FROM ( SELECT A.* , ROW_NUMBER() OVER(ORDER BY TRANS_SEQ DESC) AS RN FROM CTP_CHECK_MSG A where STAT = '0' ) ;
select count(*) from ( SELECT ROW_NUMBER() OVER(ORDER BY DB.TRAN_DATE DESC,DB.TRAN_TIME DESC) AS RN, DB.*,DUL.UPAY_MSG,PI.PASS_NAME AS CODE_NAME FROM DTB_ROLL_TR DB LEFT JOIN PASS_INF PI ON PI.PASS_TYPE = DB.TRANS_CHAN_TYPE LEFT JOIN DTB_UPAY_LIST DUL ON DB.TRAN_SEQ=DUL.TRAN_SEQ WHERE 1=1 AND TO_DATE(DB.TRAN_DATE, 'YYYY-MM-DD')=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND DB.CTP_ID = '1' ) R ;
SELECT COUNT(*) FROM ( SELECT ROWNUM RN,TT.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY T.PRO_ID DESC) AS RN_IN,T.* FROM( SELECT CPI.PRO_TYP, CPI.PRO_ID, CPI.PRO_NAME, CPI.PRO_AMT, CPI.RISK_LEV, CPI.PRO_DESC, CPI.STAR_BUY_TIME, CPI.END_BUY_TIME, CPI.STAR_DATE, CPI.PRO_TERM, CPI.EXPINC_RATE, CPI.END_DATE, CPI.MJ_NAME ID_NAME, CPI.MJ_ID_TYP ID_TYP, CPI.MJ_ID_NO ID_NO, CPI.ZR_FLAG, CPI.DC_FLAG, CPI.STAT, CPIV.RCV_ID_TYP1, CPIV.RCV_ID_NO1, CPIV.RCV_NAME1, CPIV.RCV_ID_TYP2, CPIV.RCV_ID_NO2, CPIV.RCV_NAME2, CPIV.RCV_ID_TYP3, CPIV.RCV_ID_NO3, CPIV.RCV_NAME3, CPIV.RCV_ID_TYP4, CPIV.RCV_ID_NO4, CPIV.RCV_NAME4, CPI.PRO_MIN_AMT, CUI.CUST_ROLE, CPI.BUY_ACCT, CPI.BUY_NAME BUY_ACCT_NAME, CPI.DF_ACCT, CPI.DF_NAME DF_ACCT_NAME, CPI.TOT_FEE, CPI.AUTO_REPAY_COUNT, CPI.AUTO_REPAY_QUOTA, CPI.AUTO_REPAY_END_DATE, CPI.HK_CORPUS, CPI.HK_ACCRUAL, CPI.HK_AMT FROM CTP_PP_INFO CPI LEFT JOIN CTP_PP_INFO_RECV CPIV ON CPIV.PRO_ID=CPI.PRO_ID LEFT JOIN CTP_USER_INFO CUI ON CPI.MJ_NO = CUI.EBUSER_NO WHERE CPI.CTP_ID='1' AND CPI.PRO_TYP='1' AND CPI.PRO_ID='1' ) T ) TT ) ;
SELECT COUNT(HANG_DATE) FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CUI ON DA.EBUSER_NO = CUI.EBUSER_NO WHERE CUI.EBUSER_TYP = '1' and DA.CTP_ID='1' AND DA.ACCT_TP='1' ;
SELECT COUNT(HANG_DATE) FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CUI ON DA.EBUSER_NO = CUI.EBUSER_NO WHERE CUI.EBUSER_TYP = '1' and DA.CTP_ID='1' AND DA.ACCT_TP='1' AND DA.ACCT_NAME LIKE '%'||'1'||'%' ;
SELECT CPABT.STAT TRAN_STAT, CPABT.CTP_SEQ, CUI.CUST_NAME ID_NAME, CUI.ID_NO, CT.TRANS_URL,CT.H_RSP_MSG TRAN_MSG FROM CTP_PP_AUTO_BID_TR CPABT LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = CPABT.EBUSER_NO LEFT JOIN CTP_COMMON_TR CT ON CPABT.CTP_SEQ = CT.CTP_SEQ WHERE CPABT.CTP_SEQ = '1' AND CPABT.CTP_ID = '1' AND CT.APP_TYPE = 'Interface' AND CT.TRANS_CODE = 'ctpP2pAutoBidRSignReq' ORDER BY REPLACE(CPABT.TRAN_DATE,'-','')||REPLACE(CPABT.TRAN_TIME,':','') DESC ;
SELECT CPAT.CTP_SEQ TRANS_SEQ,CPAT.CTP_ID,CPAT.SYNZ_URL, CPAT.PRO_TYP,CPAT.PRO_ID, CPAT.PRO_NAME, TO_CHAR(CPAT.PRO_AMT*100) PRO_AMT, CPAT.MJ_ID_NO ID_NO,CPAT.MJ_ID_TYP ID_TYP, CPAT.MJ_NAME ID_NAME, DA.ACCT_NO ELE_ACCT_NO, CPI.STAT,CPAT.CRE_DATE,CPAT.CRE_TIME, DA.CUST_ROLE, CPI.BUY_ACCT, CPI.BUY_NAME BUY_ACCT_NAME, CPI.DF_ACCT, CPI.DF_NAME DF_ACCT_NAME FROM CTP_PP_ADD_TR CPAT LEFT JOIN CTP_PP_INFO CPI ON CPI.CTP_ID=CPAT.CTP_ID AND CPI.PRO_ID=CPAT.PRO_ID LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CPAT.MJ_NO AND DA.ACCT_TP='0' WHERE CPAT.CTP_ID = '1' AND CPAT.CTP_SEQ = '1' AND CPAT.STAT = '5' AND CPAT.SYNZ_URL IS NOT NULL ;
SELECT CPBT.HOST_FILE,CPI.STAT,CPBT.TOT_NUM, CPI.CTP_ID,CPI.PRO_ID, CPBT.HOST_BATCH_NO, CPBT.TRAN_SEQ, CPBT.TRAN_TYPE,CPBT.CTP_SEQ,CPBT.CTP_DATE FROM CTP_BATCH_TR CPBT LEFT JOIN CTP_PP_INFO CPI ON CPBT.PRO_ID=CPI.PRO_ID AND CPBT.CTP_ID=CPI.CTP_ID WHERE HOST_BATCH_NO = '1' ;
SELECT CPBT.HOST_FILE,CPI.STAT,CPBT.TOT_NUM, CPI.CTP_ID,CPI.PRO_ID, CPBT.HOST_BATCH_NO, CPBT.TRAN_SEQ, CPBT.TRAN_TYPE,CPBT.CTP_SEQ,CPBT.TRAN_AMT*100 TOT_AMT FROM CTP_BATCH_TR CPBT LEFT JOIN CTP_PP_INFO CPI ON CPBT.PRO_ID=CPI.PRO_ID AND CPBT.CTP_ID=CPI.CTP_ID WHERE HOST_BATCH_NO = '1' ;
SELECT CPCT.ACCT_NO, CUI.EBUSER_NO, CPCT.ACCT_NAME FROM DTB_ACCT CPCT LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO=CPCT.EBUSER_NO WHERE CUI.CUST_NAME = '1' AND CUI.ID_TYP = '1' AND CUI.ID_NO = '1' AND CUI.CUST_ROLE = '1' AND CUI.CTP_ID = '1' AND CPCT.ACCT_TP = '0' AND CUI.IS_CANCEL ='0' ;
SELECT CPCT.FRONT_CODE,CI.OPEN_ORG,CI.CTP_ID,CPCT.STAT FROM CTP_BATCH_TR CPCT LEFT JOIN CTP_INFO CI ON CI.CTP_ID=CPCT.CTP_ID WHERE HOST_BATCH_NO = '1' ;
SELECT CPCT.TRANS_SEQ, CPCT.BID_SEQ_NO,CUI.ID_TYP,CUI.ID_NO, CUI.CUST_NAME,CPCT.BIDER_ACCT RCV_ACCT, CPCT.DF_SEQ CTP_DETAIL_SEQ,CPCT.BID_AMT,CPCT.PRO_ID, CUI.CUST_ROLE FROM CTP_PP_CONFIRM_TR CPCT LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO=CPCT.BIDER_NO WHERE CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' AND CPCT.BID_STAT = '5' AND CPCT.LOCK_FLAG = '0' ;
SELECT CPI.BUY_ACCT GJ_ACCT,DA.ACCT_NO MJ_ACCT, CPI.BUY_NAME GJ_NAME,DA.ACCT_NAME MJ_NAME, CPI.PRO_AMT TRAN_AMT, CPI.FEE_ACCT1,CPI.FEE_NAME1,CPI.FEE_AMT1, CPI.FEE_ACCT2,CPI.FEE_NAME2,CPI.FEE_AMT2, CPI.FEE_ACCT3,CPI.FEE_NAME3,CPI.FEE_AMT3, CPI.FEE_ACCT4,CPI.FEE_NAME4,CPI.FEE_AMT4, CPI.FEE_ACCT5,CPI.FEE_NAME5,CPI.FEE_AMT5 FROM CTP_PP_INFO CPI LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CPI.MJ_NO AND DA.ACCT_TP = '0' WHERE CPI.CTP_ID = '1' AND CPI.PRO_ID = '1' ;
SELECT CPI.STAT,CPI.DB_FLAG,CPI.BUY_ACCT,CPI.HK_FLAG, CPI.BUY_ACCT,CPI.BUY_NAME,DA.ACCT_NO,DA.ACCT_NAME, CPI.PRO_AMT,CPI.TOT_NUM,CPI.CONF_STAT,CPI.CONF_SEQ, CPI.FEE_PER_TOP,CPI.LEFT_AMT,CPI.TOT_FEE FROM CTP_PP_INFO CPI LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CPI.MJ_NO AND DA.ACCT_TP='0' WHERE CPI.CTP_ID = '1' AND CPI.PRO_TYP = '1' AND CPI.PRO_ID = '1' AND CPI.MJ_NO = '1' ;
SELECT CPOT.BIDER_NAME ID_NAME, CPOT.BIDER_ID_NO ID_NO, CPOT.BIDER_ACCT ACCT_NO, CPOT.TRAN_AMT, CPI.PRO_NAME, CPOT.CTP_SEQ, CT.TRANS_URL, CASE WHEN CPOT.STAT = 4 THEN '0' WHEN CPOT.STAT = 5 THEN '2' WHEN CPOT.STAT = 3 THEN '4' WHEN CPOT.STAT = 1 THEN '3' ELSE '1' END AS TRAN_STAT,CT.H_RSP_MSG TRAN_MSG FROM CTP_PP_ORDER_TR CPOT LEFT JOIN CTP_PP_INFO CPI ON CPI.PRO_ID = CPOT.PRO_ID AND CPI.CTP_ID = CPOT.CTP_ID LEFT JOIN CTP_COMMON_TR CT ON CPOT.CTP_SEQ = CT.CTP_SEQ WHERE CPOT.CTP_SEQ = '1' AND CT.APP_TYPE = 'Interface' AND CT.TRANS_CODE = 'ctpP2pProjectBidReq' ORDER BY REPLACE(CT.TRAN_DATE,'-','')||REPLACE(CT.TRAN_TIME,':','') DESC ;
SELECT CPZOT.CTP_ID, CPZOT.TRANS_SEQ, CPZOT.PRO_ID, CPCT1.BID_SEQ_NO BID_SEQ_NO, CPCT1.BID_SEQ_NO BUY_BID_NO, CPCT1.BID_STAT BUY_BID_STAT, CPCT2.BID_SEQ_NO ZR_BID_NO, CPCT2.BID_STAT ZR_BID_STAT, CPZT.STAT TRAN_STAT, CPZT.RET_CODE HOST_CODE, CPZT.RET_MSG HOST_CODE, CPZOT.SYNZ_URL FROM CTP_PP_ZR_ORDER_TR CPZOT LEFT JOIN CTP_PP_ZR_TR CPZT ON CPZT.CTP_ID=CPZOT.CTP_ID AND CPZT.CTP_SEQ=CPZOT.CTP_SEQ LEFT JOIN CTP_PP_CONFIRM_TR CPCT1 ON CPCT1.TRANS_SEQ=CPZT.ZR_REG_NO LEFT JOIN CTP_PP_CONFIRM_TR CPCT2 ON CPCT2.TRANS_SEQ=CPZT.BUY_REG_NO WHERE CPZOT.CTP_ID='1' AND CPZOT.CTP_SEQ='1' AND CPZOT.STAT='4' AND CPZOT.SYNZ_URL IS NOT NULL ;
SELECT CPZT.ZR_NAME ID_NAME, CPZT.ZR_ID_NO ID_NO, CPZT.ZR_ACCT ACCT_NO, CPZT.TRAN_AMT, CPZT.CTP_SEQ, CPI.PRO_NAME, CT.TRANS_URL, CASE WHEN CPZT.STAT = 4 THEN '0' WHEN CPZT.STAT = 5 THEN '2' WHEN CPZT.STAT = 3 THEN '4' WHEN CPZT.STAT = 1 THEN '3' ELSE '1' END AS TRAN_STAT,CPZT.RET_MSG,CT.H_RSP_MSG TRAN_MSG FROM CTP_PP_ZR_ORDER_TR CPZT LEFT JOIN CTP_PP_INFO CPI ON CPI.PRO_ID = CPZT.PRO_ID AND CPI.CTP_ID = CPZT.CTP_ID LEFT JOIN CTP_COMMON_TR CT ON CPZT.CTP_SEQ = CT.CTP_SEQ WHERE CPZT.CTP_SEQ = '1' AND CPZT.CTP_ID = '1' AND CT.APP_TYPE = 'Interface' AND CT.TRANS_CODE = 'ctpP2pProjectAssiReq' ORDER BY REPLACE(CT.TRAN_DATE,'-','')||REPLACE(CT.TRAN_TIME,':','') DESC ;
SELECT CRT.TRAN_STATE TRAN_STAT, CCQI.ID_NO, CCQI.COMP_NAME, CCQI.CTP_TRAN_SEQ CTP_SEQ, CCQI.EACCT_NO, DA.EBUSER_NO, CCQI.UNI_STAT FROM CTP_COMP_QUAIL_INFO CCQI LEFT JOIN CTP_REGISTER_TR CRT ON CCQI.CTP_TRAN_SEQ=CRT.CTP_SEQ_NO LEFT JOIN DTB_ACCT DA ON DA.ACCT_NO = CCQI.EACCT_NO WHERE CCQI.CTP_TRAN_SEQ = '1' ORDER BY REPLACE(CRT.TRAN_DATE,'-', '') || REPLACE(CRT.TRAN_TIME, ':', '') DESC ;
SELECT CSD.TRAN_TYPE,CSD.TRAN_DATE FEE_DATE, SUM(CSD.COST_FEE)*100 FEE_COST, SUM(CSD.FEE_AMT)*100 FEE_AMT, SUM(CSD.SER_FEE)*100 SER_FEE, SUM(DR.TRAN_FEE)*100 TOT_FEE, SUM(DUL.OPER_AMT)*100 TOT_AMT, DR.GG_BRANCH_NO,DU.OPER_TYPE, DR.GG_TELLER_NO,DR.TERMINALID, DU.PASS_TYPE,DR.CTP_ID,DR.CHAN_TYP, DU.LOAD_DATE,DU.ORDER_DATE,DR.SYSID FROM DTB_UPAY_ACCT_CHECK DU LEFT JOIN DTB_ROLL_TR DR ON DR.TRAN_SEQ=DU.TRAN_SEQ LEFT JOIN CTP_SERVICE_DETAIL_REGISTER CSD ON CSD.TRAN_SEQ=DU.TRAN_SEQ LEFT JOIN DTB_UPAY_LIST DUL ON DUL.TRAN_SEQ = DU.TRAN_SEQ WHERE 1=1 AND DU.CHECK_RESULT = '3' AND DU.PASS_TYPE = '1' AND DU.ORDER_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') GROUP BY DR.GG_BRANCH_NO,DU.OPER_TYPE, DU.PASS_TYPE,DU.LOAD_DATE,DU.ORDER_DATE, CSD.TRAN_TYPE, DR.CTP_ID,CSD.TRAN_DATE, DR.CHAN_TYP,DR.GG_TELLER_NO,DR.TERMINALID,DR.SYSID ;
SELECT CTO.EBUSER_NO, CTO.OPER_TYPE, CTO.ORDER_NO, CTO.ACCT_NO, CTO.TRAN_AMT, CTO.CUST_FEE, DA.ACCT_NO ELE_ACCT_NO, DA.ACCT_TP, DA2.BANK_NO RCV_BANK_CODE, BCC.BANK_NAME RCV_BANK_NAME, DA2.BRANCH_NO RCV_BRANCH_CODE, PBC.LNAME RCV_BRANCH_NAME, PBC.NODE_CODE PROV_CODE, PBC.CITY_CODE, CTO.BACK_URL,CTO.CTP_SEQ, PBC.CLS_CODE, CUI.MOBILE MOBILE_NO,FEE_LIST,CUI.EBUSER_TYP, REPLACE(CRE_DATE,'-','')||REPLACE(CRE_TIME,':','') ORDER_CRE_TIME FROM CTP_TRANS_ORDER_INFO CTO LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO=CTO.EBUSER_NO AND DA.ACCT_TP='0' AND DA.CTP_ID = CTO.CTP_ID LEFT JOIN DTB_ACCT DA2 ON DA2.EBUSER_NO = CTO.EBUSER_NO AND DA2.CTP_ID = CTO.CTP_ID AND DA2.ACCT_TP != '0' LEFT JOIN BANK_COFG_CODE BCC ON DA2.BANK_NO=BCC.BANK_CODE AND DA2.ACCT_NO=CTO.ACCT_NO LEFT JOIN PT_BANK_CODE PBC ON DA2.BRANCH_NO=PBC.BANK_CODE AND DA2.ACCT_NO=CTO.ACCT_NO AND PBC.MSG_TYPE IN('CNAPS','CNAPS1') LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO=CTO.EBUSER_NO WHERE CTO.CTP_ID = '1' AND CTO.ORDER_NO = '1' AND STATE = '1' ;
SELECT CTP_ACCT,CTP_ACCT_NAME,TAKE_PRE_NO, BANK_NO, BANKNAME, CTP_OPEN_ORG FROM CTP_ACCT WHERE CTP_ID = '1' AND ACCT_STATE = 'N' ;
SELECT CTP_ACCT,CTP_ACCT_NAME,TAKE_PRE_NO, BANK_NO, BANKNAME, CTP_OPEN_ORG FROM CTP_ACCT WHERE CTP_ID = '1' AND ACCT_STATE = 'N' AND ACCT_RIGHT = '1' ;
SELECT CTP_ACCT FROM CTP_ACCT WHERE CTP_ID = '1' AND ACCT_STATE = 'N' AND CTP_ACCT = '1' ;
SELECT CTP_ACCT_NAME FROM CTP_ACCT WHERE CTP_ACCT = '1' AND CTP_ID = '1' ;
SELECT CTP_DETAIL_SEQ.NEXTVAL FROM DUAL ;
SELECT CTP_ID1,CTP_ID2 FROM CTP_CAP_CONF_TR WHERE CTP_ID1 = '1' UNION SELECT CTP_ID1,CTP_ID2 FROM CTP_CAP_CONF_TR WHERE CTP_ID2 = '1' ;
SELECT CTP_ID,ACCT_NO from DTB_ACCT WHERE EBUSER_NO='1' AND IS_CANCEL='0' AND ACCT_TP='0' ;
SELECT CTP_ID,CTP_NAME,CTP_ONLINE_DATE,CONTRACT_BEGIN_DATE,CONTRACT_END_DATE,COMP_FULL_NAME FROM CTP_ONLINE_INFO WHERE 1=1 AND CTP_ID = '1' ;
SELECT CTP_ID,CTP_NAME,OPEN_ORG,STAT, CIF_NO,SER_FEE_ACCT,SER_FEE_NAME, DF_ACCT,ACCOUNT,MIDDLE_ACCT_NO,MIDDLE_ACCT_NAME FROM CTP_INFO ;
SELECT CTP_ID,CTP_SEQ,FRONT_CODE,HOST_BATCH_NO BATCH_NO, STAT BATCH_STAT, TRAN_TYPE, TOT_NUM, TO_CHAR(TRAN_AMT*100) TOT_AMT, SUCC_NUM,TO_CHAR(SUCC_AMT*100) SUCC_AMT, FAIL_NUM,TO_CHAR(FAIL_AMT*100) FAIL_AMT FROM CTP_BATCH_TR WHERE TRAN_SEQ = '1' ;
SELECT CTP_ID,CTP_TRAN_SEQ,UNI_STAT,DO_FLAG FROM CTP_COMP_QUAIL_INFO WHERE UNI_NO='1' ;
SELECT CTP_ID,PRO_ID,PRO_NAME,PRO_TYP, PRO_AMT*100 PRO_AMT,RISK_LEV, PRO_DESC,CRE_DATE,CRE_TIME, STAR_BUY_TIME,END_BUY_TIME, STAR_DATE,END_DATE,PRO_TERM, MJ_NO,MJ_NAME,MJ_ID_TYP,MJ_ID_NO, DF_DATE,DF_TIME,ZR_FLAG, DC_FLAG,IS_DC_FLAG,HK_FLAG, FEE_PER_TOP,EXPINC_RATE,BUY_ACCT,BUY_NAME, DF_ACCT,DF_NAME,STAT,DC_AMT,TOT_FX_AMT, FX_PER_TOP,AGREE_NO,DB_FLAG, LEFT_AMT*100 LEFT_AMT,TOT_NUM,CONF_SEQ, CONF_STAT,DF_SEQ,DF_STAT,IS_AUTO_BID,PRO_MIN_AMT*100 PRO_MIN_AMT FROM CTP_PP_INFO WHERE CTP_ID = '1' AND PRO_ID = '1' ;
SELECT CTP_ID,TRAN_SEQ,CTP_SEQ,BID_SEQ_NO, BIDER_NO EBUSER_NO,BIDER_NAME ELE_ACCT_NAME, BIDER_ID_TYP, BIDER_ID_NO, BIDER_ACCT ELE_ACCT_NO, PRO_ID, BID_AMT*100 BID_AMT,TRAN_AMT*100 TRAN_AMT, ACTIVE_DESC1,ACTIVE_ACCT1,ACTIVE_NAME1, ACTIVE_AMT1*100 ACTIVE_AMT1,ACTIVE_DESC2, ACTIVE_ACCT2,ACTIVE_NAME2, ACTIVE_AMT2*100 ACTIVE_AMT2, ACTIVE_DESC3,ACTIVE_ACCT3,ACTIVE_NAME3, ACTIVE_AMT3*100 ACTIVE_AMT3, BACK_URL,STAT,CRE_DATE,CRE_TIME, REPLACE(CRE_DATE,'-','')||REPLACE(CRE_TIME,':','') ORDER_CRE_TIME FROM CTP_PP_ORDER_TR WHERE CTP_ID = '1' AND CTP_SEQ = '1' ;
SELECT CTP_NAME FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT CTP_NAME,OPEN_ORG,STAT,ACCOUNT,ACCOUNT_NAME FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT CTP_OPEN_ORG,CTP_ACCT_NAME, TAKE_PRE_NO, ACCT_RIGHT FROM CTP_ACCT WHERE CTP_ID = '1' AND CTP_ACCT = '1' AND ACCT_STATE = 'N' ;
SELECT CTP_P2P_REGIST_SEQ.NEXTVAL FROM DUAL ;
SELECT CU.EBUSER_NO,CU.USER_STAT ,DA.IS_ACTIVE, DA.ACCT_NO EACCT_NO,DA.IS_SIGN_MOBILE, DA1.BANK_NO BANK_CODE,DA1.BANK_NAME,DA1.REG_AMT FROM CTP_USER_INFO cu LEFT JOIN DTB_ACCT DA ON CU.EBUSER_NO=DA.EBUSER_NO AND DA.ACCT_TP='0' LEFT JOIN DTB_ACCT DA1 ON CU.EBUSER_NO=DA1.EBUSER_NO AND DA1.ACCT_TP<>'0' WHERE CU.ID_TYP = '1' AND CU.ID_NO = '1' AND CU.CUST_NAME = '1' AND CU.CTP_ID = '1' AND CU.CUST_ROLE = '1' AND CU.IS_CANCEL = '0' ;
SELECT CUI.EBUSER_NO, DA.ACCT_NO ELE_ACCT_NO, DA.ACCT_NAME FROM CTP_USER_INFO CUI LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO = CUI.EBUSER_NO AND ACCT_TP = '0' WHERE CUI.CTP_ID = '1' AND CUI.ID_TYP = '1' AND CUI.ID_NO = '1' AND CUI.CUST_NAME = '1' AND CUI.CUST_ROLE = '1' AND CUI.IS_CANCEL = '0' ;
SELECT CUI.MOBILE MOBILE_NO, CUI.CIF_NO CUST_NO, DA.ACCT_NO ELE_ACCT_NO FROM CTP_USER_INFO CUI LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO = CUI.EBUSER_NO AND DA.ACCT_TP = '0' WHERE CUI.EBUSER_NO = '1' ;
SELECT CUST_FEE_TOP FROM CTP_SER_FEE_CONF WHERE TRAN_TYPE='P5' AND CTP_ID='1' ;
SELECT CUST_ID_SEQ.NEXTVAL FROM DUAL ;
SELECT CUST_LOGIN_ID_SEQ.NEXTVAL FROM DUAL ;
SELECT CUST_NAME,ID_TYP,ID_NO FROM CTP_USER_INFO WHERE EBUSER_NO = '1' ;
SELECT CUSTOMERID CIF_ID,ID_TYP,ID_NO,COMP_NAME CUST_NAME,LEGAL_ID_TYP LEGAL_IDT, LEGAL_ID_NO LEGAL_IDT_NO,LEGAL_PHONE LEGAL_PHONE_NO,LEGAL_NAME,CUST_ROLE FROM CTP_COMP_QUAIL_INFO WHERE UNI_NO='1' AND CTP_ID='1' AND IS_EACCT_SIGN='N' AND UNI_STAT='1' ;
SELECT CUST_ROLE, EBUSER_NO, A.CTP_ID ,B.CTP_NAME,B.OPEN_ORG FROM CTP_USER_INFO A, CTP_INFO B WHERE A.CUST_NAME='1' AND A.ID_TYP='1' AND A.ID_NO='1' AND A.IS_CANCEL = '0' AND A.CTP_ID=B.CTP_ID AND B.CTP_ID IN (SELECT DISTINCT CTP_ID FROM CTP_P2P_TYP_CONF) ;
SELECT CUST_ROLE,ID_NAME,ID_NO,MOBILE,CTP_LOGIN_NAME,CTP_NICK_NAME,CCY_TYPE,ACC_ALIAS,CUST_ENAME,ID_TYP, EBUSER_TYP,OPEN_TELLER,SERIAL_NO,CHK_CODE,SYNZ_URL,CTP_ID,BACK_URL,STAT,TRANS_SEQ, CASE WHEN ID_TYP='01' THEN '身份证' WHEN ID_TYP='02' THEN '户口本' WHEN ID_TYP='03' THEN '军官证' WHEN ID_TYP='05' THEN '护照' WHEN ID_TYP='20' THEN '港澳居民来往内地通行证' WHEN ID_TYP='21' THEN '台湾居民来往大陆通行证' WHEN ID_TYP='22' THEN '临时身份证' WHEN ID_TYP='23' THEN '武警证' WHEN ID_TYP='24' THEN '外国人永久居留证' WHEN ID_TYP='25' THEN '边民出入通行证' WHEN ID_TYP='26' THEN '外国护照' END AS ID_TYP_CNY, CASE WHEN STAT IN ('0','2') THEN '0' ELSE STAT END AS ORDER_STAT FROM PER_CUST_ACCOUNT_APPLY WHERE TRAN_SEQ = '1' AND CTP_ID = '1' ;
SELECT CUT.ACTIVE_ACCT1,CUT.ACTIVE_NAME1,CUT.ACTIVE_AMT1, CUT.ACTIVE_ACCT2,CUT.ACTIVE_NAME2,CUT.ACTIVE_AMT2, CUT.ACTIVE_ACCT3,CUT.ACTIVE_NAME3,CUT.ACTIVE_AMT3 FROM CTP_FINAN_PLAN_TR CUT WHERE CUT.TRANS_SEQ = '1' AND CUT.CTP_ID = '1' AND CUT.CTP_SEQ = '1' ;
SELECT CUT.CTP_ID,CUT.CTP_SEQ,CUT.TRAN_SEQ TRANS_SEQ,CUT.SYNZ_URL,CPABT.CTP_SEQ CTP_SEQ, CUI.ID_TYP,CUI.ID_NO,CUI.CUST_NAME ID_NAME, CASE WHEN CUT.DATA_FIELD='S' THEN '1' WHEN CUT.DATA_FIELD='F' THEN '2'END AS OPER_TYPE, CPABT.STAT TRAN_STAT, CUI.CUST_ROLE FROM CTP_URL_TR CUT LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO=CUT.EBUSER_NO LEFT JOIN CTP_PP_AUTO_BID_TR CPABT ON CPABT.CTP_ID=CUT.CTP_ID AND CPABT.CTP_SEQ=CUT.CTP_SEQ WHERE CUT.CTP_ID='1' AND CUT.TRAN_SEQ='1' AND CUT.TRAN_TYPE = '6' AND CUT.STAT = '2' AND CUT.SYNZ_URL IS NOT NULL ;
SELECT CUT.EBUSER_NO, CUT.BACK_URL, CUT.DATA_FIELD OPER_TYPE, CUT.CTP_SEQ, DA.ACCT_NO ELE_ACCT_NO, DA.ACCT_NAME ELE_ACCT_NAME, CUT.TRAN_DATE, CUT.MAX_DATE, CUT.MAX_AMT, CUT.MAX_COUNT, CUT.CTP_DATE FROM CTP_URL_TR CUT LEFT JOIN DTB_ACCT DA ON CUT.EBUSER_NO=DA.EBUSER_NO AND DA.CTP_ID = CUT.CTP_ID AND DA.ACCT_TP = '0' WHERE CUT.TRAN_SEQ = '1' AND CUT.CTP_ID = '1' AND CUT.TRAN_TYPE = '6' ;
SELECT CUT.EBUSER_NO, CUT.BACK_URL, CUT.SIGN_TYPE OPER_TYPE, CUT.CTP_SEQ, DA.ACCT_NO ELE_ACCT_NO, DA.ACCT_NAME ELE_ACCT_NAME, CUT.TRAN_DATE, CUT.TRAN_TIME, CUT.PACKAGE_ID,CUT.PACKAGE_NAME,CUT.FEE_TOP, CUT.AMT*100 AMT,CUT.TRAN_AMT*100 TRAN_AMT, CUT.MAX_DATE FROM CTP_FINAN_PLAN_TR CUT LEFT JOIN DTB_ACCT DA ON CUT.EBUSER_NO=DA.EBUSER_NO AND DA.CTP_ID = CUT.CTP_ID AND DA.ACCT_TP = '0' WHERE CUT.TRANS_SEQ = '1' AND CUT.CTP_ID = '1' AND CUT.STAT = '3' ;
SELECT CUT.STAT, CUT.BACK_URL, CUT.EBUSER_NO, CCI.MOBILE, CCI.CUST_NAME, CUT.CTP_SEQ, CCI.ID_NO, DT.ACCT_NO CARD_NO, DA.ACCT_NO BIND_CARD, CUT.DATA_FIELD, CUT.TRAN_DATE, CUT.CUST_ROLE, CUT.IS_REALNAME FROM CTP_URL_TR CUT LEFT JOIN CTP_USER_INFO CCI ON CCI.EBUSER_NO = CUT.EBUSER_NO LEFT JOIN DTB_ACCT DA ON DA.EBUSER_NO = CUT.EBUSER_NO AND ACCT_TP = '0' LEFT JOIN DTB_ACCT DT ON DT.EBUSER_NO = CUT.EBUSER_NO AND DT.ACCT_TP != '0' WHERE CUT.CTP_ID='1' AND CUT.TRAN_SEQ='1' AND CUT.TRAN_TYPE='1' ;
SELECT DA.ACCT_NAME, DA.ACCT_NO, CFPT.SUB_ACCT_NO,CFPT.SIGN_TYPE,CFPT.STAT,CFPT.PACKAGE_ID,CFPT.PACKAGE_NAME,CFPI.AMT*100 AMT,CFPT.MAX_DATE,CUI.CUST_ROLE FROM CTP_FINAN_PLAN_TR CFPT LEFT JOIN CTP_SUB_ACCT CSA ON CFPT.EBUSER_NO = CSA.EBUSER_NO AND CFPT.CTP_ID = CSA.CTP_ID AND CFPT.SUB_ACCT_NO = CSA.SUB_ACCT_NO LEFT JOIN CTP_FINAN_PLAN_INFO CFPI ON CFPT.CTP_ID = CFPI.CTP_ID AND CFPT.EBUSER_NO = CFPI.EBUSER_NO AND CFPT.PACKAGE_ID =CFPI.PACKAGE_ID LEFT JOIN DTB_ACCT DA ON CFPT.EBUSER_NO = DA.EBUSER_NO AND CFPT.CTP_ID=DA.CTP_ID LEFT JOIN CTP_USER_INFO CUI ON CFPT.EBUSER_NO = CUI.EBUSER_NO AND CFPT.CTP_ID=CUI.CTP_ID WHERE CFPT.CTP_SEQ='1' AND CFPT.CTP_ID='1' AND DA.ACCT_TP='0' AND CFPT.SIGN_TYPE='1' ;
SELECT DA.ACCT_NO,DA.ACCT_NAME,CUI.EBUSER_NO,CUI.CUST_NAME,CUI.ID_TYP,CUI.ID_NO,DA.CUST_ROLE FROM CTP_USER_INFO CUI LEFT JOIN DTB_ACCT DA ON CUI.EBUSER_NO=DA.EBUSER_NO WHERE CUI.EBUSER_NO='1' AND CUI.CTP_ID='1' AND DA.ACCT_TP='0' AND CUI.IS_CANCEL = '0' ;
SELECT DA.ACCT_NO,DA.BANK_NO,DA.REG_AMT*100 REG_AMT,DA.IS_ACTIVE,(SELECT LNAME FROM PT_BANK_CODE WHERE BANK_CODE=DA.BANK_NO AND MSG_TYPE IN ('CNAPS', 'CNAPS1')) BANK_NAME, DA.BRANCH_NO BRC_NO,(SELECT LNAME FROM PT_BANK_CODE WHERE BANK_CODE=DA.BRANCH_NO AND MSG_TYPE IN ('CNAPS', 'CNAPS1')) BRC_NAME FROM DTB_ACCT DA WHERE EBUSER_NO='1' AND CTP_ID='1' AND ACCT_TP !='0' ;
SELECT DA.ACCT_NO,DA.IS_ACTIVE,CI.CIF_NO FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CI ON DA.EBUSER_NO=CI.EBUSER_NO AND DA.CTP_ID=CI.CTP_ID WHERE DA.EBUSER_NO='1' AND DA.CTP_ID='1' AND DA.ACCT_TP='0' ;
SELECT DA.ACCT_NO, DA.OPEN_ORG, DA.ACCT_NAME, DA.ACCT_TP ACCT_TYP, DA.IS_ACTIVE, CUI.EBUSER_TYP, DA.CUST_ROLE, CUI.MOBILE FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CUI ON CUI.EBUSER_NO = DA.EBUSER_NO WHERE DA.EBUSER_NO = '1' AND DA.ACCT_TP = '1' ;
