SELECT DRT.CTP_SEQ_NO ORDER_NO,DRT.OPER_TYPE,TRAN_STATE, CASE WHEN DRT.OPER_TYPE='0' THEN PC1.CODE_NAME WHEN DRT.OPER_TYPE = '1'THEN PC2.CODE_NAME END AS TRAN_STATE_DESC FROM DTB_ROLL_TR DRT LEFT JOIN PARM_CODE PC1 ON PC1.CODE_TYPE='CTP_STAT_IN' AND PC1.CODE_NO=DRT.TRAN_STATE LEFT JOIN PARM_CODE PC2 ON PC2.CODE_TYPE='CTP_STAT_OUT'AND PC2.CODE_NO=DRT.TRAN_STATE WHERE 1=1 AND DRT.CTP_SEQ_NO = (SELECT CTP_SEQ FROM CTP_TRANS_ORDER_INFO WHERE ORDER_NO='1') AND CTP_ID = '1' ORDER BY REPLACE(DRT.TRAN_DATE,'-','')||REPLACE(DRT.TRAN_TIME,':','') DESC ;
