SELECT * FROM (SELECT CRR.CHAN_TYPE,CRR.RES_TYPE,PN.ID,PN.CATG_CODE,PN.TITLE,PN.CONTENT PNCONTENT,PN.USE_TIME STARDATE,PN.EXPIRE_TIME ENDDATE, CASE WHEN TO_DATE(PN.USE_TIME,'YYYY-MM-DD')<=SYSDATE AND TO_DATE(PN.EXPIRE_TIME,'YYYY-MM-DD')+1>=SYSDATE THEN '1' ELSE '0' END IS_USERFUL FROM PUB_NOTICE PN LEFT JOIN CHAN_RESOURCE_REL CRR ON PN.ID = CRR.ID AND CRR.RES_TYPE='C' WHERE CRR.CHAN_TYPE ='1' ) US WHERE US.IS_USERFUL='1' ORDER BY US.STARDATE DESC ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, CASE A.CUST_ROLE WHEN '0' THEN '投资人' WHEN '1' THEN '借款人' WHEN '2' THEN '担保人' END CUST_ROLE, CASE A.IS_CANCEL WHEN '0' THEN '正常' WHEN '1' THEN '注销' END IS_CANCEL, B.CANCEL_DATE, B.CANCEL_TIME, C.SUB_ACCT_NO, C.SUB_ACCT_NO_SECOND, ROW_NUMBER() OVER(ORDER BY A.OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP = '0' LEFT JOIN DTB_ACCT_EXTEND C ON A.EBUSER_NO=C.EBUSER_NO WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND B.CUST_ROLE = '1' AND A.CUST_NAME LIKE '%'||'1'||'%' AND A.EBUSER_TYP = '1' AND A.ID_NO LIKE '%'||'1'||'%' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, CASE A.CUST_ROLE WHEN '0' THEN '投资人' WHEN '1' THEN '借款人' WHEN '2' THEN '担保人' END CUST_ROLE, CASE A.IS_CANCEL WHEN '0' THEN '正常' WHEN '1' THEN '注销' END IS_CANCEL, B.CANCEL_DATE, B.CANCEL_TIME, C.SUB_ACCT_NO, C.SUB_ACCT_NO_SECOND, ROW_NUMBER() OVER(ORDER BY A.OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') LEFT JOIN DTB_ACCT_EXTEND C ON A.EBUSER_NO=C.EBUSER_NO WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND A.CUST_NAME LIKE '%'||'1'||'%' AND A.EBUSER_TYP = '1' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, CASE A.CUST_ROLE WHEN '0' THEN '投资人' WHEN '1' THEN '借款人' WHEN '2' THEN '担保人' END CUST_ROLE, CASE A.IS_CANCEL WHEN '0' THEN '正常' WHEN '1' THEN '注销' END IS_CANCEL, B.CANCEL_DATE, B.CANCEL_TIME, C.SUB_ACCT_NO, C.SUB_ACCT_NO_SECOND, ROW_NUMBER() OVER(ORDER BY A.OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') LEFT JOIN DTB_ACCT_EXTEND C ON A.EBUSER_NO=C.EBUSER_NO WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND A.EBUSER_TYP = '1' AND A.ID_NO LIKE '%'||'1'||'%' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_ID, A.CUST_NAME, A.CUST_ENAME, A.OPEN_DATE, A.OPEN_TIME, A.MOBILE, A.ID_TYP, A.ID_NO, A.OPEN_TELLER, A.CTP_NICK_NAME, A.CTP_LOGIN_NAME, A.COMP_ORG_NO, A.COMP_LICEN, A.COMP_ADD, A.COMP_ZIPCODE, A.COMP_EMAIL, A.COMP_FAX, A.LEGAL_IDT, A.LEGAL_IDT_NO, A.LEGAL_PHONE_NO, A.LEGAL_ADD, A.USER_STAT, A.EBUSER_NO, A.EBUSER_TYP, B.ACCT_NO, B.IS_ACTIVE, B.IS_SIGN_MOBILE, B.HANG_DATE, B.REG_AMT, B.BANK_NO, B.BANK_NAME, B.IS_DK, A.LEGAL_NAME, CASE A.CUST_ROLE WHEN '0' THEN '投资人' WHEN '1' THEN '借款人' WHEN '2' THEN '担保人' END CUST_ROLE, CASE A.IS_CANCEL WHEN '0' THEN '正常' WHEN '1' THEN '注销' END IS_CANCEL, B.CANCEL_DATE, B.CANCEL_TIME, C.SUB_ACCT_NO, C.SUB_ACCT_NO_SECOND, ROW_NUMBER() OVER(ORDER BY A.OPEN_DATE DESC) AS RN FROM CTP_USER_INFO A LEFT JOIN DTB_ACCT B ON A.EBUSER_NO=B.EBUSER_NO AND B.ACCT_TP in ('1','2','3') LEFT JOIN DTB_ACCT_EXTEND C ON A.EBUSER_NO=C.EBUSER_NO WHERE A.CTP_ID = '1' AND A.USER_STAT='N' AND A.EBUSER_TYP = '1' ORDER BY A.OPEN_DATE DESC,A.EBUSER_NO DESC  ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_TRAN_SEQ CTP_SEQ, A.UNI_NO, A.COMP_NAME, A.ID_TYP, A.ID_NO, A.EACCT_NO, A.SYNZ_URL, A.IS_SYNZ, A.SYNZ_RATE, A.COMP_PHONE, A.COMP_LICEN, A.IRS_REGIST, A.LAND_TAX_REGIST, A.APP_NO, A.LEGAL_NAME, A.LEGAL_ID_TYP, A.LEGAL_ID_NO, A.LEGAL_PHONE, A.AUDIT_OPINION, ROW_NUMBER() OVER(ORDER BY A.SUBMIT_DATE DESC,A.SUBMIT_TIME DESC) AS RN FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN CTP_INFO C ON A.CTP_ID=C.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' AND A.COMP_NAME LIKE '%'||'1'||'%' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_TRAN_SEQ CTP_SEQ, A.UNI_NO, A.COMP_NAME, A.ID_TYP, A.ID_NO, A.EACCT_NO, A.SYNZ_URL, A.IS_SYNZ, A.SYNZ_RATE, A.COMP_PHONE, A.COMP_LICEN, A.IRS_REGIST, A.LAND_TAX_REGIST, A.APP_NO, A.LEGAL_NAME, A.LEGAL_ID_TYP, A.LEGAL_ID_NO, A.LEGAL_PHONE, A.AUDIT_OPINION, ROW_NUMBER() OVER(ORDER BY A.SUBMIT_DATE DESC,A.SUBMIT_TIME DESC) AS RN FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN CTP_INFO C ON A.CTP_ID=C.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' AND A.CTP_TRAN_SEQ LIKE '%'||'1'||'%' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.CTP_TRAN_SEQ CTP_SEQ, A.UNI_NO, A.COMP_NAME, A.ID_TYP, A.ID_NO, A.EACCT_NO, A.SYNZ_URL, A.IS_SYNZ, A.SYNZ_RATE, A.COMP_PHONE, A.COMP_LICEN, A.IRS_REGIST, A.LAND_TAX_REGIST, A.APP_NO, A.LEGAL_NAME, A.LEGAL_ID_TYP, A.LEGAL_ID_NO, A.LEGAL_PHONE, A.AUDIT_OPINION, ROW_NUMBER() OVER(ORDER BY A.SUBMIT_DATE DESC,A.SUBMIT_TIME DESC) AS RN FROM CTP_COMP_QUAIL_INFO A LEFT JOIN DTB_ACCT B ON A.EACCT_NO = B.ACCT_NO LEFT JOIN CTP_INFO C ON A.CTP_ID=C.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.PRO_ID, A.PRO_NAME, A.PRO_TYP, A.PRO_AMT, A.RISK_LEV, A.PRO_DESC, CASE A.STAT WHEN '1' THEN '添加待确认' WHEN '2' THEN '已拒绝' WHEN '3' THEN '投标中' WHEN '4' THEN '已满标' WHEN '5' THEN '定标已受理' WHEN '6' THEN '已定标' WHEN '7' THEN '流标已受理' WHEN '8' THEN '已流标' WHEN '9' THEN '还款中' WHEN '10' THEN '兑付中' WHEN '11' THEN '已兑付' WHEN '31' THEN '待上架' WHEN '52' THEN '定标成功,打款失败' END STAT, A.CRE_DATE, A.CRE_TIME, A.STAR_BUY_TIME, A.END_BUY_TIME, A.STAR_DATE, A.END_DATE, A.PRO_TERM, A.EXPINC_RATE, A.MJ_NAME, A.MJ_ID_TYP, A.MJ_ID_NO, CASE A.HK_FLAG WHEN '0' THEN '止付' WHEN '1' THEN '直接划款' END HK_FLAG, CASE A.ZR_FLAG WHEN '0' THEN '否' WHEN '1' THEN '是' END ZR_FLAG, CASE A.DC_FLAG WHEN '0' THEN '否' WHEN '1' THEN '是' END DC_FLAG, CASE A.IS_DC_FLAG WHEN '0' THEN '未代偿' WHEN '1' THEN '已代偿' END IS_DC_FLAG, A.DC_AMT, A.DF_DATE, A.DF_TIME, A.BUY_ACCT, A.BUY_NAME, A.DF_ACCT, A.DF_NAME, A.FX_PER_TOP, A.TOT_FX_AMT, A.FEE_PER_TOP, A.AGREE_NO, CASE A.DB_FLAG WHEN '0' THEN '满标可定' WHEN '1' THEN '非满标可定' ELSE '未知' END DB_FLAG, A.LEFT_AMT, A.TOT_NUM, A.CONF_SEQ, CASE A.CONF_STAT WHEN '1' THEN '定标成功' WHEN '2' THEN '定标失败' WHEN '3' THEN '流标成功' WHEN '4' THEN '流标失败' END CONF_STAT, A.DF_SEQ, CASE A.DF_STAT WHEN '1' THEN '还款成功' WHEN '2' THEN '还款失败' WHEN '3' THEN '兑付成功' WHEN '4' THEN '兑付失败' END DF_STAT, A.FEE_ACCT1, A.FEE_NAME1, A.FEE_AMT1, A.FEE_ACCT2, A.FEE_NAME2, A.FEE_AMT2, A.FEE_ACCT3, A.FEE_NAME3, A.FEE_AMT3, A.ZR_FEE_ACCT, A.HK_AMT, A.PRO_MIN_AMT, A.DB_AMT, A.CTP_S_TIME, A.CTP_F_TIME, A.CTP_REPAY_TIME, A.CTP_CASH_TIME, A.IS_DATA_TRANS, A.ERR_MSG, CASE A.IS_AUTO_BID WHEN '0' THEN '否' WHEN '1' THEN '是' END IS_AUTO_BID, A.TOT_FEE, A.AUTO_REPAY_COUNT, A.AUTO_REPAY_QUOTA, A.AUTO_REPAY_END_DATE, A.HK_CORPUS, A.HK_ACCRUAL, ROW_NUMBER() OVER(ORDER BY CRE_DATE DESC,CRE_TIME DESC) AS RN FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' AND TO_DATE(A.CRE_DATE,'YYYY-MM-DD')>=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TO_DATE(A.CRE_DATE,'YYYY-MM-DD')<=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD')+1 ORDER BY A.PRO_ID ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.PRO_ID, A.PRO_NAME, A.PRO_TYP, A.PRO_AMT, A.RISK_LEV, A.PRO_DESC, CASE A.STAT WHEN '1' THEN '添加待确认' WHEN '2' THEN '已拒绝' WHEN '3' THEN '投标中' WHEN '4' THEN '已满标' WHEN '5' THEN '定标已受理' WHEN '6' THEN '已定标' WHEN '7' THEN '流标已受理' WHEN '8' THEN '已流标' WHEN '9' THEN '还款中' WHEN '10' THEN '兑付中' WHEN '11' THEN '已兑付' WHEN '31' THEN '待上架' WHEN '52' THEN '定标成功,打款失败' END STAT, A.CRE_DATE, A.CRE_TIME, A.STAR_BUY_TIME, A.END_BUY_TIME, A.STAR_DATE, A.END_DATE, A.PRO_TERM, A.EXPINC_RATE, A.MJ_NAME, A.MJ_ID_TYP, A.MJ_ID_NO, CASE A.HK_FLAG WHEN '0' THEN '止付' WHEN '1' THEN '直接划款' END HK_FLAG, CASE A.ZR_FLAG WHEN '0' THEN '否' WHEN '1' THEN '是' END ZR_FLAG, CASE A.DC_FLAG WHEN '0' THEN '否' WHEN '1' THEN '是' END DC_FLAG, CASE A.IS_DC_FLAG WHEN '0' THEN '未代偿' WHEN '1' THEN '已代偿' END IS_DC_FLAG, A.DC_AMT, A.DF_DATE, A.DF_TIME, A.BUY_ACCT, A.BUY_NAME, A.DF_ACCT, A.DF_NAME, A.FX_PER_TOP, A.TOT_FX_AMT, A.FEE_PER_TOP, A.AGREE_NO, CASE A.DB_FLAG WHEN '0' THEN '满标可定' WHEN '1' THEN '非满标可定' ELSE '未知' END DB_FLAG, A.LEFT_AMT, A.TOT_NUM, A.CONF_SEQ, CASE A.CONF_STAT WHEN '1' THEN '定标成功' WHEN '2' THEN '定标失败' WHEN '3' THEN '流标成功' WHEN '4' THEN '流标失败' END CONF_STAT, A.DF_SEQ, CASE A.DF_STAT WHEN '1' THEN '还款成功' WHEN '2' THEN '还款失败' WHEN '3' THEN '兑付成功' WHEN '4' THEN '兑付失败' END DF_STAT, A.FEE_ACCT1, A.FEE_NAME1, A.FEE_AMT1, A.FEE_ACCT2, A.FEE_NAME2, A.FEE_AMT2, A.FEE_ACCT3, A.FEE_NAME3, A.FEE_AMT3, A.ZR_FEE_ACCT, A.HK_AMT, A.PRO_MIN_AMT, A.DB_AMT, A.CTP_S_TIME, A.CTP_F_TIME, A.CTP_REPAY_TIME, A.CTP_CASH_TIME, A.IS_DATA_TRANS, A.ERR_MSG, CASE A.IS_AUTO_BID WHEN '0' THEN '否' WHEN '1' THEN '是' END IS_AUTO_BID, A.TOT_FEE, A.AUTO_REPAY_COUNT, A.AUTO_REPAY_QUOTA, A.AUTO_REPAY_END_DATE, A.HK_CORPUS, A.HK_ACCRUAL, ROW_NUMBER() OVER(ORDER BY CRE_DATE DESC,CRE_TIME DESC) AS RN FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' ORDER BY A.PRO_ID ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.*, ROW_NUMBER() OVER(ORDER BY CTP_ACCT) AS RN FROM CTP_ACCT A WHERE CTP_ID = '1' AND ACCT_STATE='N' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT A.* , ROW_NUMBER() OVER(ORDER BY TRANS_SEQ DESC) AS RN FROM CTP_CHECK_MSG A where STAT = '0' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT B.CTP_NAME, A.CTP_TRAN_SEQ CTP_SEQ, A.UNI_NO, A.COMP_NAME, A.SUBMIT_DATE CRE_DATE, A.UNI_STAT, A.SYNZ_URL, A.IS_SYNZ, A.SYNZ_RATE, A.COMP_LICEN, A.IRS_REGIST, A.LAND_TAX_REGIST, A.APP_NO, A.ID_TYP, A.ID_NO, A.COMP_PHONE, A.LEGAL_NAME, A.LEGAL_ID_TYP, A.LEGAL_ID_NO, A.LEGAL_PHONE, A.AUDIT_OPINION, ROW_NUMBER() OVER(ORDER BY A.SUBMIT_DATE DESC,A.SUBMIT_TIME DESC) AS RN FROM CTP_COMP_QUAIL_INFO A LEFT JOIN CTP_INFO B ON A.CTP_ID=B.CTP_ID WHERE A.CTP_ID ='1' AND A.IS_SYNZ='N' AND A.SYNZ_RATE='3' AND A.SUBMIT_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT CPCT.BID_SEQ_NO, CPCT.PRO_ID, CUI.CUST_NAME, CUI.ID_NO, CUI.ID_TYP, CASE WHEN CPCT.BID_STAT = '0' THEN '正常' WHEN CPCT.BID_STAT = '1' THEN '已转让' WHEN CPCT.BID_STAT = '2' THEN '已兑付' WHEN CPCT.BID_STAT = '4' THEN '部分转让' WHEN CPCT.BID_STAT = '5' THEN '已定标' WHEN CPCT.BID_STAT = '6' THEN '作废' WHEN CPCT.BID_STAT = '7' THEN '已流标' WHEN CPCT.BID_STAT = '8' THEN '撤销已受理' WHEN CPCT.BID_STAT = '9' THEN '撤消成功' WHEN CPCT.BID_STAT = '10' THEN '撤销失败' ELSE CPCT.BID_STAT END AS BID_STAT_NAME, CASE WHEN CPCT.DF_STAT = '12' THEN '还款失败' WHEN CPCT.DF_STAT = '22' THEN '兑付失败' ELSE CPCT.DF_STAT END AS DF_STAT_NAME, NVL(CPCT.HK_AMT ,0) HK_AMT, ROW_NUMBER() OVER(ORDER BY CPCT.TRANS_SEQ DESC) AS RN FROM CTP_PP_CONFIRM_TR CPCT JOIN CTP_USER_INFO CUI ON CPCT.BIDER_NO = CUI.EBUSER_NO WHERE CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' AND (CPCT.DF_STAT = '12' OR CPCT.DF_STAT = '22') ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT CTP_ACCT,CTP_ACCT_NAME,BANKNAME,TAKE_PRE_NO,STATUS,ROW_NUMBER() OVER(ORDER BY PRE_NO DESC) AS RN FROM CTP_ACCT WHERE CTP_ID='1' AND ACCT_STATE='N' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT CTP_ACCT,CTP_ACCT_NAME,REBATE_ACCT_NAME,REBATE_ACCT_NO,REBATE_TYPE,PRO_ID,STAT,ROW_NUMBER() OVER(ORDER BY PRO_ID DESC) AS RN FROM CTP_REBATE_SIGN_INFO WHERE CTP_ID='1' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT DA.ACCT_NO, DA.ACC_ALIAS, DA.ACCT_NAME, DA.HANG_DATE, DA.HANG_ORG, DA.HANG_TELER, DA.HANG_CHAN, DA.IS_ACTIVE, DA.IS_SIGN_MOBILE, DA.ACCT_TP, DA.HANG_TIME, DA.BANK_NAME, CASE DA.CUST_ROLE WHEN '0' THEN '投资人' WHEN '1' THEN '借款人' WHEN '2' THEN '担保人' END CUST_ROLE, CASE DA.IS_CANCEL WHEN '0' THEN '正常' WHEN '1' THEN '注销' END IS_CANCEL, DA.CANCEL_DATE, DA.CANCEL_TIME, ROW_NUMBER() OVER(ORDER BY HANG_DATE DESC) AS RN FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CUI ON DA.EBUSER_NO = CUI.EBUSER_NO WHERE CUI.EBUSER_TYP = '1' and DA.CTP_ID='1' AND DA.ACCT_TP='1' AND DA.ACCT_NAME LIKE '%'||'1'||'%' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT DA.ACCT_NO, DA.ACC_ALIAS, DA.ACCT_NAME, DA.HANG_DATE, DA.HANG_ORG, DA.HANG_TELER, DA.HANG_CHAN, DA.IS_ACTIVE, DA.IS_SIGN_MOBILE, DA.ACCT_TP, DA.HANG_TIME, DA.BANK_NAME, CASE DA.CUST_ROLE WHEN '0' THEN '投资人' WHEN '1' THEN '借款人' WHEN '2' THEN '担保人' END CUST_ROLE, CASE DA.IS_CANCEL WHEN '0' THEN '正常' WHEN '1' THEN '注销' END IS_CANCEL, DA.CANCEL_DATE, DA.CANCEL_TIME, ROW_NUMBER() OVER(ORDER BY HANG_DATE DESC) AS RN FROM DTB_ACCT DA LEFT JOIN CTP_USER_INFO CUI ON DA.EBUSER_NO = CUI.EBUSER_NO WHERE CUI.EBUSER_TYP = '1' and DA.CTP_ID='1' AND DA.ACCT_TP='1' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY DB.TRAN_DATE DESC,DB.TRAN_TIME DESC) AS RN, DB.*,DUL.UPAY_MSG,PI.PASS_NAME AS CODE_NAME FROM DTB_ROLL_TR DB LEFT JOIN PASS_INF PI ON PI.PASS_TYPE = DB.TRANS_CHAN_TYPE LEFT JOIN DTB_UPAY_LIST DUL ON DB.TRAN_SEQ=DUL.TRAN_SEQ WHERE 1=1 AND TO_DATE(DB.TRAN_DATE, 'YYYY-MM-DD')=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND DB.CTP_ID = '1' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_DATE DESC, TRAN_TIME DESC) AS RN, SEQ_NO, STAT, ID_TYP, ID_NO, ID_NAME, ACCT_NO, ACCT_NAME, REAL_AMT, TRAN_DATE, TRAN_TIME, COMPLE_DATE, COMPLE_TIME, HOST_CODE, HOST_MSG FROM CTP_BATCH_REBATE_TR WHERE 1=1 AND CTP_ID = '1' AND CTP_SEQ = '1' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_DATE DESC, TRAN_TIME DESC) AS RN, TRAN_SEQ, CTP_SEQ, STAT, ACCT_NO, ACCT_NAME, TRAN_AMT, TOT_NUM, SUCC_NUM, SUCC_AMT, FAIL_NUM, FAIL_AMT, TRAN_DATE, TRAN_TIME, COMPLE_DATE, COMPLE_TIME, HOST_CODE, HOST_MSG FROM CTP_BATCH_TR WHERE 1=1 AND CTP_ID = '1' AND ACCT_NO='1' AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')>=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')<=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TRAN_TYPE = '6' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_DATE DESC, TRAN_TIME DESC) AS RN, TRAN_SEQ, CTP_SEQ, STAT, ACCT_NO, ACCT_NAME, TRAN_AMT, TOT_NUM, SUCC_NUM, SUCC_AMT, FAIL_NUM, FAIL_AMT, TRAN_DATE, TRAN_TIME, COMPLE_DATE, COMPLE_TIME, HOST_CODE, HOST_MSG FROM CTP_BATCH_TR WHERE 1=1 AND CTP_ID = '1' AND CTP_SEQ='1' AND TRAN_TYPE = '6' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY TRAN_SEQ DESC) AS RN, TRAN_SEQ, CTP_SEQ, TRAN_STAT STAT, PAY_ACCT ACCT_NO, PAY_NAME ACCT_NAME, TRAN_AMT, TRAN_DATE, TRAN_TIME FROM CTP_TRANS_UN_TR WHERE 1=1 AND CTP_ID = '1' AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')>=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') AND TO_DATE(TRAN_DATE, 'YYYY-MM-DD')<=TO_DATE(TO_CHAR(SYSDATE, 'YYYY-MM-DD'), 'YYYY-MM-DD') ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT ROWNUM RN,TT.* FROM ( SELECT ROW_NUMBER() OVER(ORDER BY T.PRO_ID DESC) AS RN_IN,T.* FROM( SELECT CPI.PRO_TYP, CPI.PRO_ID, CPI.PRO_NAME, CPI.PRO_AMT, CPI.RISK_LEV, CPI.PRO_DESC, CPI.STAR_BUY_TIME, CPI.END_BUY_TIME, CPI.STAR_DATE, CPI.PRO_TERM, CPI.EXPINC_RATE, CPI.END_DATE, CPI.MJ_NAME ID_NAME, CPI.MJ_ID_TYP ID_TYP, CPI.MJ_ID_NO ID_NO, CPI.ZR_FLAG, CPI.DC_FLAG, CPI.STAT, CPIV.RCV_ID_TYP1, CPIV.RCV_ID_NO1, CPIV.RCV_NAME1, CPIV.RCV_ID_TYP2, CPIV.RCV_ID_NO2, CPIV.RCV_NAME2, CPIV.RCV_ID_TYP3, CPIV.RCV_ID_NO3, CPIV.RCV_NAME3, CPIV.RCV_ID_TYP4, CPIV.RCV_ID_NO4, CPIV.RCV_NAME4, CPI.PRO_MIN_AMT, CUI.CUST_ROLE, CPI.BUY_ACCT, CPI.BUY_NAME BUY_ACCT_NAME, CPI.DF_ACCT, CPI.DF_NAME DF_ACCT_NAME, CPI.TOT_FEE, CPI.AUTO_REPAY_COUNT, CPI.AUTO_REPAY_QUOTA, CPI.AUTO_REPAY_END_DATE, CPI.HK_CORPUS, CPI.HK_ACCRUAL, CPI.HK_AMT FROM CTP_PP_INFO CPI LEFT JOIN CTP_PP_INFO_RECV CPIV ON CPIV.PRO_ID=CPI.PRO_ID LEFT JOIN CTP_USER_INFO CUI ON CPI.MJ_NO = CUI.EBUSER_NO WHERE CPI.CTP_ID='1' AND CPI.PRO_TYP='1' AND CPI.PRO_ID='1' ) T ) TT ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT * FROM ( SELECT ROW_.* FROM ( SELECT TRAN_SEQ, TRADE_CODE, TRADE_NAME,  OPER_NAME, TRADE_AMT, TRADE_NO, TRADE_CON, REVIEW_NO, TRANS_SEQ, ROW_NUMBER() OVER(ORDER BY TRADE_DATE DESC,TRADE_TIME DESC) AS RN FROM CTP_MER_AUTH_DATA WHERE REV_RESULT = '2' AND CTP_ID = '1' AND SUM_MER_ID <> '1' ) ROW_ WHERE RN <= '1' ) WHERE RN > '1' ;
SELECT ID_NO,ID_NAME,ID_TYP,ELE_ACCT_NO,MOBILE_NO,SYNZ_URL,BACK_URL,CTP_SEQ,CUST_ROLE,ACCT_NO,EBUSER_TYP, CASE WHEN ID_TYP='01' THEN '身份证' WHEN ID_TYP='02' THEN '户口本' WHEN ID_TYP='03' THEN '军官证' WHEN ID_TYP='05' THEN '护照' WHEN ID_TYP='06' THEN '营业执照' WHEN ID_TYP='07' THEN '开户许可证' WHEN ID_TYP='08' THEN '税务登记证' WHEN ID_TYP='09' THEN '纳税人编码' WHEN ID_TYP='20' THEN '港澳居民来往内地通行证' WHEN ID_TYP='21' THEN '台湾居民来往大陆通行证' WHEN ID_TYP='22' THEN '临时身份证' WHEN ID_TYP='23' THEN '武警证' WHEN ID_TYP='24' THEN '外国人永久居留证' WHEN ID_TYP='25' THEN '边民出入通行证' WHEN ID_TYP='26' THEN '外国护照' END AS ID_TYP_CNY, CASE WHEN IS_ACTIVE_STAT IN ('F','Y') THEN '0' ELSE IS_ACTIVE_STAT END AS ORDER_STAT FROM CTP_BATCH_ACTIVE_TR WHERE TRANS_SEQ='1' AND CTP_ID='1' ;
SELECT IS_MOBILE,MOBILE FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT IS_MOBILE,MOBILE,MOBILE_TYP FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT IS_RANDOM,CHECK_TYPE FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT IS_RANDOM FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT IS_SIGN_MOBILE FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT LGN_ID_TYP OPER_ID_TYP, LGN_ID_NO OPER_ID_NO, OPER_NAME, OPER_STAT, OPER_MOBILE, LAST_LGN_TIME FROM CTP_OPERATOR WHERE CTP_ID = '1' AND OPER_ID = '1' ;
SELECT MA.* FROM MARKET_ACTIVITY MA LEFT JOIN CHAN_RESOURCE_REL CRR ON MA.ACTIVITY_ID = CRR.ID WHERE CRR.CHAN_TYPE ='1' AND MA.STATE ='0' AND TO_DATE(MA.BEGIN_TIME,'YYYY-MM-DD')<=SYSDATE AND TO_DATE(MA.END_TIME,'YYYY-MM-DD')+1>=SYSDATE AND CRR.RES_TYPE='1' ORDER BY MA.ORDER_INDEX ASC ;
SELECT MAX(CANCEL_COUNT) FROM CTP_USER_INFO WHERE CTP_ID='1' AND ID_NO='1' AND ID_TYP='1' AND CUST_ROLE='1' AND CUST_NAME='1' ;
SELECT NVL(B.ORI_CTP_SEQ,B.CTP_SEQ_NO) CTP_SEQ, 'ctpTransIn' TRANS_CODE, NVL(CTOI.CTP_DATE,CTOI.CRE_DATE) CTP_DATE, B.OPER_TYPE, C.ID_TYP, C.ID_NO, C.CUST_NAME ID_NAME, B.ACCT_NO ELE_ACCT_NO, B.CARD_NO ACCT_NO, TO_CHAR(B.OPER_AMT*100) OPER_AMT, TO_CHAR(B.TRAN_FEE*100) TRAN_FEE, C.CUST_ROLE FROM DTB_ROLL_TR B JOIN CTP_USER_INFO C ON B.EBUSER_NO=C.EBUSER_NO LEFT JOIN CTP_TRANS_ORDER_INFO CTOI ON B.CTP_ID = CTOI.CTP_ID AND B.CTP_SEQ_NO = CTOI.CTP_SEQ WHERE 1=1 AND B.TRAN_STATE = '6' AND B.OPER_TYPE = '0' AND CTOI.CTP_DATE <= '1' AND CTOI.UPD_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND B.CTP_ID = '1' ;
SELECT NVL(SUM(NVL(REAL_AMT,0)),0) TOT_HK_AMT,NVL(SUM(NVL(CORPUS,0)),0) TOT_HK_CORPUS,NVL(SUM(NVL(ACCRUAL,0)),0) TOT_HK_ACCRUAL FROM CTP_BATCH_REPAY_TR WHERE CTP_ID = '1' AND CTP_SEQ = '1' AND PRO_ID = '1' AND STAT = '0' AND FEE_FLAG = '2' ;
SELECT NVL(SUM(TRAN_AMT),0) FROM CTP_PP_RETURN_TR WHERE CTP_ID='1' AND PRO_ID='1' AND FEE_TYP='CA' AND TRAN_STAT ='0' ;
SELECT ONCE_LIMIT ONCE_LMT, DAY_LIMIT DAY_LMT FROM BANK_LIMIT_DEF WHERE BANK_LIMIT_TY = 'C' ;
SELECT ONCE_LMT,DAY_LMT FROM CTP_ACCT_LMT_CT WHERE CTP_ID = '1' AND ACCT_NO = '1' AND STAT = '0' ;
SELECT OPEN_NAME FROM CTP_INFO WHERE CTP_ID='1' ;
SELECT OPER_NAME FROM ctp_operator WHERE CTP_ID='1' AND OPER_ID='1' ;
SELECT OPER_TYPE,SUM(TOTAL_FEE) TOTAL_FEE,ORDER_DATE,CHAN_TYP,GG_BRANCH_NO FROM DTB_BUSINESS_FEE WHERE REC_ACCT = '1' AND TRANS_FLAG = '0' GROUP BY OPER_TYPE,ORDER_DATE,CHAN_TYP,GG_BRANCH_NO ORDER BY ORDER_DATE DESC ;
SELECT ORDER_NO FROM CTP_TRANS_ORDER_INFO WHERE CTP_ID = '1' AND ORDER_NO = '1' ;
SELECT ORG_NO FROM CTP_COMP_QUAIL_INFO WHERE UNI_NO='1' AND CTP_ID='1' ;
SELECT PARAM_TYPE,PARAM_VALUE FROM SYS_FILTER_PARAM ORDER BY SORT ;
SELECT PASS_TYPE,CHECK_DATE FROM CTP_CHEAR_INFO WHERE CHECK_STATE='2' AND CLEAR_STATE = '0' ;
SELECT PASS_TYPE,PASS_NAME FROM PASS_INF ;
