SELECT PASS_URL,CHECK_TYPE, FEE_OUT_AMT FEE_COST FROM PASS_INF WHERE PASS_TYPE='1' ;
SELECT PAY_TYPE,ACCOUNT_NO FROM CTP_TRANS_CONF WHERE TRANS_CODE = '1' AND FEE_TYPE = '1' AND CTP_ID = '1' ;
SELECT PCA.CUST_ROLE, PCA.ID_NAME, PCA.ID_NO, PCA.MOBILE, PCA.CTP_LOGIN_NAME, PCA.CTP_NICK_NAME, PCA.CCY_TYPE, PCA.ACC_ALIAS, PCA.CUST_ENAME, PCA.ID_TYP, PCA.EBUSER_TYP, PCA.OPEN_TELLER, PCA.SERIAL_NO, PCA.CHK_CODE, PCA.SYNZ_URL, PCA.TRAN_DATE, PCA.TRAN_TIME, PCA.CTP_ID, PCA.BACK_URL, PCA.STAT, PCA.TRANS_SEQ, PBC.DC_FLAG, PBC.CTP_SEND_FEE, PBC.AUTO_REPAY_COUNT, PBC.AUTO_REPAY_QUOTA, PBC.AUTO_REPAY_END_DATE, CASE WHEN ID_TYP = '01' THEN '身份证' WHEN ID_TYP = '02' THEN '户口本' WHEN ID_TYP = '03' THEN '军官证' WHEN ID_TYP = '05' THEN '护照' WHEN ID_TYP = '20' THEN '港澳居民来往内地通行证' WHEN ID_TYP = '21' THEN '台湾居民来往大陆通行证' WHEN ID_TYP = '22' THEN '临时身份证' WHEN ID_TYP = '23' THEN '武警证' WHEN ID_TYP = '24' THEN '外国人永久居留证' WHEN ID_TYP = '25' THEN '边民出入通行证' WHEN ID_TYP = '26' THEN '外国护照' END AS ID_TYP_CNY, CASE WHEN STAT IN ('0', '2') THEN '0' ELSE STAT END AS ORDER_STAT FROM PER_CUST_ACCOUNT_APPLY PCA, PER_BORR_CUST_ACCOUNT_INFO PBC WHERE PCA.TRAN_SEQ = '1' AND PCA.CTP_ID = '1' AND PCA.CTP_ID = PBC.CTP_ID AND PCA.TRAN_SEQ = PBC.TRAN_SEQ ;
SELECT PI.PASS_URL,BEI.* FROM BANK_EXT_INF BEI LEFT JOIN PASS_INF PI ON BEI.CERTIFY_PASS_TYPE=PI.PASS_TYPE WHERE BEI.BANK_CODE='1' AND BEI.CTP_ID='1' ;
SELECT PMT.PROMPT_TYPE, PMT.PROMPT_TRANS_CODE, PMT.PROMPT_HOST_TRANS_CODE, PMT.PROMPT_MSG_CODE, PMT.PROMPT_PREVIOUS_MSG_VALUE, PMT.PROMPT_MSG_VALUE FROM PROMPT_MSG_TRANSLATE PMT ;
SELECT PPZR.TRANS_SEQ, PPZR.CTP_ID, PPZR.CTP_SEQ, PPZR.PRO_ID, PPZR.ORI_BID_SEQ_NO, PPZR.BID_SEQ_NO, PPZR.ZR_EBUSER_NO, PPZR.ZR_ACCT, PPZR.ZR_NAME, PPZR.ZR_ID_TYP, PPZR.ZR_ID_NO, PPZR.BID_AMT, PPZR.TRAN_AMT, PPZR.ZR_DATE, PPZR.ZR_TIME, PPZR.ZR_TYP, PPZR.STAT, PPZR.BUY_EBUSER_NO, PPZR.BUY_ACCT, PPZR.BUY_NAME, PPZR.BUY_ID_TYP, PPZR.BUY_ID_NO, PPZR.BUY_ACCT, PPZR.BACK_URL, PPIF.PRO_NAME, PPIF.PRO_TYP, PPIF.END_DATE, PPIF.PRO_DESC FROM CTP_PP_ZR_ORDER_TR PPZR LEFT JOIN CTP_PP_INFO PPIF ON PPZR.PRO_ID=PPIF.PRO_ID WHERE PPZR.TRANS_SEQ='1' and PPZR.CTP_ID = '1' ;
SELECT PRO_ID FROM CTP_PP_INFO WHERE MJ_NO='1' AND STAT ='6' AND DF_STAT IN ('2','4') ;
SELECT REBATE_ACCT_NO FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT REBATE_ACCT_NO,REBATE_ACCT_NAME,PRO_ID FROM CTP_REBATE_SIGN_INFO WHERE CTP_ID = '1' AND CTP_ACCT='1' AND REBATE_TYPE='1' AND STAT='2' ;
SELECT REBATE_ACCT_NO,REBATE_ACCT_NAME,PRO_ID FROM CTP_REBATE_SIGN_INFO WHERE CTP_ID = '1' AND CTP_ACCT='1' AND REBATE_TYPE='1' AND STAT='2' AND CTP_ACCT_NAME = '1' ;
SELECT RECHARGE_SEQ.NEXTVAL FROM DUAL ;
SELECT REV_RESULT FROM CTP_MER_AUTH_DATA WHERE TRAN_SEQ='1' ;
SELECT ROW_NUMBER() OVER(ORDER BY A.HOST_SEQ) AS SEQ_NO, A.* FROM( SELECT CTT.PAY_ACCT,CTT.PAY_NAME, CTT.RCV_ACCT,CTT.RCV_NAME, TO_CHAR(CTT.TRAN_AMT*100) TRAN_AMT_FEN, CTT.TRAN_AMT, CTT.TRAN_HOST_NO HOST_SEQ,CTT.HOST_DATE, CTT.PAY_ACCT ACCT_NO,CTT.PAY_NAME ACCT_NAME, CPCT.CONF_SEQ CTP_DETAIL_SEQ,'3' JD_FLAG FROM CTP_TRANS_TR CTT LEFT JOIN CTP_PP_CONFIRM_TR CPCT ON CTT.TRAN_SEQ=CPCT.PAY_SEQ WHERE CPCT.BID_STAT='0' AND CPCT.CTP_ID = '1' AND CPCT.PRO_ID = '1' UNION ALL SELECT CBHT2.ACCT_NO,CBHT2.ACCT_NAME, CBT2.ACCT_NO RCV_ACCT,CBT2.ACCT_NAME RCV_NAME, TO_CHAR(CBHT2.TRAN_AMT*100) TRAN_AMT_FEN,CBHT2.TRAN_AMT, CBHT2.HOST_SEQ,CBHT2.HOST_DATE, CBHT2.ACCT_NO,CBHT2.ACCT_NAME, CPCT2.CONF_SEQ CTP_DETAIL_SEQ,'3' FROM CTP_BATCH_HOST_TR CBHT2 LEFT JOIN CTP_BATCH_TR CBT2 ON CBT2.TRAN_SEQ=CBHT2.TRAN_SEQ LEFT JOIN CTP_PP_CONFIRM_TR CPCT2 ON CPCT2.PAY_SEQ=CBHT2.TRAN_SEQ AND CPCT2.AUTO_SEQ = CBHT2.DETAIL_SEQ AND CPCT2.PRO_ID=CBHT2.PRO_ID AND CBT2.TRAN_TYPE='1' WHERE CPCT2.BID_STAT='0' AND CPCT2.CTP_ID = '1' AND CPCT2.PRO_ID = '1' ) A ;
SELECT SER_FEE_ACCT,SER_FEE_NAME,DF_ACCT,MIDDLE_ACCT_NO,MIDDLE_ACCT_NAME,OPEN_ORG FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT SER_FEE_ACCT, SER_FEE_NAME, MIDDLE_ACCT_NO, MIDDLE_ACCT_NAME FROM CTP_INFO WHERE CTP_ID = '1' ;
SELECT SMS_TEMP_CONT FROM SMS_TEMP WHERE SMS_TEMP_ID='1' ;
SELECT STAT,AGREE_NO FROM CTP_PP_AUTO_BID_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' ;
SELECT STAT,AGREE_NO FROM CTP_SUB_AUTO_BID_INFO WHERE CTP_ID = '1' AND SUB_ACCT_NO = '1' ;
SELECT STAT,AGREE_NO FROM CTP_SUB_AUTO_CREDIT_INFO WHERE CTP_ID = '1' AND SUB_ACCT_NO = '1' ;
SELECT STAT,AGREE_NO FROM CTP_SUB_AUTO_TRANSF_INFO WHERE CTP_ID = '1' AND SUB_ACCT_NO = '1' ;
SELECT STAT, DF_ACCT, DF_NAME, DF_SEQ, DF_STAT, DC_FLAG,MJ_NO, TOT_FEE,HK_CORPUS*100 HK_CORPUS,DB_AMT*100 DB_AMT,PRO_NAME FROM CTP_PP_INFO WHERE CTP_ID = '1' AND PRO_ID = '1' AND PRO_TYP = '1' ;
SELECT STATE FROM CTP_TRANS_ORDER_INFO WHERE CTP_SEQ='1' AND CTP_ID='1' ;
SELECT STAT FROM CTP_PP_INFO WHERE CTP_ID = '1' AND PRO_ID = '1' AND PRO_TYP = '1' ;
SELECT STAT FROM CTP_SUB_ACCT WHERE EBUSER_NO='1' AND ACCT_NO = '1' AND SUB_ACCT_NO = '1' AND CTP_ID = '1' ;
SELECT STAT,MAX_DATE FROM CTP_SUB_AUTO_CREDIT_INFO WHERE CTP_ID = '1' AND SUB_ACCT_NO = '1' ;
SELECT STAT,SUB_ACCT_NO,AMT FROM CTP_FINAN_PLAN_INFO WHERE CTP_ID = '1' AND EBUSER_NO = '1' AND PACKAGE_ID = '1' ;
SELECT STAT TRAN_STAT,RET_MSG TRAN_MSG from CTP_PP_ZR_TR WHERE CTP_SEQ='1' AND CTP_ID = '1' ;
SELECT STAT TRAN_STAT,TABLE_ID ,H_RSP_MSG TRAN_MSG FROM CTP_COMMON_TR WHERE CTP_SEQ = '1' AND TRANS_CODE='ctpP2pProjectAutoCreditTransf' AND CTP_ID = '1' ;
SELECT SUB_ACCT_NO,SUB_ACCT_NO_SECOND FROM DTB_ACCT_EXTEND WHERE EBUSER_NO = '1' AND CTP_ID = '1' AND IS_CANCEL = '0' ;
SELECT SUM(BID_AMT)*100 FROM ( SELECT BID_AMT FROM CTP_PP_CONFIRM_TR WHERE CTP_ID = '1' AND BIDER_NO = '1' AND BID_STAT IN ('0','5','8','10') UNION ALL SELECT PRO_AMT FROM CTP_PP_INFO WHERE CTP_ID = '1' AND MJ_NO = '1' AND STAT IN ('3','4','5','6','7','9','10','31') ) ;
SELECT SUM(BID_AMT) FROM CTP_PP_CONFIRM_TR CPI WHERE CTP_ID = '1' AND PRO_ID = '1' AND BID_STAT = '0' ;
SELECT SUM(CASE WHEN STAT='0' THEN REAL_AMT ELSE 0 END) SUCC_AMT FROM CTP_BATCH_REPAY_TR WHERE CTP_ID = '1' AND CTP_SEQ = '1' AND JD_FLAG = '3' ;
SELECT SUM(CASE WHEN STAT='0' THEN REAL_AMT ELSE 0 END) SUCC_AMT, SUM(CASE WHEN STAT='2' THEN REAL_AMT ELSE 0 END) FAIL_AMT, COUNT(CASE WHEN STAT='0' THEN 1 END) SUCC_NUM, COUNT(CASE WHEN STAT='2' THEN 1 END) FAIL_NUM FROM CTP_BATCH_REPAY_TR WHERE CTP_ID = '1' AND CTP_SEQ = '1' AND JD_FLAG = '4' ;
SELECT SUM(CBRT.REAL_AMT)*100 TOT_FEE,CBRT.CTP_ID,CBRT.COMPLE_DATE,CBRT.ORIGINAL_ACCT FROM CTP_BATCH_HOST_TR CBRT WHERE CBRT.MID_FEE_TYPE = '1' AND CBRT.COMPLE_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND CBRT.STAT = '0' AND CBRT.TRANS_FLAG = '0' GROUP BY CBRT.CTP_ID,CBRT.COMPLE_DATE,CBRT.ORIGINAL_ACCT ORDER BY CBRT.CTP_ID, CBRT.COMPLE_DATE ;
SELECT SUM(CORPUS) OLD_CORPUS FROM CTP_BATCH_REPAY_TR WHERE PRO_ID = '1' AND ACCT_NO = '1' AND BID_SEQ_NO = '1' AND STAT ='0' ;
SELECT SUM(CTR.TRAN_AMT)*100 TOT_FEE,CTR.CTP_ID, CTR.TRAN_DATE,CTR.ORIGINAL_ACCT FROM CTP_TRANS_TR CTR WHERE CTR.TRAN_STAT = '2' AND CTR.MID_FEE_TYPE = '1' AND CTR.TRAN_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') AND CTR.FEE_TYPE = '1' AND CTR.TRANS_FLAG = '0' AND CTR.HOST_CHECK = '1' GROUP BY CTR.CTP_ID,CTR.TRAN_DATE ,CTR.ORIGINAL_ACCT ;
SELECT SUM(NVL(DB_AMT,PRO_AMT)) DB_AMT,COUNT(1) JK_NUMBER,COUNT(TOT_NUM) CJ_NUMBER FROM CTP_PP_INFO WHERE STAT IN ('6','9','10','11') AND CTP_ID = '1' ;
SELECT SUM(OPER_AMT) TOTAL_AMT FROM DTB_ROLL_TR WHERE CARD_NO='1' AND TRAN_DATE=to_char(sysdate,'yyyy-mm-dd') and TRANS_CHAN_TYPE='1' AND OPER_TYPE='0' and TRAN_STATE in('2','3','5','6') ;
SELECT SUM(REAL_AMT) FROM CTP_BATCH_REPAY_TR WHERE CTP_ID = '1' AND CTP_SEQ = '1' AND STAT = '0' AND DC_FLAG = '1' ;
SELECT SUM(REAL_AMT) REPAY_AMT FROM CTP_BATCH_REPAY_TR WHERE FEE_FLAG !='3' AND STAT='0' AND JD_FLAG='4' AND CTP_ID = '1' ;
SELECT SUM(T.PRO_AMT * 100) PRO_AMT,SUM(T.DB_AMT * 100) DB_AMT,SUM(HK_CORPUS * 100) HK_CORPUS FROM (SELECT SUM(A.PRO_AMT) PRO_AMT, 0 DB_AMT, 0 HK_CORPUS FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' AND A.MJ_NO = '1' AND (A.STAT IN ('4','5','31') OR (TO_DATE(A.END_BUY_TIME,'YYYY-MM-DD HH24:MI:SS') > SYSDATE AND A.STAT='3') OR (TO_DATE(END_BUY_TIME,'YYYY-MM-DD HH24:MI:SS') < SYSDATE AND A.STAT='3' AND NVL(DB_FLAG,'1')= '1' AND TOT_NUM > 0)) UNION ALL SELECT 0 PRO_AMT, SUM(NVL(A.DB_AMT,A.PRO_AMT)) DB_AMT, SUM(NVL(A.HK_CORPUS,0)) HK_CORPUS FROM CTP_PP_INFO A WHERE A.CTP_ID = '1' AND A.MJ_NO = '1' AND A.STAT IN ('6','7','9','10')) T ;
SELECT T.CTP_ID,T.PRO_ID,T.PRO_NAME FROM CTP_PP_INFO T WHERE T.CTP_ID = '1' AND T.PRO_ID = '1' ;
SELECT T.PASS_TYPE,S.IS_BATCH,T.PASS_LEVEL,S.SUPPORT_DAY,S.DAY_AMT,S.END_AMT,S.MONTH_AMT FROM PASS_CTP_CONFIG T INNER JOIN PASS_DETAIL_CONF S ON T.PASS_TYPE=S.PASS_TYPE AND T.EBUSER_TYP=S.EBUSER_TYP WHERE T.BUSI_TYPE='1' AND T.CTP_ID='1' AND T.EBUSER_TYP = '1' AND S.BANK_CODE='1' AND S.BUSI_TYPE='1' AND to_char(sysdate,'HH24mi')>S.BEGIN_TIME AND to_char(sysdate,'HH24mi')<S.END_TIME ORDER BY T.PASS_LEVEL ;
SELECT T.PASS_TYPE,S.IS_BATCH,T.PASS_LEVEL,S.SUPPORT_DAY,S.DAY_AMT,TOTAL_ERR_NUM,S.MONTH_AMT FROM PASS_CTP_CONFIG T INNER JOIN PASS_DETAIL_CONF S ON T.PASS_TYPE=S.PASS_TYPE AND T.EBUSER_TYP=S.EBUSER_TYP WHERE T.BUSI_TYPE='1' AND T.CTP_ID='1' AND T.EBUSER_TYP = '1' AND S.BANK_CODE='1' AND S.BUSI_TYPE='1' AND to_char(sysdate,'HH24mi')>S.BEGIN_TIME AND to_char(sysdate,'HH24mi')<S.END_TIME AND '1'>=S.START_AMT AND '1'<=S.END_AMT ORDER BY T.PASS_LEVEL ;
SELECT TRACK_SEQ_NO.NEXTVAL FROM DUAL ;
SELECT TRADE_CODE,CTP_ID,REV_MER_ID FROM CTP_MER_AUTH_DATA WHERE TRAN_SEQ='1' ;
SELECT TRADE_CON FROM CTP_MER_AUTH_DATA WHERE TRAN_SEQ='1' ;
SELECT TRADE_NAME,TRADE_AMT,TRADE_CON,SUM_MER_ID,TRADE_NO FROM CTP_MER_AUTH_DATA WHERE TRAN_SEQ='1' ;
SELECT TRAN_SEQ, CTP_ID, CTP_SEQ, PRO_ID, PRO_NAME, PRO_TYP, PRO_AMT, RISK_LEV, PRO_DESC, CRE_DATE, CRE_TIME, STAR_BUY_TIME, END_BUY_TIME, STAR_DATE, PRO_TERM, EXPINC_RATE, END_DATE, MJ_NAME, MJ_ID_TYP, MJ_ID_NO, MJ_NO, ZR_FLAG, DC_FLAG, BACK_URL, SYNZ_URL, FEE_PER_TOP, CTP_SEND_FEE, REPLACE(CRE_DATE,'-','')||REPLACE(CRE_TIME,':','') ORDER_CRE_TIME, PRO_MIN_AMT, IS_AUTO_BID, TOT_FEE, AUTO_REPAY_COUNT, AUTO_REPAY_QUOTA, AUTO_REPAY_END_DATE FROM CTP_PP_ADD_TR WHERE CTP_SEQ = '1' AND CTP_ID = '1' AND STAT = '1' ;
SELECT TRAN_SEQ, TRADE_CODE, TRADE_NAME,  OPER_NAME, TRADE_AMT, TRADE_NO, TRADE_CON, REVIEW_NO, ROW_NUMBER() OVER(ORDER BY TRADE_DATE DESC,TRADE_TIME DESC) AS RN FROM CTP_MER_AUTH_DATA WHERE TRAN_SEQ = '1' ;
SELECT TRAN_SEQ,TRAN_DATE FROM CTP_COMMON_TR WHERE CTP_ID in ('1','1','1') AND CTP_SEQ = '1' AND TRANS_CODE = '1' ;
SELECT TRANS_SEQ,CTP_ID,PRO_ID FROM CTP_PP_CONFIRM_TR WHERE CTP_ID = '1' AND PRO_ID = '1' AND BID_STAT = '0' ;
SELECT TRAN_STAT BATCH_STAT,TOT_NUM,TO_CHAR(TOT_AMT*100) TOT_AMT FROM CTP_COMPENT_TR WHERE CTP_ID='1' AND CTP_SEQ = '1' ;
SELECT TRAN_STAT, REF_REASON, NEW_MOBILE, REG_AMT, NEW_BIND_CARD ACCT_NO, OLD_BANK_CODE, OLD_BANK_NAME, NEW_BANK_CODE, NEW_BANK_NAME FROM CTP_BIND_CARD_EXCHANG_TR WHERE CTP_SEQ = '1' ;
SELECT TRANS_URL, URL_PARM FROM P2P_TRANS_URL_CONF WHERE TRAN_TYPE = '1' ;
SELECT TRAN_TYP FROM CTP_SERVICE_TYPE_CONF WHERE BUSI_TYP='1' AND SERVICE_TYPE='1' ;
SELECT T.TRANS_CODE, T.CHECK_TYPE, T.CHECK_CHAN, T.CHECK_COLUMN, T.IS_NULL_FLAG FROM CHAN_TRANS_AUTH_CHECK_CONF T WHERE T.CONF_STATUS = '0' ;
SELECT UNI_NO FROM CTP_COMP_QUAIL_INFO WHERE COMP_NAME='1' AND ID_NO='1' AND ID_TYP='1' AND (UNI_STAT in('1','0') OR UNI_STAT='4' AND EACCT_NO IS NOT NULL) AND CTP_ID='1' AND CUST_ROLE='1' AND IS_CANCEL='0' ;
SELECT UNI_NO,UNI_STAT,AUDIT_OPINION,IS_EACCT_SIGN,EACCT_NO,COMP_NAME,ID_TYP,ID_NO,THREE_IN_ONE,COMP_PHONE,INDU_CATE,REG_AMT, LEGAL_NAME,LEGAL_ID_TYP,LEGAL_ID_NO,LEGAL_PHONE,COMP_LICEN,IRS_REGIST,LAND_TAX_REGIST,APP_NO,COMP_ORG, CASE WHEN LEGAL_PATH is null THEN 'N' ELSE 'Y' END LEGAL_ID_NO_PIC, CASE WHEN COMP_LICEN_PATH is null THEN 'N' ELSE 'Y' END COMP_LICEN_PIC, CASE WHEN IRS_PATH is null THEN 'N' ELSE 'Y' END IRS_REGIST_PIC, CASE WHEN LAND_TAX_PATH is null THEN 'N' ELSE 'Y' END LAND_TAX_REGIST_PIC, CASE WHEN APP_PATH is null THEN 'N' ELSE 'Y' END APP_NO_PIC, CASE WHEN INST_CREDIT_PATH is null THEN 'N' ELSE 'Y' END INST_CREDIT_PIC, INST_CREDIT,INST_CREDIT_DATE,INST_CREDIT_END_DATE,TRANS_URL,IS_PAR_COMP,PAR_THREE_IN_ONE,PAR_COMP_ORG,CUST_ROLE FROM CTP_COMP_QUAIL_INFO WHERE CTP_TRAN_SEQ='1' ;
SELECT UNIQUE(CTP_TYP) FROM CTP_PRO_TYP_CONF WHERE CTP_ID='1' ;
SELECT UNI_STAT FROM CTP_COMP_QUAIL_INFO WHERE CTP_TRAN_SEQ='1' ;
SELECT USED_LMT FROM CTP_ACCT_LMT_USED WHERE CTP_ID = '1' AND ACCT_NO = '1' AND USED_DATE = TO_CHAR(SYSDATE, 'YYYY-MM-DD') ;
SELECT VALID_TIME,ZR_VALID FROM CTP_P2P_TYP_CONF WHERE CTP_ID='1' AND PRO_TYP='1' ;
SELECT XABANK_PAY_ACCT,XABANK_REC_ACCT, XABANK_FEE_REC, DF_SETM_PAY_ACCT,DF_SETM_REC_ACCT, TRANS_CHAN_TYPE, XABANK_FEE_PAY_DK XABANK_FEE_PAY, XABANK_PAY_NAME, XABANK_REC_NAME FROM XABANK_INNER_ACCT WHERE TRANS_CHAN_TYPE = '1' ;
SELECT XABANK_PAY_ACCT,XABANK_REC_ACCT, XABANK_FEE_REC, DF_SETM_PAY_ACCT,DF_SETM_REC_ACCT, TRANS_CHAN_TYPE, XABANK_FEE_PAY, XABANK_PAY_NAME, XABANK_REC_NAME FROM XABANK_INNER_ACCT WHERE TRANS_CHAN_TYPE = '1' ;
SELECT XIA.XABANK_FEE_PAY,XIA.XABANK_FEE_PAY_DK, XIA.XABANK_FEE_REC,XIA.DF_SETM_PAY_ACCT, XIA.XABANK_FEE_REC_NAME,XIA.DF_SETM_PAY_ACCT_NAME, XIA.DF_SETM_REC_ACCT,XIA.DF_SETM_REC_ACCT_NAME, XIA.XABANK_FEE_REC_DF,XIA.XABANK_FEE_REC_DF_NAME FROM XABANK_INNER_ACCT XIA WHERE XIA.TRANS_CHAN_TYPE = '1' ;
SELECT ZR_FLAG,END_DATE,STAT,PRO_NAME,ZR_FEE_ACCT,NVL(HK_AMT,0) HK_AMT FROM CTP_PP_INFO WHERE CTP_ID = '1' AND PRO_TYP = '1' AND PRO_ID = '1' ;
DELETE FROM CTP_ACCT_LMT_USED WHERE CTP_ID = '1' AND ACCT_NO = '1' ;
